"use strict";(self.webpackChunkshareme=self.webpackChunkshareme||[]).push([["3782"],{14317(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"kien-truc-dieu-khien-tap-trung-plc-vs-phan-tan-dcs","metadata":{"permalink":"/shareme/blog/kien-truc-dieu-khien-tap-trung-plc-vs-phan-tan-dcs","source":"@site/blog/2026/2026-07-26-kien-truc-dieu-khien-tap-trung-va-dcs.mdx","title":"So s\xe1nh ki\u1EBFn tr\xfac \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung (Centralized PLC) v\xe0 ph\xe2n t\xe1n (DCS)","description":"Khi t\xecm hi\u1EC3u v\u1EC1 c\xe1c gi\u1EA3i ph\xe1p t\u1EF1 \u0111\u1ED9ng h\xf3a cho nh\xe0 m\xe1y quy m\xf4 c\xf4ng nghi\u1EC7p l\u1EDBn (nh\u01B0 l\u1ECDc h\xf3a d\u1EA7u, xi m\u0103ng, nhi\u1EC7t \u0111i\u1EC7n hay x\u1EED l\xfd n\u01B0\u1EDBc th\u1EA3i), c\xe1c n\xed s\u1EBD th\u01B0\u1EDDng xuy\xean nghe nh\u1EAFc \u0111\u1EBFn hai kh\xe1i ni\u1EC7m: H\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n gi\xe1m s\xe1t SCADA k\u1EBFt h\u1EE3p PLC t\u1EADp trung (Centralized PLC & SCADA) v\xe0 H\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n ph\xe2n t\xe1n DCS (Distributed Control System).","date":"2026-07-26T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"PLC","permalink":"/shareme/blog/tags/plc"},{"inline":false,"label":"SCADA","permalink":"/shareme/blog/tags/scada"}],"readingTime":5.46,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"kien-truc-dieu-khien-tap-trung-plc-vs-phan-tan-dcs","title":"So s\xe1nh ki\u1EBFn tr\xfac \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung (Centralized PLC) v\xe0 ph\xe2n t\xe1n (DCS)","authors":["gemini"],"tags":["tu-dong-hoa","plc","scada"],"image":"https://images.unsplash.com/photo-1581092160607-ee22621dd758?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"nextItem":{"title":"\u0110\u1ECDc b\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n chu\u1EA9n IEC cho ng\u01B0\u1EDDi m\u1EDBi","permalink":"/shareme/blog/huong-dan-doc-ban-ve-dien-cong-nghiep-chuan-iec"}},"content":"Khi t\xecm hi\u1EC3u v\u1EC1 c\xe1c gi\u1EA3i ph\xe1p t\u1EF1 \u0111\u1ED9ng h\xf3a cho nh\xe0 m\xe1y quy m\xf4 c\xf4ng nghi\u1EC7p l\u1EDBn (nh\u01B0 l\u1ECDc h\xf3a d\u1EA7u, xi m\u0103ng, nhi\u1EC7t \u0111i\u1EC7n hay x\u1EED l\xfd n\u01B0\u1EDBc th\u1EA3i), c\xe1c n\xed s\u1EBD th\u01B0\u1EDDng xuy\xean nghe nh\u1EAFc \u0111\u1EBFn hai kh\xe1i ni\u1EC7m: **H\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n gi\xe1m s\xe1t SCADA k\u1EBFt h\u1EE3p PLC t\u1EADp trung (Centralized PLC & SCADA)** v\xe0 **H\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n ph\xe2n t\xe1n DCS (Distributed Control System)**.\\n\\nNhi\u1EC1u k\u1EF9 s\u01B0 tr\u1EBB th\u01B0\u1EDDng ngh\u0129 \u0111\u01A1n gi\u1EA3n r\u1EB1ng \\"DCS ch\u1EC9 l\xe0 s\u1EF1 k\u1EBFt h\u1EE3p c\u1EE7a nhi\u1EC1u b\u1ED9 PLC gh\xe9p l\u1EA1i v\u1EDBi nhau\\". Th\u1EF1c ch\u1EA5t, \u0111\xe2y l\xe0 hai tri\u1EBFt l\xfd thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng ho\xe0n to\xe0n kh\xe1c bi\u1EC7t t\u1EEB g\u1ED1c r\u1EC5 c\u1EA5u tr\xfac ph\u1EA7n c\u1EE9ng, ph\u1EA7n m\u1EC1m \u0111\u1EBFn ph\u01B0\u01A1ng th\u1EE9c v\u1EADn h\xe0nh. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD ph\xe2n t\xedch s\xe2u, so s\xe1nh chi ti\u1EBFt v\xe0 \u0111\u01B0a ra l\u1EDDi khuy\xean l\u1EF1a ch\u1ECDn ki\u1EBFn tr\xfac ph\xf9 h\u1EE3p cho c\xe1c n\xed.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Ki\u1EBFn tr\xfac \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung (Centralized PLC & SCADA)\\n\\nTrong h\u1EC7 th\u1ED1ng n\xe0y, c\xe1c b\u1ED9 l\u1EADp tr\xecnh \u0111\u1ED9c l\u1EADp **PLC (Programmable Logic Controller)** ch\u1ECBu tr\xe1ch nhi\u1EC7m x\u1EED l\xfd logic \u0111i\u1EC1u khi\u1EC3n t\u1EA1i c\xe1c m\xe1y ho\u1EB7c c\xf4ng \u0111o\u1EA1n ri\xeang l\u1EBB. M\u1ED9t ho\u1EB7c nhi\u1EC1u m\xe1y t\xednh c\xe0i ph\u1EA7n m\u1EC1m **SCADA (Supervisory Control and Data Acquisition)** \u0111\u01B0\u1EE3c n\u1ED1i m\u1EA1ng Ethernet \u0111\u1EC3 thu th\u1EADp d\u1EEF li\u1EC7u v\xe0 gi\xe1m s\xe1t t\u1EADp trung.\\n\\n### \u0110\u1EB7c \u0111i\u1EC3m ki\u1EBFn tr\xfac\\n*   **X\u1EED l\xfd c\u1EE5c b\u1ED9:** PLC ch\u1EA1y ch\u01B0\u01A1ng tr\xecnh \u0111i\u1EC1u khi\u1EC3n c\u1EE5c b\u1ED9 r\u1EA5t nhanh (chu k\u1EF3 v\xf2ng qu\xe9t ch\u1EC9 v\xe0i mili-gi\xe2y).\\n*   **Thi\u1EBFt k\u1EBF Bottom-up (T\u1EEB d\u01B0\u1EDBi l\xean):** K\u1EF9 s\u01B0 vi\u1EBFt code \u0111i\u1EC1u khi\u1EC3n cho t\u1EEBng b\u1ED9 PLC \u0111\u1ED9c l\u1EADp tr\u01B0\u1EDBc, sau \u0111\xf3 m\u1EDBi ti\u1EBFn h\xe0nh thi\u1EBFt k\u1EBF giao di\u1EC7n SCADA, t\u1EA1o c\u01A1 s\u1EDF d\u1EEF li\u1EC7u tag (Tag Database) tr\xean ph\u1EA7n m\u1EC1m SCADA v\xe0 li\xean k\u1EBFt (map) c\xe1c \u0111\u1ECBa ch\u1EC9 tag t\u1EEB SCADA xu\u1ED1ng PLC b\u1EB1ng c\xe1c driver truy\u1EC1n th\xf4ng (nh\u01B0 OPC UA, Modbus...).\\n*   **T\xednh \u0111\u1ED9c l\u1EADp:** N\u1EBFu m\xe1y t\xednh SCADA b\u1ECB treo hay t\u1EAFt ngu\u1ED3n, c\xe1c b\u1ED9 PLC \u1EDF d\u01B0\u1EDBi v\u1EABn t\u1EF1 \u0111\u1ED9ng ch\u1EA1y b\xecnh th\u01B0\u1EDDng theo ch\u01B0\u01A1ng tr\xecnh \u0111\xe3 l\u1EADp tr\xecnh s\u1EB5n \u0111\u1EC3 gi\u1EEF an to\xe0n cho m\xe1y m\xf3c.\\n\\n---\\n\\n## 2. Ki\u1EBFn tr\xfac \u0111i\u1EC1u khi\u1EC3n ph\xe2n t\xe1n (DCS - Distributed Control System)\\n\\nDCS l\xe0 m\u1ED9t h\u1EC7 th\u1ED1ng t\u1EF1 \u0111\u1ED9ng h\xf3a t\xedch h\u1EE3p to\xe0n di\u1EC7n quy m\xf4 l\u1EDBn. \u1EDE \u0111\xe2y, quy\u1EC1n \u0111i\u1EC1u khi\u1EC3n kh\xf4ng t\u1EADp trung v\xe0o m\u1ED9t b\u1ED9 x\u1EED l\xfd m\xe0 \u0111\u01B0\u1EE3c ph\xe2n chia r\u1EA3i r\xe1c cho nhi\u1EC1u b\u1ED9 \u0111i\u1EC1u khi\u1EC3n ch\u1EE9c n\u0103ng **DPU (Distributed Processing Unit)** ho\u1EB7c b\u1ED9 \u0111i\u1EC1u khi\u1EC3n c\u1EE5c b\u1ED9 \u0111\u1EB7t \u1EDF c\xe1c khu v\u1EF1c kh\xe1c nhau trong nh\xe0 m\xe1y.\\n\\n### \u0110\u1EB7c \u0111i\u1EC3m ki\u1EBFn tr\xfac\\n*   **T\xednh t\xedch h\u1EE3p h\u1EC7 th\u1ED1ng c\u1EF1c cao:** DCS k\u1EBFt n\u1ED1i t\u1EA5t c\u1EA3 c\xe1c b\u1ED9 \u0111i\u1EC1u khi\u1EC3n, tr\u1EA1m v\u1EADn h\xe0nh (Operator Station), tr\u1EA1m k\u1EF9 s\u01B0 (Engineering Station) v\xe0 c\u01A1 s\u1EDF d\u1EEF li\u1EC7u th\xf4ng qua m\u1ED9t m\u1EA1ng x\u01B0\u01A1ng s\u1ED1ng t\u1ED1c \u0111\u1ED9 cao, d\u1EF1 ph\xf2ng k\xe9p (Redundant) \u0111\u01B0\u1EE3c thi\u1EBFt k\u1EBF ri\xeang g\u1ECDi l\xe0 **Control Bus** (v\xed d\u1EE5 m\u1EA1ng Ethernet c\xf4ng nghi\u1EC7p th\u1EDDi gian th\u1EF1c).\\n*   **C\u01A1 s\u1EDF d\u1EEF li\u1EC7u tag t\u1EADp trung duy nh\u1EA5t (Single Global Database):** \u0110\xe2y l\xe0 \u0111i\u1EC3m kh\xe1c bi\u1EC7t l\u1EDBn nh\u1EA5t c\u1EE7a DCS. \\n    *   *Trong h\u1EC7 th\u1ED1ng PLC/SCADA:* n\xed t\u1EA1o tag \u1EDF PLC v\xe0 t\u1EA1o tag \u1EDF SCADA ri\xeang, r\u1ED3i li\xean k\u1EBFt ch\xfang l\u1EA1i. \\n    *   *Trong h\u1EC7 th\u1ED1ng DCS:* n\xed ch\u1EC9 c\u1EA7n t\u1EA1o tag **m\u1ED9t l\u1EA7n duy nh\u1EA5t** t\u1EA1i tr\u1EA1m k\u1EF9 s\u01B0. Tag \u0111\xf3 t\u1EF1 \u0111\u1ED9ng \u0111\u01B0\u1EE3c hi\u1EC3u \u1EDF c\u1EA3 c\u1EA5p \u0111i\u1EC1u khi\u1EC3n ph\u1EA7n c\u1EE9ng l\u1EABn giao di\u1EC7n v\u1EADn h\xe0nh tr\xean m\xe0n h\xecnh gi\xe1m s\xe1t. Kh\xf4ng c\u1EA7n th\u1EF1c hi\u1EC7n map tag ph\u1EE9c t\u1EA1p.\\n*   **D\u1EF1 ph\xf2ng n\xf3ng ho\xe0n to\xe0n (Full Redundant):** DCS lu\xf4n thi\u1EBFt k\u1EBF d\u1EF1 ph\xf2ng k\xe9p cho t\u1EA5t c\u1EA3 c\xe1c th\xe0nh ph\u1EA7n c\u1ED1t l\xf5i: CPU \u0111i\u1EC1u khi\u1EC3n (ch\u1EA1y ch\u1EBF \u0111\u1ED9 Hot-Standby song song), card I/O ngu\u1ED3n, m\u1EA1ng truy\u1EC1n th\xf4ng v\xe0 m\xe1y ch\u1EE7 d\u1EEF li\u1EC7u. N\u1EBFu m\u1ED9t CPU b\u1ECB l\u1ED7i \u0111\u1ED9t ng\u1ED9t, CPU d\u1EF1 ph\xf2ng s\u1EBD ti\u1EBFp qu\u1EA3n \u0111i\u1EC1u khi\u1EC3n ngay l\u1EADp t\u1EE9c trong v\xf2ng d\u01B0\u1EDBi 10ms m\xe0 kh\xf4ng g\xe2y gi\xe1n \u0111o\u1EA1n d\xe2y chuy\u1EC1n.\\n\\n---\\n\\n## 3. So s\xe1nh chi ti\u1EBFt Centralized PLC + SCADA vs. DCS\\n\\n\u0110\u1EC3 c\xe1c n\xed d\u1EC5 \u0111\u1ED1i chi\u1EBFu \u0111\u01B0a ra quy\u1EBFt \u0111\u1ECBnh thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng, m\xecnh \u0111\xe3 t\xf3m t\u1EAFt c\xe1c ti\xeau ch\xed c\u1ED1t l\xf5i nh\u1EA5t d\u01B0\u1EDBi \u0111\xe2y:\\n\\n| Ti\xeau ch\xed | H\u1EC7 PLC + SCADA | H\u1EC7 th\u1ED1ng ph\xe2n t\xe1n DCS |\\n| :--- | :--- | :--- |\\n| **Quy m\xf4 h\u1EC7 th\u1ED1ng** | Nh\u1ECF \u0111\u1EBFn trung b\xecnh (d\u01B0\u1EDBi 5000 I/O) | R\u1EA5t l\u1EDBn (l\xean \u0111\u1EBFn h\xe0ng ch\u1EE5c ngh\xecn I/O) |\\n| **Lo\u1EA1i h\xecnh s\u1EA3n xu\u1EA5t** | \u0110i\u1EC1u khi\u1EC3n r\u1EDDi r\u1EA1c (Discrete Control) nh\u01B0 l\u1EAFp r\xe1p, \u0111\xf3ng g\xf3i, b\u0103ng t\u1EA3i. | \u0110i\u1EC1u khi\u1EC3n qu\xe1 tr\xecnh li\xean t\u1EE5c (Process Control) nh\u01B0 h\xf3a ch\u1EA5t, d\u1EA7u kh\xed, gi\u1EA5y, \u0111i\u1EC7n. |\\n| **C\u01A1 s\u1EDF d\u1EEF li\u1EC7u (Database)** | T\xe1ch bi\u1EC7t gi\u1EEFa PLC v\xe0 SCADA | C\u01A1 s\u1EDF d\u1EEF li\u1EC7u to\xe0n c\u1EE5c t\u1EADp trung duy nh\u1EA5t |\\n| **Kh\u1EA3 n\u0103ng d\u1EF1 ph\xf2ng** | C\xf3 th\u1EC3 c\u1EA5u h\xecnh d\u1EF1 ph\xf2ng nh\u01B0ng ph\u1EE9c t\u1EA1p v\xe0 gi\xe1 th\xe0nh cao. | D\u1EF1 ph\xf2ng n\xf3ng m\u1EB7c \u0111\u1ECBnh t\u1EEB ph\u1EA7n c\u1EE9ng \u0111\u1EBFn ph\u1EA7n m\u1EC1m. |\\n| **T\u1ED1c \u0111\u1ED9 \u0111\xe1p \u1EE9ng (Scan time)** | C\u1EF1c k\u1EF3 nhanh (1 ~ 10ms), th\xedch h\u1EE3p b\u1EA3o v\u1EC7 kh\u1EA9n c\u1EA5p, m\xe1y ch\u1EA1y t\u1ED1c \u0111\u1ED9 cao. | Ch\u1EADm h\u01A1n (100 ~ 500ms), do t\u1EADp trung x\u1EED l\xfd thu\u1EADt to\xe1n ph\u1EE9c t\u1EA1p (PID, Cascade). |\\n| **M\u1EE9c \u0111\u1ED9 m\u1EDF r\u1ED9ng v\xe0 s\u1EEDa \u0111\u1ED5i** | D\u1EC5 d\xe0ng n\xe2ng c\u1EA5p nh\u1ECF l\u1EBB, chi ph\xed r\u1EBB. | Y\xeau c\u1EA7u nghi\xeam ng\u1EB7t, chi ph\xed b\u1EA3n quy\u1EC1n n\xe2ng c\u1EA5p tag r\u1EA5t l\u1EDBn. |\\n| **Chi ph\xed \u0111\u1EA7u t\u01B0** | Th\u1EA5p \u0111\u1EBFn trung b\xecnh | R\u1EA5t cao |\\n\\n---\\n\\n## 4. L\u1EDDi khuy\xean l\u1EF1a ch\u1ECDn th\u1EF1c t\u1EBF cho k\u1EF9 s\u01B0 t\u1EF1 \u0111\u1ED9ng h\xf3a\\n\\n*   **Ch\u1ECDn PLC + SCADA khi:** n\xed thi\u1EBFt k\u1EBF c\xe1c m\xe1y m\xf3c ch\u1EA1y \u0111\u1ED9c l\u1EADp, tr\u1EA1m b\u01A1m n\u01B0\u1EDBc, x\u1EED l\xfd n\u01B0\u1EDBc th\u1EA3i quy m\xf4 v\u1EEBa, d\xe2y chuy\u1EC1n s\u1EA3n xu\u1EA5t th\u1EF1c ph\u1EA9m \u0111\xf3ng chai d\u1EA1ng r\u1EDDi r\u1EA1c. T\u1ED1c \u0111\u1ED9 \u0111\xe1p \u1EE9ng c\u1EE7a logic c\u1EA7n r\u1EA5t nhanh v\xe0 chi ph\xed \u0111\u1EA7u t\u01B0 d\u1EF1 \xe1n \u1EDF m\u1EE9c v\u1EEBa ph\u1EA3i.\\n*   **Ch\u1ECDn DCS khi:** n\xed l\xe0m vi\u1EC7c trong c\xe1c nh\xe0 m\xe1y c\xf3 quy tr\xecnh c\xf4ng ngh\u1EC7 li\xean t\u1EE5c si\xeau ph\u1EE9c t\u1EA1p. N\u01A1i m\xe0 m\u1ED9t gi\xe2y gi\xe1n \u0111o\u1EA1n s\u1EA3n xu\u1EA5t c\xf3 th\u1EC3 g\xe2y thi\u1EC7t h\u1EA1i h\xe0ng t\u1EF7 \u0111\u1ED3ng ho\u1EB7c g\xe2y tai n\u1EA1n th\u1EA3m h\u1ECDa (nh\u01B0 nh\xe0 m\xe1y h\xf3a ch\u1EA5t, l\u1ECDc d\u1EA7u). L\xfac n\xe0y, t\xednh n\u0103ng **d\u1EF1 ph\xf2ng n\xf3ng**, **c\u01A1 s\u1EDF d\u1EEF li\u1EC7u th\u1ED1ng nh\u1EA5t** v\xe0 thu\u1EADt to\xe1n ki\u1EC3m so\xe1t qu\xe1 tr\xecnh ti\xean ti\u1EBFn c\u1EE7a DCS l\xe0 s\u1EF1 l\u1EF1a ch\u1ECDn duy nh\u1EA5t \u0111\xe1ng tin c\u1EADy.\\n*   **Xu h\u01B0\u1EDBng t\xedch h\u1EE3p:** Ng\xe0y nay ranh gi\u1EDBi gi\u1EEFa PLC v\xe0 DCS \u0111ang d\u1EA7n thu h\u1EB9p. Nhi\u1EC1u h\xe3ng t\u1EF1 \u0111\u1ED9ng h\xf3a \u0111\xe3 ph\xe1t tri\u1EC3n c\xe1c h\u1EC7 th\u1ED1ng lai (Hybrid DCS) c\xf3 gi\xe1 th\xe0nh t\u1ED1t c\u1EE7a PLC nh\u01B0ng c\u1EA5u tr\xfac c\u01A1 s\u1EDF d\u1EEF li\u1EC7u t\u1EADp trung g\u1EA7n t\u01B0\u01A1ng \u0111\u01B0\u01A1ng DCS (v\xed d\u1EE5 h\u1EC7 th\u1ED1ng PlantPAx c\u1EE7a Rockwell Automation hay PCS7 c\u1EE7a Siemens). \u0110\xe2y l\xe0 h\u01B0\u1EDBng \u0111i m\u1EDBi m\xe0 c\xe1c n\xed n\xean t\xecm hi\u1EC3u s\xe2u \u0111\u1EC3 \u0111\xf3n \u0111\u1EA7u c\xf4ng ngh\u1EC7."},{"id":"huong-dan-doc-ban-ve-dien-cong-nghiep-chuan-iec","metadata":{"permalink":"/shareme/blog/huong-dan-doc-ban-ve-dien-cong-nghiep-chuan-iec","source":"@site/blog/2026/2026-07-25-huong-dan-doc-ban-ve-dien-chuan-iec.mdx","title":"\u0110\u1ECDc b\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n chu\u1EA9n IEC cho ng\u01B0\u1EDDi m\u1EDBi","description":"Khi n\xed b\u01B0\u1EDBc ch\xe2n v\xe0o m\u1ED9t c\xf4ng tr\xecnh \u0111i\u1EC7n, nh\u1EADn b\xe0n giao m\u1ED9t t\u1EE7 \u0111i\u1EC7n \u0111i\u1EC1u khi\u1EC3n PLC t\u1EEB nh\xe0 th\u1EA7u, th\u1EE9 \u0111\u1EA7u ti\xean n\xed c\u1EA7n c\u1EA7m tr\xean tay l\xe0 b\u1ED9 B\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n. B\u1EA3n v\u1EBD \u0111i\u1EC7n gi\u1ED1ng nh\u01B0 b\u1EA3n \u0111\u1ED3 kho b\xe1u, n\u1EBFu kh\xf4ng \u0111\u1ECDc hi\u1EC3u \u0111\u01B0\u1EE3c k\xfd hi\u1EC7u v\xe0 nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng, n\xed s\u1EBD kh\xf4ng th\u1EC3 \u0111\u1EA5u n\u1ED1i d\xe2y, kh\xf4ng bi\u1EBFt c\xe1ch vi\u1EBFt code PLC cho \u0111\xfang d\u1EA3i I/O v\xe0 ho\xe0n to\xe0n b\u1EA5t l\u1EF1c khi t\u1EE7 \u0111i\u1EC7n x\u1EA3y ra s\u1EF1 c\u1ED1 c\u1EA7n s\u1EEDa ch\u1EEFa.","date":"2026-07-25T00:00:00.000Z","tags":[{"inline":false,"label":"\u0110i\u1EC7n C\xf4ng Nghi\u1EC7p","permalink":"/shareme/blog/tags/dien-cong-nghiep"},{"inline":false,"label":"B\u1EA3n V\u1EBD \u0110i\u1EC7n","permalink":"/shareme/blog/tags/schematics"}],"readingTime":5.56,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"huong-dan-doc-ban-ve-dien-cong-nghiep-chuan-iec","title":"\u0110\u1ECDc b\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n chu\u1EA9n IEC cho ng\u01B0\u1EDDi m\u1EDBi","authors":["gemini"],"tags":["dien-cong-nghiep","schematics"],"image":"https://images.unsplash.com/photo-1652715564391-38cc4475b7f5?q=80&w=765&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D"},"unlisted":false,"prevItem":{"title":"So s\xe1nh ki\u1EBFn tr\xfac \u0111i\u1EC1u khi\u1EC3n t\u1EADp trung (Centralized PLC) v\xe0 ph\xe2n t\xe1n (DCS)","permalink":"/shareme/blog/kien-truc-dieu-khien-tap-trung-plc-vs-phan-tan-dcs"},"nextItem":{"title":"T\xecm hi\u1EC3u ti\xeau chu\u1EA9n m\xe3 b\u1EA3o v\u1EC7 IP c\u1EE7a thi\u1EBFt b\u1ECB v\xe0 v\u1ECF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p","permalink":"/shareme/blog/tieu-chuan-ma-bao-ve-ip-thiet-bi-tu-dien"}},"content":"Khi n\xed b\u01B0\u1EDBc ch\xe2n v\xe0o m\u1ED9t c\xf4ng tr\xecnh \u0111i\u1EC7n, nh\u1EADn b\xe0n giao m\u1ED9t t\u1EE7 \u0111i\u1EC7n \u0111i\u1EC1u khi\u1EC3n PLC t\u1EEB nh\xe0 th\u1EA7u, th\u1EE9 \u0111\u1EA7u ti\xean n\xed c\u1EA7n c\u1EA7m tr\xean tay l\xe0 b\u1ED9 **B\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n**. B\u1EA3n v\u1EBD \u0111i\u1EC7n gi\u1ED1ng nh\u01B0 b\u1EA3n \u0111\u1ED3 kho b\xe1u, n\u1EBFu kh\xf4ng \u0111\u1ECDc hi\u1EC3u \u0111\u01B0\u1EE3c k\xfd hi\u1EC7u v\xe0 nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng, n\xed s\u1EBD kh\xf4ng th\u1EC3 \u0111\u1EA5u n\u1ED1i d\xe2y, kh\xf4ng bi\u1EBFt c\xe1ch vi\u1EBFt code PLC cho \u0111\xfang d\u1EA3i I/O v\xe0 ho\xe0n to\xe0n b\u1EA5t l\u1EF1c khi t\u1EE7 \u0111i\u1EC7n x\u1EA3y ra s\u1EF1 c\u1ED1 c\u1EA7n s\u1EEDa ch\u1EEFa.\\n\\nH\u1EA7u h\u1EBFt c\xe1c b\u1EA3n v\u1EBD thi\u1EBFt k\u1EBF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p hi\u1EC7n nay \u0111\u1EC1u tu\xe2n theo ti\xeau chu\u1EA9n qu\u1ED1c t\u1EBF **IEC (International Electrotechnical Commission)**. Trong b\xe0i vi\u1EBFt n\xe0y, m\xecnh s\u1EBD chia s\u1EBB nh\u1EEFng kinh nghi\u1EC7m th\u1EF1c chi\u1EBFn gi\xfap c\xe1c n\xed nhanh ch\xf3ng l\xe0m ch\u1EE7 k\u1EF9 n\u0103ng \u0111\u1ECDc b\u1EA3n v\u1EBD \u0111i\u1EC7n chu\u1EA9n IEC t\u1EEB nh\u1EEFng chi ti\u1EBFt nh\u1ECF nh\u1EA5t.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. C\xe1ch \u0111\u1ECDc khung t\xean v\xe0 t\u1ECDa \u0111\u1ED9 trang b\u1EA3n v\u1EBD \u0111i\u1EC7n\\n\\nM\u1ED9t t\u1EADp b\u1EA3n v\u1EBD \u0111i\u1EC7n c\xf4ng nghi\u1EC7p th\u01B0\u1EDDng r\u1EA5t d\xe0y (t\u1EEB v\xe0i ch\u1EE5c \u0111\u1EBFn h\xe0ng tr\u0103m trang). \u0110\u1EC3 ng\u01B0\u1EDDi \u0111\u1ECDc d\u1EC5 d\xe0ng \u0111\u1ECBnh v\u1ECB c\xe1c thi\u1EBFt b\u1ECB v\xe0 \u0111i\u1EC3m \u0111\u1EA5u n\u1ED1i, c\xe1c trang b\u1EA3n v\u1EBD lu\xf4n \u0111\u01B0\u1EE3c thi\u1EBFt k\u1EBF theo h\u1EC7 t\u1ECDa \u0111\u1ED9 l\u01B0\u1EDBi.\\n\\n### H\u1EC7 t\u1ECDa \u0111\u1ED9 l\u01B0\u1EDBi (Grid Coordinates)\\n*   **Tr\u1EE5c ngang (X-axis):** Th\u01B0\u1EDDng \u0111\u01B0\u1EE3c chia th\xe0nh c\xe1c v\xf9ng t\u1EEB **1 \u0111\u1EBFn 8** ho\u1EB7c **1 \u0111\u1EBFn 10** \u1EDF vi\u1EC1n tr\xean v\xe0 vi\u1EC1n d\u01B0\u1EDBi trang gi\u1EA5y.\\n*   **Tr\u1EE5c d\u1ECDc (Y-axis):** Th\u01B0\u1EDDng \u0111\u01B0\u1EE3c chia th\xe0nh c\xe1c v\xf9ng ch\u1EEF c\xe1i t\u1EEB **A \u0111\u1EBFn F** \u1EDF vi\u1EC1n tr\xe1i v\xe0 vi\u1EC1n ph\u1EA3i trang gi\u1EA5y.\\n*   **C\xe1ch g\u1ECDi t\xean t\u1ECDa \u0111\u1ED9:** M\u1ED9t \u0111i\u1EC3m giao c\u1EAFt tr\xean b\u1EA3n v\u1EBD s\u1EBD c\xf3 t\u1ECDa \u0111\u1ED9 v\xed d\u1EE5 l\xe0 `Page 12 / Column 4` (vi\u1EBFt t\u1EAFt l\xe0 `12/4` ho\u1EB7c `12.4`). \\n\\n### \xdd ngh\u0129a c\u1EE7a t\u1ECDa \u0111\u1ED9 li\xean k\u1EBFt trang (Cross-Reference)\\nKhi m\u1ED9t s\u1EE3i d\xe2y ch\u1EA1y t\u1EEB trang n\xe0y sang trang kh\xe1c (v\xed d\u1EE5 d\xe2y ngu\u1ED3n \u0111i\u1EC1u khi\u1EC3n 24VDC ch\u1EA1y xuy\xean su\u1ED1t nhi\u1EC1u trang), cu\u1ED1i \u0111\u1EA7u d\xe2y \u1EDF trang c\u0169 s\u1EBD c\xf3 k\xfd hi\u1EC7u m\u0169i t\xean k\xe8m t\u1ECDa \u0111\u1ED9 trang \u0111\xedch, v\xed d\u1EE5: **`\u2192 15.2`**. \\n\u0110i\u1EC1u n\xe0y c\xf3 ngh\u0129a l\xe0 s\u1EE3i d\xe2y n\xe0y s\u1EBD \u0111\u01B0\u1EE3c \u0111\u1EA5u n\u1ED1i ti\u1EBFp t\u1EE5c \u1EDF **Trang 15, V\xf9ng t\u1ECDa \u0111\u1ED9 c\u1ED9t s\u1ED1 2**. Khi l\u1EADt sang trang 15.2, n\xed s\u1EBD th\u1EA5y \u0111\u1EA7u d\xe2y \u0111i v\xe0o c\xf3 k\xfd hi\u1EC7u ng\u01B0\u1EE3c l\u1EA1i ch\u1EC9 v\u1EC1 trang ngu\u1ED3n: **`\u2190 12.4`**. \\n\u0110\xe2y l\xe0 k\u1EF9 n\u0103ng t\u1ED1i quan tr\u1ECDng \u0111\u1EC3 d\xf2 d\xe2y (wiring tracing) khi s\u1EEDa ch\u1EEFa t\u1EE7 \u0111i\u1EC7n.\\n\\n---\\n\\n## 2. K\xfd hi\u1EC7u ch\u1EEF c\u1EE7a c\xe1c thi\u1EBFt b\u1ECB \u0111i\u1EC7n th\u01B0\u1EDDng g\u1EB7p theo chu\u1EA9n IEC 81346\\n\\nChu\u1EA9n IEC quy \u0111\u1ECBnh c\xe1c thi\u1EBFt b\u1ECB \u0111i\u1EC7n ph\u1EA3i \u0111\u01B0\u1EE3c g\xe1n nh\xe3n b\u1EAFt \u0111\u1EA7u b\u1EB1ng c\xe1c ch\u1EEF c\xe1i \u0111\u1EA1i di\u1EC7n cho nh\xf3m ch\u1EE9c n\u0103ng c\u1EE7a ch\xfang. D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EA3ng c\xe1c ch\u1EEF c\xe1i k\xfd hi\u1EC7u ph\u1ED5 bi\u1EBFn nh\u1EA5t m\xe0 n\xed c\u1EA7n thu\u1ED9c l\xf2ng:\\n\\n| K\xfd hi\u1EC7u ch\u1EEF | Lo\u1EA1i thi\u1EBFt b\u1ECB \u0111i\u1EC7n th\u1EF1c t\u1EBF | \xdd ngh\u0129a ch\u1EE9c n\u0103ng |\\n| :--- | :--- | :--- |\\n| **Q** | Aptomat (CB, MCCB, MCB), Dao c\xe1ch ly | Thi\u1EBFt b\u1ECB \u0111\xf3ng c\u1EAFt ngu\u1ED3n \u0111\u1ED9ng l\u1EF1c |\\n| **F** | C\u1EA7u ch\xec, R\u01A1-le nhi\u1EC7t b\u1EA3o v\u1EC7 qu\xe1 t\u1EA3i, b\u1ED9 ch\u1ED1ng s\xe9t | Thi\u1EBFt b\u1ECB b\u1EA3o v\u1EC7 d\xf2ng \u0111i\u1EC7n/qu\xe1 \xe1p |\\n| **K** | Contactor (Kh\u1EDFi \u0111\u1ED9ng t\u1EEB), Relay trung gian | Thi\u1EBFt b\u1ECB \u0111\xf3ng c\u1EAFt \u0111i\u1EC1u khi\u1EC3n \u0111i\u1EC7n c\u01A1 |\\n| **T** | M\xe1y bi\u1EBFn \xe1p (Transformer), B\u1ED9 ngu\u1ED3n chuy\u1EC3n m\u1EA1ch (SPS) | Thi\u1EBFt b\u1ECB bi\u1EBFn \u0111\u1ED5i n\u0103ng l\u01B0\u1EE3ng \u0111i\u1EC7n |\\n| **S** | N\xfat nh\u1EA5n, C\xf4ng t\u1EAFc xoay, C\xf4ng t\u1EAFc h\xe0nh tr\xecnh | Thi\u1EBFt b\u1ECB ph\xe1t l\u1EC7nh \u0111\u1EA7u v\xe0o b\u1EB1ng tay |\\n| **B** | C\u1EA3m bi\u1EBFn ti\u1EC7m c\u1EADn, c\u1EA3m bi\u1EBFn \xe1p su\u1EA5t, c\u1EA3m bi\u1EBFn nhi\u1EC7t \u0111\u1ED9 | Thi\u1EBFt b\u1ECB c\u1EA3m bi\u1EBFn v\u1EADt l\xfd \u0111\u1EA7u v\xe0o |\\n| **H** | \u0110\xe8n b\xe1o pha, c\xf2i b\xe1o \u0111\u1ED9ng (Horn) | Thi\u1EBFt b\u1ECB ph\xe1t t\xedn hi\u1EC7u c\u1EA3nh b\xe1o \u0111\u1EA7u ra |\\n| **X** | C\u1EA7u \u0111\u1EA5u d\xe2y (Terminal block) | \u0110i\u1EC3m n\u1ED1i c\xe1p trung gian |\\n\\nV\xed d\u1EE5 g\xe1n nh\xe3n tr\xean b\u1EA3n v\u1EBD:\\n*   `1Q1`: Aptomat s\u1ED1 1 n\u1EB1m \u1EDF Trang 1.\\n*   `3KM2`: Contactor s\u1ED1 2 n\u1EB1m \u1EDF Trang 3.\\n*   `5KA1`: R\u01A1-le trung gian s\u1ED1 1 n\u1EB1m \u1EDF Trang 5.\\n\\n---\\n\\n## 3. C\xe1ch \u0111\u1ECDc s\u01A1 \u0111\u1ED3 m\u1EA1ch l\u1EF1c v\xe0 m\u1EA1ch \u0111i\u1EC1u khi\u1EC3n\\n\\nB\u1EA3n v\u1EBD \u0111i\u1EC7n th\u01B0\u1EDDng chia l\xe0m hai ph\u1EA7n r\xf5 r\u1EC7t: **M\u1EA1ch l\u1EF1c (Power Circuit)** v\xe0 **M\u1EA1ch \u0111i\u1EC1u khi\u1EC3n (Control Circuit)**.\\n\\n### 3.1. M\u1EA1ch l\u1EF1c (\u0110\u1ED9ng l\u1EF1c)\\n*   Th\u01B0\u1EDDng n\u1EB1m \u1EDF nh\u1EEFng trang \u0111\u1EA7u ti\xean c\u1EE7a t\u1EADp b\u1EA3n v\u1EBD.\\n*   Th\u1EC3 hi\u1EC7n \u0111\u01B0\u1EDDng \u0111i c\u1EE7a d\xf2ng \u0111i\u1EC7n ngu\u1ED3n xoay chi\u1EC1u 3 pha (L1, L2, L3, PE) t\u1EEB Aptomat t\u1ED5ng, thanh c\xe1i (busbar), qua Aptomat nh\xe1nh, Contactor \u0111\u1ED9ng l\u1EF1c, Relay nhi\u1EC7t r\u1ED3i \u0111i ra c\u1EA7u \u0111\u1EA5u d\xe2y `X` c\u1EA5p xu\u1ED1ng \u0111\u1ED9ng c\u01A1.\\n*   D\xe2y v\u1EBD \u1EDF m\u1EA1ch l\u1EF1c th\u01B0\u1EDDng l\xe0 n\xe9t \u0111\u1EADm. K\xfd hi\u1EC7u ti\u1EBFp \u0111i\u1EC3m \u0111\u1ED9ng l\u1EF1c c\u1EE7a contactor lu\xf4n c\xf3 3 c\u1EB7p ti\u1EBFp \u0111i\u1EC3m song song \u0111\u01B0\u1EE3c \u0111\xe1nh s\u1ED1 ng\xf5 v\xe0o l\xe0 `1, 3, 5` v\xe0 ng\xf5 ra l\xe0 `2, 4, 6`.\\n\\n### 3.2. M\u1EA1ch \u0111i\u1EC1u khi\u1EC3n\\n*   Th\u1EC3 hi\u1EC7n logic \u0111i\u1EC1u khi\u1EC3n c\xe1c thi\u1EBFt b\u1ECB. Ngu\u1ED3n \u0111i\u1EC7n m\u1EA1ch \u0111i\u1EC1u khi\u1EC3n th\u01B0\u1EDDng l\xe0 24VDC ho\u1EB7c 220VAC \u0111\u1EC3 \u0111\u1EA3m b\u1EA3o an to\xe0n cho ng\u01B0\u1EDDi v\u1EADn h\xe0nh.\\n*   K\xfd hi\u1EC7u cu\u1ED9n h\xfat c\u1EE7a Contactor hay Relay trung gian l\xe0 h\xecnh ch\u1EEF nh\u1EADt \u0111\u1EE9ng, c\xf3 hai \u0111\u1EA7u \u0111\u1EA5u n\u1ED1i k\xfd hi\u1EC7u l\xe0 **A1** v\xe0 **A2**.\\n*   **Ti\u1EBFp \u0111i\u1EC3m ph\u1EE5:**\\n    *   Ti\u1EBFp \u0111i\u1EC3m th\u01B0\u1EDDng m\u1EDF (**NO** - Normally Open): K\xfd hi\u1EC7u b\u1EB1ng ch\u1EEF s\u1ED1 t\u1EADn c\xf9ng l\xe0 `.3` v\xe0 `.4` (v\xed d\u1EE5 ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 c\u1EE7a contactor KM l\xe0 `13-14` ho\u1EB7c `43-44`). Ti\u1EBFp \u0111i\u1EC3m n\xe0y \u0111\xf3ng l\u1EA1i khi cu\u1ED9n h\xfat c\xf3 \u0111i\u1EC7n.\\n    *   Ti\u1EBFp \u0111i\u1EC3m th\u01B0\u1EDDng \u0111\xf3ng (**NC** - Normally Closed): K\xfd hi\u1EC7u b\u1EB1ng ch\u1EEF s\u1ED1 t\u1EADn c\xf9ng l\xe0 `.1` v\xe0 `.2` (v\xed d\u1EE5 ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 c\u1EE7a r\u01A1-le nhi\u1EC7t l\xe0 `95-96` d\xf9ng \u0111\u1EC3 ng\u1EAFt m\u1EA1ch \u0111i\u1EC1u khi\u1EC3n khi qu\xe1 t\u1EA3i). Ti\u1EBFp \u0111i\u1EC3m n\xe0y m\u1EDF ra khi cu\u1ED9n h\xfat c\xf3 \u0111i\u1EC7n/relay nhi\u1EC7t t\xe1c \u0111\u1ED9ng.\\n\\n---\\n\\n## 4. H\u01B0\u1EDBng d\u1EABn \u0111\u1ECDc b\u1EA3ng ch\u1EC9 d\u1EABn ti\u1EBFp \u0111i\u1EC3m (Contact Map)\\n\\n\u1EDE d\u01B0\u1EDBi ch\xe2n trang b\u1EA3n v\u1EBD, ngay d\u01B0\u1EDBi k\xfd hi\u1EC7u cu\u1ED9n d\xe2y c\u1EE7a Contactor `KM` ho\u1EB7c Relay trung gian `KA`, n\xed s\u1EBD th\u1EA5y m\u1ED9t b\u1EA3ng nh\u1ECF ch\u1EE9a c\xe1c con s\u1ED1. \u0110\xe2y l\xe0 **Contact Map (B\u1EA3n \u0111\u1ED3 ti\u1EBFp \u0111i\u1EC3m)**.\\n\\nB\u1EA3ng n\xe0y ch\u1EC9 ra cho n\xed bi\u1EBFt:\\n*   Cu\u1ED9n h\xfat n\xe0y c\xf3 bao nhi\xeau ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 NO v\xe0 NC.\\n*   C\xe1c ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 \u0111\xf3 \u0111ang \u0111\u01B0\u1EE3c s\u1EED d\u1EE5ng \u1EDF trang v\u1EBD n\xe0o v\xe0 v\xf9ng t\u1ECDa \u0111\u1ED9 n\xe0o.\\n\\n*V\xed d\u1EE5:* D\u01B0\u1EDBi ch\xe2n cu\u1ED9n h\xfat Contactor `2KM1` c\xf3 ghi th\xf4ng s\u1ED1:\\n*   `NO: 3.4, 5.2` (Ngh\u0129a l\xe0 contactor n\xe0y c\xf3 2 ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 th\u01B0\u1EDDng m\u1EDF \u0111ang \u0111\u01B0\u1EE3c s\u1EED d\u1EE5ng \u1EDF Trang 3 c\u1ED9t 4 v\xe0 Trang 5 c\u1ED9t 2).\\n*   `NC: 3.8` (Ngh\u0129a l\xe0 c\xf3 1 ti\u1EBFp \u0111i\u1EC3m ph\u1EE5 th\u01B0\u1EDDng \u0111\xf3ng \u0111ang \u0111\u01B0\u1EE3c s\u1EED d\u1EE5ng l\xe0m m\u1EA1ch li\xean kh\xf3a kh\xf3a ch\xe9o \u1EDF Trang 3 c\u1ED9t 8).\\n\\nK\u1EF9 n\u0103ng n\xe0y gi\xfap n\xed ki\u1EC3m so\xe1t \u0111\u01B0\u1EE3c to\xe0n b\u1ED9 li\xean \u0111\u1ED9ng c\u01A1 \u0111i\u1EC7n c\u1EE7a t\u1EE7, tr\xe1nh vi\u1EC7c \u0111\u1EA5u n\u1ED1i thi\u1EBFu ho\u1EB7c \u0111\u1EA5u tr\xf9ng l\u1EB7p ti\u1EBFp \u0111i\u1EC3m ph\u1EE5."},{"id":"tieu-chuan-ma-bao-ve-ip-thiet-bi-tu-dien","metadata":{"permalink":"/shareme/blog/tieu-chuan-ma-bao-ve-ip-thiet-bi-tu-dien","source":"@site/blog/2026/2026-07-24-tieu-chuan-ma-bao-ve-ip-thiet-bi.mdx","title":"T\xecm hi\u1EC3u ti\xeau chu\u1EA9n m\xe3 b\u1EA3o v\u1EC7 IP c\u1EE7a thi\u1EBFt b\u1ECB v\xe0 v\u1ECF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p","description":"Trong qu\xe1 tr\xecnh thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng c\u01A1 \u0111i\u1EC7n, vi\u1EC7c l\u1EF1a ch\u1ECDn v\u1ECF t\u1EE7 \u0111i\u1EC7n v\xe0 c\xe1c thi\u1EBFt b\u1ECB t\u1EF1 \u0111\u1ED9ng h\xf3a (c\u1EA3m bi\u1EBFn, \u0111\u1ED9ng c\u01A1, PLC, HMI) kh\xf4ng ch\u1EC9 d\u1EEBng l\u1EA1i \u1EDF t\xednh n\u0103ng v\xe0 c\xf4ng su\u1EA5t \u0111i\u1EC7n. M\u1ED9t th\xf4ng s\u1ED1 c\u1EF1c k\u1EF3 quan tr\u1ECDng \u1EA3nh h\u01B0\u1EDFng tr\u1EF1c ti\u1EBFp \u0111\u1EBFn tu\u1ED5i th\u1ECD v\xe0 s\u1EF1 an to\xe0n c\u1EE7a to\xe0n b\u1ED9 h\u1EC7 th\u1ED1ng l\xe0 ti\xeau chu\u1EA9n IP (Ingress Protection).","date":"2026-07-24T00:00:00.000Z","tags":[{"inline":false,"label":"\u0110i\u1EC7n C\xf4ng Nghi\u1EC7p","permalink":"/shareme/blog/tags/dien-cong-nghiep"},{"inline":false,"label":"Ti\xeau Chu\u1EA9n IP","permalink":"/shareme/blog/tags/standards"}],"readingTime":5.07,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"tieu-chuan-ma-bao-ve-ip-thiet-bi-tu-dien","title":"T\xecm hi\u1EC3u ti\xeau chu\u1EA9n m\xe3 b\u1EA3o v\u1EC7 IP c\u1EE7a thi\u1EBFt b\u1ECB v\xe0 v\u1ECF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p","authors":["gemini"],"tags":["dien-cong-nghiep","standards"],"image":"https://images.unsplash.com/photo-1563456019560-2b37aa7ad890?q=80&w=688&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D"},"unlisted":false,"prevItem":{"title":"\u0110\u1ECDc b\u1EA3n v\u1EBD s\u01A1 \u0111\u1ED3 m\u1EA1ch \u0111i\u1EC7n chu\u1EA9n IEC cho ng\u01B0\u1EDDi m\u1EDBi","permalink":"/shareme/blog/huong-dan-doc-ban-ve-dien-cong-nghiep-chuan-iec"},"nextItem":{"title":"Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng v\xe0 h\u01B0\u1EDBng d\u1EABn c\xe1c b\u01B0\u1EDBc tuning b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID th\u1EF1c t\u1EBF","permalink":"/shareme/blog/nguyen-ly-va-tuning-bo-dieu-khien-pid"}},"content":"Trong qu\xe1 tr\xecnh thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng c\u01A1 \u0111i\u1EC7n, vi\u1EC7c l\u1EF1a ch\u1ECDn v\u1ECF t\u1EE7 \u0111i\u1EC7n v\xe0 c\xe1c thi\u1EBFt b\u1ECB t\u1EF1 \u0111\u1ED9ng h\xf3a (c\u1EA3m bi\u1EBFn, \u0111\u1ED9ng c\u01A1, PLC, HMI) kh\xf4ng ch\u1EC9 d\u1EEBng l\u1EA1i \u1EDF t\xednh n\u0103ng v\xe0 c\xf4ng su\u1EA5t \u0111i\u1EC7n. M\u1ED9t th\xf4ng s\u1ED1 c\u1EF1c k\u1EF3 quan tr\u1ECDng \u1EA3nh h\u01B0\u1EDFng tr\u1EF1c ti\u1EBFp \u0111\u1EBFn tu\u1ED5i th\u1ECD v\xe0 s\u1EF1 an to\xe0n c\u1EE7a to\xe0n b\u1ED9 h\u1EC7 th\u1ED1ng l\xe0 **ti\xeau chu\u1EA9n IP (Ingress Protection)**.\\n\\nR\u1EA5t nhi\u1EC1u s\u1EF1 c\u1ED1 \u0111\xe1ng ti\u1EBFc \u0111\xe3 x\u1EA3y ra khi k\u1EF9 s\u01B0 l\u1EAFp \u0111\u1EB7t m\xe0n h\xecnh HMI ngo\xe0i tr\u1EDDi nh\u01B0ng ch\u1ECDn m\xe3 IP qu\xe1 th\u1EA5p d\u1EABn \u0111\u1EBFn n\u01B0\u1EDBc m\u01B0a th\u1EA5m v\xe0o l\xe0m ch\u1EADp ch\xe1y m\xe0n h\xecnh, ho\u1EB7c l\u1EAFp \u0111\u1ED9ng c\u01A1 b\u1EA3o v\u1EC7 th\u1EA5p v\xe0o m\xf4i tr\u01B0\u1EDDng nhi\u1EC1u b\u1EE5i m\u1ECBn c\u1EE7a nh\xe0 m\xe1y xi m\u0103ng khi\u1EBFn motor b\u1ECB k\u1EB9t b\u1EA1c \u0111\u1EA1n ch\u1EC9 sau v\xe0i tu\u1EA7n ch\u1EA1y. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD h\u01B0\u1EDBng d\u1EABn c\xe1c n\xed c\xe1ch \u0111\u1ECDc hi\u1EC3u chu\u1EA9n IP v\xe0 c\xe1ch ch\u1ECDn l\u1EF1a v\u1ECF t\u1EE7, thi\u1EBFt b\u1ECB ph\xf9 h\u1EE3p cho t\u1EEBng m\xf4i tr\u01B0\u1EDDng th\u1EF1c t\u1EBF.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. C\u1EA5u tr\xfac c\u1EE7a m\xe3 b\u1EA3o v\u1EC7 IP (Ingress Protection)\\n\\nTi\xeau chu\u1EA9n b\u1EA3o v\u1EC7 IP do \u1EE6y ban K\u1EF9 thu\u1EADt \u0110i\u1EC7n Qu\u1ED1c t\u1EBF (IEC) thi\u1EBFt l\u1EADp, quy \u0111\u1ECBnh m\u1EE9c \u0111\u1ED9 b\u1EA3o v\u1EC7 c\u1EE7a thi\u1EBFt b\u1ECB \u0111i\u1EC7n \u0111\u1ED1i v\u1EDBi s\u1EF1 x\xe2m nh\u1EADp c\u1EE7a v\u1EADt th\u1EC3 r\u1EAFn (b\u1EE5i, tay ng\u01B0\u1EDDi...) v\xe0 ch\u1EA5t l\u1ECFng (n\u01B0\u1EDBc).\\n\\nM\xe3 ti\xeau chu\u1EA9n th\u01B0\u1EDDng \u0111\u01B0\u1EE3c c\u1EA5u tr\xfac g\u1ED3m ch\u1EEF c\xe1i **IP** \u0111i k\xe8m v\u1EDBi **hai ch\u1EEF s\u1ED1**:\\n\\n\\n\\n```math\\n\\\\text{M\xe3 IP} = \\\\text{IP} + X_1 + X_2\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c ch\u1EEF s\u1ED1:\\n*   **Ch\u1EEF s\u1ED1 th\u1EE9 nh\u1EA5t ($X_1$):** Bi\u1EC3u th\u1ECB m\u1EE9c \u0111\u1ED9 b\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i s\u1EF1 x\xe2m nh\u1EADp c\u1EE7a **v\u1EADt th\u1EC3 r\u1EAFn v\xe0 b\u1EE5i** (d\u1EA3i gi\xe1 tr\u1ECB t\u1EEB **0 \u0111\u1EBFn 6**).\\n*   **Ch\u1EEF s\u1ED1 th\u1EE9 hai ($X_2$):** Bi\u1EC3u th\u1ECB m\u1EE9c \u0111\u1ED9 b\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i s\u1EF1 x\xe2m nh\u1EADp c\u1EE7a **ch\u1EA5t l\u1ECFng v\xe0 n\u01B0\u1EDBc** (d\u1EA3i gi\xe1 tr\u1ECB t\u1EEB **0 \u0111\u1EBFn 9K**).\\n\\n---\\n\\n## 2. B\u1EA3ng tra c\u1EE9u \xfd ngh\u0129a chi ti\u1EBFt c\xe1c ch\u1EEF s\u1ED1 b\u1EA3o v\u1EC7\\n\\n### 2.1. Ch\u1EEF s\u1ED1 th\u1EE9 nh\u1EA5t: B\u1EA3o v\u1EC7 ch\u1ED1ng v\u1EADt th\u1EC3 r\u1EAFn (B\u1EE5i)\\n*   **0:** Kh\xf4ng b\u1EA3o v\u1EC7.\\n*   **1:** B\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i v\u1EADt r\u1EAFn \u0111\u01B0\u1EDDng k\xednh $> 50text{ mm}$ (v\xed d\u1EE5: v\xf4 t\xecnh ch\u1EA1m c\u1EA3 b\xe0n tay).\\n*   **2:** B\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i v\u1EADt r\u1EAFn \u0111\u01B0\u1EDDng k\xednh $> 12.5text{ mm}$ (v\xed d\u1EE5: ng\xf3n tay ng\u01B0\u1EDDi).\\n*   **3:** B\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i v\u1EADt r\u1EAFn \u0111\u01B0\u1EDDng k\xednh $> 2.5text{ mm}$ (v\xed d\u1EE5: tua-v\xedt, d\xe2y \u0111i\u1EC7n l\u1EDBn).\\n*   **4:** B\u1EA3o v\u1EC7 ch\u1ED1ng l\u1EA1i v\u1EADt r\u1EAFn \u0111\u01B0\u1EDDng k\xednh $> 1.0text{ mm}$ (v\xed d\u1EE5: s\u1EE3i d\xe2y k\u1EBDm nh\u1ECF, c\xf4n tr\xf9ng).\\n*   **5:** **B\u1EA3o v\u1EC7 ch\u1ED1ng b\u1EE5i (Dust-protected):** B\u1EE5i v\u1EABn c\xf3 th\u1EC3 l\u1ECDt v\xe0o trong nh\u01B0ng kh\xf4ng \u0111\u1EE7 l\u01B0\u1EE3ng g\xe2y \u1EA3nh h\u01B0\u1EDFng \u0111\u1EBFn ho\u1EA1t \u0111\u1ED9ng b\xecnh th\u01B0\u1EDDng c\u1EE7a thi\u1EBFt b\u1ECB.\\n*   **6:** **Ch\u1ED1ng b\u1EE5i ho\xe0n to\xe0n (Dust-tight):** Ng\u0103n ng\u1EEBa ho\xe0n to\xe0n s\u1EF1 x\xe2m nh\u1EADp c\u1EE7a c\xe1t b\u1EE5i (m\u1EE9c cao nh\u1EA5t).\\n\\n### 2.2. Ch\u1EEF s\u1ED1 th\u1EE9 hai: B\u1EA3o v\u1EC7 ch\u1ED1ng ch\u1EA5t l\u1ECFng (N\u01B0\u1EDBc)\\n*   **0:** Kh\xf4ng b\u1EA3o v\u1EC7.\\n*   **1:** B\u1EA3o v\u1EC7 ch\u1ED1ng gi\u1ECDt n\u01B0\u1EDBc r\u01A1i th\u1EB3ng \u0111\u1EE9ng.\\n*   **2:** B\u1EA3o v\u1EC7 ch\u1ED1ng gi\u1ECDt n\u01B0\u1EDBc r\u01A1i xi\xean g\xf3c t\u1ED1i \u0111a 15 \u0111\u1ED9.\\n*   **3:** B\u1EA3o v\u1EC7 ch\u1ED1ng n\u01B0\u1EDBc phun m\u01B0a (g\xf3c nghi\xeang t\u1ED1i \u0111a 60 \u0111\u1ED9).\\n*   **4:** **B\u1EA3o v\u1EC7 ch\u1ED1ng n\u01B0\u1EDBc phun tia t\u1EEB m\u1ECDi h\u01B0\u1EDBng (Splash-proof):** N\u01B0\u1EDBc b\u1EAFn t\u1EEB m\u1ECDi h\u01B0\u1EDBng kh\xf4ng g\xe2y h\u1EA1i.\\n*   **5:** B\u1EA3o v\u1EC7 ch\u1ED1ng v\xf2i phun n\u01B0\u1EDBc \xe1p l\u1EF1c th\u1EA5p t\u1EEB m\u1ECDi h\u01B0\u1EDBng.\\n*   **6:** B\u1EA3o v\u1EC7 ch\u1ED1ng v\xf2i phun n\u01B0\u1EDBc \xe1p l\u1EF1c m\u1EA1nh t\u1EEB m\u1ECDi h\u01B0\u1EDBng (s\xf3ng bi\u1EC3n).\\n*   **7:** **B\u1EA3o v\u1EC7 ng\xe2m n\u01B0\u1EDBc t\u1EA1m th\u1EDDi:** Ng\xe2m n\u01B0\u1EDBc s\xe2u t\u1ED1i \u0111a 1 m\xe9t trong th\u1EDDi gian t\u1ED1i \u0111a 30 ph\xfat.\\n*   **8:** **B\u1EA3o v\u1EC7 ng\xe2m n\u01B0\u1EDBc l\xe2u d\xe0i:** Ng\xe2m n\u01B0\u1EDBc li\xean t\u1EE5c d\u01B0\u1EDBi \u0111\u1ED9 s\xe2u v\xe0 \u0111i\u1EC1u ki\u1EC7n th\u1ECFa thu\u1EADn c\u1EE7a nh\xe0 s\u1EA3n xu\u1EA5t (v\xed d\u1EE5 b\u01A1m ch\xecm).\\n*   **9K:** B\u1EA3o v\u1EC7 ch\u1ED1ng tia n\u01B0\u1EDBc \xe1p l\u1EF1c c\u1EF1c cao v\xe0 nhi\u1EC7t \u0111\u1ED9 cao (v\u1EC7 sinh b\u1EB1ng v\xf2i \xe1p l\u1EF1c nhi\u1EC7t \u0111\u1ED9 cao).\\n\\n---\\n\\n## 3. H\u01B0\u1EDBng d\u1EABn ch\u1ECDn l\u1EF1a IP cho v\u1ECF t\u1EE7 \u0111i\u1EC7n theo m\xf4i tr\u01B0\u1EDDng th\u1EF1c t\u1EBF\\n\\nT\u1EEB kinh nghi\u1EC7m th\u1EF1c chi\u1EBFn c\u1EE7a m\xecnh, d\u01B0\u1EDBi \u0111\xe2y l\xe0 c\u1EA9m nang ch\u1ECDn c\u1EA5p b\u1EA3o v\u1EC7 IP cho v\u1ECF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p:\\n\\n### 3.1. T\u1EE7 \u0111i\u1EC7n \u0111\u1EB7t trong ph\xf2ng \u0111i\u1EC7n \u0111i\u1EC1u khi\u1EC3n s\u1EA1ch (Ph\xf2ng bi\u1EBFn t\u1EA7n, ph\xf2ng SCADA)\\n*   M\xf4i tr\u01B0\u1EDDng n\xe0y c\xf3 m\xe1y l\u1EA1nh \u0111i\u1EC1u h\xf2a, s\u1EA1ch s\u1EBD, kh\xf4ng c\xf3 b\u1EE5i b\u1EA9n hay n\u01B0\u1EDBc b\u1EAFn.\\n*   **Khuy\u1EBFn ngh\u1ECB:** Ch\u1ECDn v\u1ECF t\u1EE7 \u0111i\u1EC7n \u0111\u1EA1t chu\u1EA9n **IP31** ho\u1EB7c **IP41**. V\u1ECF t\u1EE7 lo\u1EA1i n\xe0y th\u01B0\u1EDDng c\xf3 khe ch\u1EDBp t\u1EA3n nhi\u1EC7t t\u1EF1 nhi\xean ho\u1EB7c t\xedch h\u1EE3p qu\u1EA1t h\xfat c\xf3 m\xe0ng l\u1ECDc b\u1EE5i m\u1ECFng \u1EDF c\xe1nh c\u1EEDa \u0111\u1EC3 t\u1ED1i \u01B0u nhi\u1EC7t \u0111\u1ED9 b\xean trong t\u1EE7.\\n\\n### 3.2. T\u1EE7 \u0111i\u1EC7n \u0111\u1EB7t trong ph\xe2n x\u01B0\u1EDFng s\u1EA3n xu\u1EA5t th\xf4ng th\u01B0\u1EDDng\\n*   M\xf4i tr\u01B0\u1EDDng c\xf3 nhi\u1EC1u c\xe1t b\u1EE5i bay l\u01A1 l\u1EEDng, th\u1EC9nh tho\u1EA3ng c\xf3 c\xf4ng nh\xe2n v\u1EC7 sinh lau ch\xf9i b\u1EB1ng gi\u1EBB \u1EA9m.\\n*   **Khuy\u1EBFn ngh\u1ECB:** Ch\u1ECDn v\u1ECF t\u1EE7 \u0111i\u1EC7n \u0111\u1EA1t t\u1ED1i thi\u1EC3u **IP54**. C\xe1nh t\u1EE7 ph\u1EA3i c\xf3 gio\u0103ng cao su b\u1ECDc k\xedn xung quanh r\xe3nh tho\xe1t n\u01B0\u1EDBc. N\u1EBFu l\u1EAFp qu\u1EA1t th\xf4ng gi\xf3, b\u1EAFt bu\u1ED9c ph\u1EA3i d\xf9ng lo\u1EA1i qu\u1EA1t k\xe8m t\u1EA5m l\u1ECDc b\u1EE5i chuy\xean d\u1EE5ng (Filter) v\xe0 c\xf3 m\u0169 che m\u01B0a (Rain hood).\\n\\n### 3.3. T\u1EE7 \u0111i\u1EC7n \u0111\u1EB7t ngo\xe0i tr\u1EDDi (Outdoor Cabinets)\\n*   Ch\u1ECBu m\u01B0a b\xe3o t\u1EA1t tr\u1EF1c ti\u1EBFp t\u1EEB m\u1ECDi h\u01B0\u1EDBng v\xe0 \xe1nh n\u1EAFng m\u1EB7t tr\u1EDDi tr\u1EF1c x\u1EA1.\\n*   **Khuy\u1EBFn ngh\u1ECB:** Ch\u1ECDn v\u1ECF t\u1EE7 \u0111i\u1EC7n \u0111\u1EA1t t\u1ED1i thi\u1EC3u **IP65** (ch\u1ED1ng b\u1EE5i ho\xe0n to\xe0n v\xe0 ch\u1ED1ng n\u01B0\u1EDBc phun). \\n*   **L\u01B0u \xfd thi\u1EBFt k\u1EBF:** V\u1ECF t\u1EE7 ngo\xe0i tr\u1EDDi ph\u1EA3i thi\u1EBFt k\u1EBF **hai l\u1EDBp c\u1EEDa** (l\u1EDBp c\u1EEDa ngo\xe0i k\xedn ho\xe0n to\xe0n che m\u01B0a n\u1EAFng, l\u1EDBp c\u1EEDa trong l\u1EAFp c\xe1c n\xfat nh\u1EA5n, m\xe0n h\xecnh HMI \u0111i\u1EC1u khi\u1EC3n). T\u1EE7 ph\u1EA3i c\xf3 m\xe1i che d\u1ED1c ch\u1EA3y n\u01B0\u1EDBc m\u01B0a ra ph\xeda sau, ch\u1EA5t li\u1EC7u v\u1ECF n\xean l\xe0m b\u1EB1ng inox 304 ho\u1EB7c t\xf4n s\u01A1n t\u0129nh \u0111i\u1EC7n d\xe0y tr\xean 2.0mm \u0111\u1EC3 ch\u1ED1ng r\u1EC9 s\xe9t.\\n\\n### 3.4. Thi\u1EBFt b\u1ECB t\u1EF1 \u0111\u1ED9ng l\u1EAFp tr\u1EF1c ti\u1EBFp t\u1EA1i c\xf4ng \u0111o\u1EA1n r\u1EEDa tr\xf4i (Nh\xe0 m\xe1y F&B, bia r\u01B0\u1EE3u)\\n*   Khu v\u1EF1c ch\u1EBF bi\u1EBFn th\u1EF1c ph\u1EA9m y\xeau c\u1EA7u phun r\u1EEDa v\u1EC7 sinh s\xe1t tr\xf9ng b\u1EB1ng n\u01B0\u1EDBc n\xf3ng \xe1p l\u1EF1c cao m\u1ED7i ng\xe0y.\\n*   **Khuy\u1EBFn ngh\u1ECB:** C\xe1c n\xfat nh\u1EA5n \u0111i\u1EC1u khi\u1EC3n t\u1EA1i ch\u1ED7 v\xe0 c\u1EA3m bi\u1EBFn ph\u1EA3i \u0111\u1EA1t chu\u1EA9n t\u1ED1i thi\u1EC3u **IP67** ho\u1EB7c **IP69K**. V\u1ECF b\u1ECDc thi\u1EBFt b\u1ECB n\xean l\xe0m b\u1EB1ng th\xe9p kh\xf4ng g\u1EC9 \u0111\u01B0\u1EE3c bo tr\xf2n c\xe1c g\xf3c \u0111\u1EC3 kh\xf4ng \u0111\u1ECDng l\u1EA1i ch\u1EA5t b\u1EA9n v\xe0 vi khu\u1EA9n."},{"id":"nguyen-ly-va-tuning-bo-dieu-khien-pid","metadata":{"permalink":"/shareme/blog/nguyen-ly-va-tuning-bo-dieu-khien-pid","source":"@site/blog/2026/2026-07-23-nguyen-ly-va-tuning-bo-dieu-khien-pid.mdx","title":"Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng v\xe0 h\u01B0\u1EDBng d\u1EABn c\xe1c b\u01B0\u1EDBc tuning b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID th\u1EF1c t\u1EBF","description":"Trong \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a quy tr\xecnh (Process Control), b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID (Proportional - Integral - Derivative) l\xe0 gi\u1EA3i ph\xe1p \u0111i\u1EC1u khi\u1EC3n ph\u1EA3n h\u1ED3i v\xf2ng k\xedn (Closed-loop Control) kinh \u0111i\u1EC3n v\xe0 m\u1EA1nh m\u1EBD nh\u1EA5t. H\u01A1n 90% c\xe1c \u1EE9ng d\u1EE5ng ki\u1EC3m so\xe1t nhi\u1EC7t \u0111\u1ED9 l\xf2 nhi\u1EC7t, l\u01B0u l\u01B0\u1EE3ng d\xf2ng ch\u1EA3y, \xe1p su\u1EA5t \u0111\u01B0\u1EDDng \u1ED1ng hay m\u1EF1c ch\u1EA5t l\u1ECFng trong b\u1ED3n ch\u1EE9a hi\u1EC7n nay \u0111\u1EC1u s\u1EED d\u1EE5ng thu\u1EADt to\xe1n PID.","date":"2026-07-23T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"B\u1ED9 \u0110i\u1EC1u Khi\u1EC3n PID","permalink":"/shareme/blog/tags/pid-control"},{"inline":false,"label":"PLC","permalink":"/shareme/blog/tags/plc"}],"readingTime":6.29,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"nguyen-ly-va-tuning-bo-dieu-khien-pid","title":"Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng v\xe0 h\u01B0\u1EDBng d\u1EABn c\xe1c b\u01B0\u1EDBc tuning b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID th\u1EF1c t\u1EBF","authors":["gemini"],"tags":["tu-dong-hoa","pid-control","plc"],"image":"https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"prevItem":{"title":"T\xecm hi\u1EC3u ti\xeau chu\u1EA9n m\xe3 b\u1EA3o v\u1EC7 IP c\u1EE7a thi\u1EBFt b\u1ECB v\xe0 v\u1ECF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p","permalink":"/shareme/blog/tieu-chuan-ma-bao-ve-ip-thiet-bi-tu-dien"},"nextItem":{"title":"T\u1EA1i sao d\xf9ng t\xedn hi\u1EC7u d\xf2ng 4-20mA v\xe0 c\xf4ng th\u1EE9c scaling tuy\u1EBFn t\xednh trong PLC","permalink":"/shareme/blog/analog-4-20ma-va-cong-thuc-scaling-analog-plc"}},"content":"Trong \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a quy tr\xecnh (Process Control), b\u1ED9 \u0111i\u1EC1u khi\u1EC3n **PID (Proportional - Integral - Derivative)** l\xe0 gi\u1EA3i ph\xe1p \u0111i\u1EC1u khi\u1EC3n ph\u1EA3n h\u1ED3i v\xf2ng k\xedn (Closed-loop Control) kinh \u0111i\u1EC3n v\xe0 m\u1EA1nh m\u1EBD nh\u1EA5t. H\u01A1n 90% c\xe1c \u1EE9ng d\u1EE5ng ki\u1EC3m so\xe1t nhi\u1EC7t \u0111\u1ED9 l\xf2 nhi\u1EC7t, l\u01B0u l\u01B0\u1EE3ng d\xf2ng ch\u1EA3y, \xe1p su\u1EA5t \u0111\u01B0\u1EDDng \u1ED1ng hay m\u1EF1c ch\u1EA5t l\u1ECFng trong b\u1ED3n ch\u1EE9a hi\u1EC7n nay \u0111\u1EC1u s\u1EED d\u1EE5ng thu\u1EADt to\xe1n PID.\\n\\nM\u1EB7c d\xf9 c\xe1c ph\u1EA7n m\u1EC1m l\u1EADp tr\xecnh PLC hi\u1EC7n nay \u0111\u1EC1u t\xedch h\u1EE3p s\u1EB5n kh\u1ED1i h\xe0m PID Auto-Tuning, nh\u01B0ng tr\xean th\u1EF1c t\u1EBF c\xf4ng tr\u01B0\u1EDDng, c\xf3 r\u1EA5t nhi\u1EC1u tr\u01B0\u1EDDng h\u1EE3p thu\u1EADt to\xe1n t\u1EF1 \u0111\u1ED9ng d\xf2 tham s\u1ED1 th\u1EA5t b\u1EA1i ho\u1EB7c ch\u1EA1y kh\xf4ng \u1ED5n \u0111\u1ECBnh. L\xe0 m\u1ED9t k\u1EF9 s\u01B0 t\u1EF1 \u0111\u1ED9ng h\xf3a, n\xed c\u1EA7n l\xe0m ch\u1EE7 b\u1EA3n ch\u1EA5t to\xe1n h\u1ECDc c\u1EE7a PID v\xe0 n\u1EAFm \u0111\u01B0\u1EE3c quy tr\xecnh tuning th\u1EE7 c\xf4ng b\u1EB1ng kinh nghi\u1EC7m th\u1EF1c t\u1EBF. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD gi\u1EA3i th\xedch ng\u1EAFn g\u1ECDn nguy\xean l\xfd c\u1EE7a 3 kh\xe2u P, I, D v\xe0 c\xe1c b\u01B0\u1EDBc ch\u1EC9nh \u0111\u1ECBnh hi\u1EC7u qu\u1EA3 nh\u1EA5t.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng: Ba th\xe0nh ph\u1EA7n P, I, D l\xe0m nhi\u1EC7m v\u1EE5 g\xec?\\n\\nM\u1EE5c ti\xeau c\u1EE7a b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID l\xe0 \u0111i\u1EC1u ch\u1EC9nh gi\xe1 tr\u1ECB ng\xf5 ra \u0111i\u1EC1u khi\u1EC3n (MV - Manipulated Variable, v\xed d\u1EE5 g\xf3c m\u1EDF van, t\u1EA7n s\u1ED1 bi\u1EBFn t\u1EA7n) sao cho gi\xe1 tr\u1ECB \u0111o \u0111\u01B0\u1EE3c t\u1EEB c\u1EA3m bi\u1EBFn (PV - Process Variable) nhanh ch\xf3ng b\xe1m s\xe1t v\xe0 duy tr\xec \u1EDF gi\xe1 tr\u1ECB mong mu\u1ED1n (SP - Setpoint).\\n\\nThu\u1EADt to\xe1n ho\u1EA1t \u0111\u1ED9ng d\u1EF1a tr\xean sai l\u1EC7ch \u0111i\u1EC1u khi\u1EC3n:\\n\\n\\n\\n```math\\ne(t) = SP - PV\\n```\\n\\n\\n\\n### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc PID t\u1ED5ng qu\xe1t\\n\\nGi\xe1 tr\u1ECB \u0111\u1EA7u ra \u0111i\u1EC1u khi\u1EC3n $u(t)$ l\xe0 t\u1ED5ng c\u1EE7a 3 kh\xe2u:\\n\\n\\n\\n```math\\nu(t) = K_p \\\\cdot e(t) + K_i int_{0}^{t} e(tau) dtau + K_d \\\\frac{de(t)}{dt}\\n```\\n\\n\\n\\n### \xdd ngh\u0129a c\u1EE7a c\xe1c kh\xe2u \u0111i\u1EC1u khi\u1EC3n:\\n\\n1.  **Kh\xe2u t\u1EF7 l\u1EC7 P (Proportional):**\\n    *   T\xe1c \u0111\u1ED9ng tr\u1EF1c ti\u1EBFp t\u1EF7 l\u1EC7 thu\u1EADn v\u1EDBi sai s\u1ED1 hi\u1EC7n t\u1EA1i: $u_P(t) = K_p \\\\cdot e(t)$.\\n    *   *B\u1EA3n ch\u1EA5t:* Sai s\u1ED1 c\xe0ng l\u1EDBn th\xec l\u1EF1c \u0111i\u1EC1u ch\u1EC9nh c\xe0ng m\u1EA1nh.\\n    *   *Nh\u01B0\u1EE3c \u0111i\u1EC3m:* Kh\xe2u P \u0111\u01A1n l\u1EBB **kh\xf4ng bao gi\u1EDD lo\u1EA1i b\u1ECF \u0111\u01B0\u1EE3c sai s\u1ED1 t\u0129nh** (Offset error). N\u1EBFu t\u0103ng h\u1EC7 s\u1ED1 P qu\xe1 cao \u0111\u1EC3 c\u1ED1 x\xf3a sai s\u1ED1 t\u0129nh, h\u1EC7 th\u1ED1ng s\u1EBD b\u1ECB dao \u0111\u1ED9ng li\xean t\u1EE5c v\xe0 m\u1EA5t \u1ED5n \u0111\u1ECBnh.\\n2.  **Kh\xe2u t\xedch ph\xe2n I (Integral):**\\n    *   C\u1ED9ng d\u1ED3n t\u1EA5t c\u1EA3 c\xe1c sai s\u1ED1 t\xedch l\u0169y trong qu\xe1 kh\u1EE9 theo th\u1EDDi gian: $u_I(t) = K_i int_{0}^{t} e(tau) dtau$.\\n    *   *B\u1EA3n ch\u1EA5t:* Ch\u1EC9 c\u1EA7n c\xf2n t\u1ED3n t\u1EA1i sai s\u1ED1 t\u0129nh d\xf9 r\u1EA5t nh\u1ECF, kh\xe2u I s\u1EBD t\xedch l\u0169y d\u1EA7n theo th\u1EDDi gian \u0111\u1EC3 t\u1EA1o ra m\u1ED9t l\u1EF1c \u0111i\u1EC1u ch\u1EC9nh \u0111\u1EE7 l\u1EDBn \u0111\u1EA9y gi\xe1 tr\u1ECB PV v\u1EC1 \u0111\xfang Setpoint.\\n    *   *Nh\u01B0\u1EE3c \u0111i\u1EC3m:* Kh\xe2u I g\xe2y ra hi\u1EC7n t\u01B0\u1EE3ng t\xedch ph\xe2n b\xe3o h\xf2a (Windup) khi\u1EBFn h\u1EC7 th\u1ED1ng ph\u1EA3n \u1EE9ng ch\u1EADm h\u01A1n v\xe0 d\u1EC5 b\u1ECB v\u1ECDt l\u1ED1 (Overshoot) khi kh\u1EDFi \u0111\u1ED9ng ho\u1EB7c thay \u0111\u1ED5i Setpoint \u0111\u1ED9t ng\u1ED9t.\\n3.  **Kh\xe2u vi ph\xe2n D (Derivative):**\\n    *   D\u1EF1 b\xe1o sai s\u1ED1 trong t\u01B0\u01A1ng lai d\u1EF1a tr\xean t\u1ED1c \u0111\u1ED9 thay \u0111\u1ED5i sai s\u1ED1 hi\u1EC7n t\u1EA1i: $u_D(t) = K_d \\\\frac{de(t)}{dt}$.\\n    *   *B\u1EA3n ch\u1EA5t:* Kh\xe2u D \u0111\xf3ng vai tr\xf2 nh\u01B0 m\u1ED9t b\u1ED9 phanh gi\u1EA3m ch\u1EA5n. Khi th\u1EA5y gi\xe1 tr\u1ECB PV \u0111ang ti\u1EBFn v\u1EC1 Setpoint qu\xe1 nhanh, kh\xe2u D s\u1EBD sinh l\u1EF1c c\u1EA3n ng\u01B0\u1EE3c l\u1EA1i \u0111\u1EC3 gi\u1EA3m hi\u1EC7n t\u01B0\u1EE3ng v\u1ECDt l\u1ED1 v\xe0 d\u1EADp t\u1EAFt dao \u0111\u1ED9ng nhanh h\u01A1n.\\n    *   *Nh\u01B0\u1EE3c \u0111i\u1EC3m:* Kh\xe2u D c\u1EF1c k\u1EF3 nh\u1EA1y c\u1EA3m v\u1EDBi nhi\u1EC5u t\xedn hi\u1EC7u. N\u1EBFu t\xedn hi\u1EC7u c\u1EA3m bi\u1EBFn b\u1ECB nhi\u1EC5u r\u0103ng c\u01B0a, kh\xe2u vi ph\xe2n D s\u1EBD ph\xf3ng \u0111\u1EA1i nhi\u1EC5u l\xean khi\u1EBFn \u0111\u1EA7u ra MV dao \u0111\u1ED9ng h\u1ED7n lo\u1EA1n, nhanh ch\xf3ng ph\xe1 h\u1ECFng c\u01A1 c\u1EA5u ch\u1EA5p h\xe0nh (nh\u01B0 ch\xe1y cu\u1ED9n coil c\u1EE7a van tuy\u1EBFn t\xednh).\\n\\n---\\n\\n## 2. Quy tr\xecnh Tuning PID th\u1EE7 c\xf4ng t\u1EEBng b\u01B0\u1EDBc \u1EDF c\xf4ng tr\u01B0\u1EDDng\\n\\nKhi ch\u1EA1y th\u1EED nghi\u1EC7m (Commissioning) m\u1ED9t h\u1EC7 th\u1ED1ng th\u1EF1c t\u1EBF t\u1EA1i c\xf4ng tr\u01B0\u1EDDng, n\xed c\xf3 th\u1EC3 \xe1p d\u1EE5ng ph\u01B0\u01A1ng ph\xe1p ch\u1EC9nh \u0111\u1ECBnh th\u1EED v\xe0 sai (Trial and Error) theo quy tr\xecnh chu\u1EA9n sau:\\n\\n### B\u01B0\u1EDBc 1: V\xf4 hi\u1EC7u h\xf3a kh\xe2u I v\xe0 kh\xe2u D\\n*   C\xe0i \u0111\u1EB7t h\u1EC7 s\u1ED1 t\xedch ph\xe2n $K_i = 0$ (ho\u1EB7c th\u1EDDi gian t\xedch ph\xe2n $T_i = infty$) v\xe0 h\u1EC7 s\u1ED1 vi ph\xe2n $K_d = 0$ (ho\u1EB7c th\u1EDDi gian vi ph\xe2n $T_d = 0$).\\n*   \u0110\u1EB7t h\u1EC7 s\u1ED1 t\u1EF7 l\u1EC7 $K_p$ \u1EDF m\u1ED9t gi\xe1 tr\u1ECB nh\u1ECF ban \u0111\u1EA7u.\\n\\n### B\u01B0\u1EDBc 2: T\xecm h\u1EC7 s\u1ED1 t\u1EF7 l\u1EC7 gi\u1EDBi h\u1EA1n (D\xf2 kh\xe2u P)\\n*   T\u0103ng d\u1EA7n h\u1EC7 s\u1ED1 $K_p$ l\xean t\u1EEBng b\u01B0\u1EDBc nh\u1ECF (v\xed d\u1EE5 g\u1EA5p \u0111\xf4i sau m\u1ED7i l\u1EA7n th\u1EED) \u0111\u1ED3ng th\u1EDDi t\u1EA1o ra c\xe1c thay \u0111\u1ED5i nh\u1ECF \u1EDF Setpoint \u0111\u1EC3 quan s\xe1t ph\u1EA3n \u1EE9ng c\u1EE7a h\u1EC7 th\u1ED1ng.\\n*   Ti\u1EBFp t\u1EE5c t\u0103ng $K_p$ cho \u0111\u1EBFn khi h\u1EC7 th\u1ED1ng b\u1EAFt \u0111\u1EA7u dao \u0111\u1ED9ng li\xean t\u1EE5c v\u1EDBi bi\xean \u0111\u1ED9 kh\xf4ng \u0111\u1ED5i (tr\u1EA1ng th\xe1i dao \u0111\u1ED9ng \u0111i\u1EC1u h\xf2a t\u1EF1 duy tr\xec). Ghi l\u1EA1i gi\xe1 tr\u1ECB $K_p$ gi\u1EDBi h\u1EA1n n\xe0y (k\xfd hi\u1EC7u l\xe0 $K_u$) v\xe0 chu k\u1EF3 dao \u0111\u1ED9ng c\u1EE7a h\u1EC7 th\u1ED1ng (k\xfd hi\u1EC7u l\xe0 $T_u$).\\n*   \u0110\u1EB7t h\u1EC7 s\u1ED1 $K_p$ v\u1EADn h\xe0nh b\u1EB1ng kho\u1EA3ng **50%** gi\xe1 tr\u1ECB $K_u$ v\u1EEBa t\xecm \u0111\u01B0\u1EE3c. L\xfac n\xe0y h\u1EC7 th\u1ED1ng s\u1EBD \u1ED5n \u0111\u1ECBnh tr\u1EDF l\u1EA1i nh\u01B0ng v\u1EABn t\u1ED3n t\u1EA1i sai s\u1ED1 t\u0129nh.\\n\\n### B\u01B0\u1EDBc 3: \u0110\u01B0a kh\xe2u t\xedch ph\xe2n I v\xe0o m\u1EA1ch (X\xf3a sai s\u1ED1 t\u0129nh)\\n*   B\u1EAFt \u0111\u1EA7u gi\u1EA3m d\u1EA7n th\u1EDDi gian t\xedch ph\xe2n $T_i$ (ho\u1EB7c t\u0103ng d\u1EA7n h\u1EC7 s\u1ED1 $K_i$) t\u1EEB t\u1EEB.\\n*   Quan s\xe1t \u0111\xe1p \u1EE9ng: sai s\u1ED1 t\u0129nh s\u1EBD gi\u1EA3m d\u1EA7n v\u1EC1 0. H\xe3y \u0111i\u1EC1u ch\u1EC9nh sao cho h\u1EC7 th\u1ED1ng \u0111\u1EA1t \u0111\u01B0\u1EE3c th\u1EDDi gian \u0111\xe1p \u1EE9ng mong mu\u1ED1n m\xe0 kh\xf4ng g\xe2y ra v\u1ECDt l\u1ED1 qu\xe1 m\u1EE9c cho ph\xe9p (th\xf4ng th\u01B0\u1EDDng \u0111\u1ED9 v\u1ECDt l\u1ED1 ch\u1EA5p nh\u1EADn \u0111\u01B0\u1EE3c d\u01B0\u1EDBi 5% - 10%).\\n\\n### B\u01B0\u1EDBc 4: Th\xeam kh\xe2u vi ph\xe2n D (N\u1EBFu c\u1EA7n thi\u1EBFt)\\n*   \u0110\u1ED1i v\u1EDBi c\xe1c h\u1EC7 th\u1ED1ng c\xf3 qu\xe1n t\xednh nhi\u1EC7t c\u1EF1c l\u1EDBn (l\xf2 nung, l\xf2 s\u1EA5y) ho\u1EB7c h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n v\u1ECB tr\xed chuy\u1EC3n \u0111\u1ED9ng, h\xe3y \u0111\u01B0a th\xeam kh\xe2u vi ph\xe2n D b\u1EB1ng c\xe1ch t\u0103ng d\u1EA7n $T_d$ (ho\u1EB7c $K_d$) l\xean r\u1EA5t nh\u1ECF.\\n*   Kh\xe2u D s\u1EBD gi\xfap tri\u1EC7t ti\xeau hi\u1EC7n t\u01B0\u1EE3ng v\u1ECDt l\u1ED1 c\u1EE7a kh\xe2u I v\xe0 r\xfat ng\u1EAFn th\u1EDDi gian x\xe1c l\u1EADp c\u1EE7a h\u1EC7 th\u1ED1ng.\\n*   **L\u01B0u \xfd:** \u0110\u1ED1i v\u1EDBi c\xe1c h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n \xe1p su\u1EA5t n\u01B0\u1EDBc ho\u1EB7c l\u01B0u l\u01B0\u1EE3ng kh\xed (v\u1ED1n ph\u1EA3n \u1EE9ng r\u1EA5t nhanh v\xe0 t\xedn hi\u1EC7u c\u1EA3m bi\u1EBFn hay b\u1ECB dao \u0111\u1ED9ng nhi\u1EC5u), tuy\u1EC7t \u0111\u1ED1i **kh\xf4ng s\u1EED d\u1EE5ng kh\xe2u D** (ch\u1EC9 c\u1EA7n ch\u1EA1y PI l\xe0 \u0111\u1EE7).\\n\\n---\\n\\n## 3. V\xed d\u1EE5 th\u1EF1c t\u1EBF \u1EDF c\xf4ng tr\u01B0\u1EDDng\\n\\nM\xecnh t\u1EEBng tuning h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n nhi\u1EC7t \u0111\u1ED9 cho m\u1ED9t l\xf2 s\u1EA5y bao b\xec c\xf4ng nghi\u1EC7p s\u1EED d\u1EE5ng thanh \u0111i\u1EC7n tr\u1EDF \u0111\u1ED1t v\xe0 \u0111i\u1EC1u khi\u1EC3n g\xf3c m\u1EDF van SCR. D\u1EA3i nhi\u1EC7t \u0111\u1ED9 s\u1EA5y y\xeau c\u1EA7u duy tr\xec \u1ED5n \u0111\u1ECBnh \u1EDF **150\xb0C** v\u1EDBi sai s\u1ED1 cho ph\xe9p \xb11\xb0C.\\n\\n**Quy tr\xecnh tuning th\u1EF1c hi\u1EC7n:**\\n1.  Kh\xf3a kh\xe2u I v\xe0 D. Ban \u0111\u1EA7u ch\u1EA1y h\u1EC7 s\u1ED1 $K_p = 1.0$ th\u1EA5y nhi\u1EC7t \u0111\u1ED9 ch\u1EC9 \u0111\u1EA1t 130\xb0C (sai s\u1ED1 t\u0129nh 20\xb0C).\\n2.  T\u0103ng d\u1EA7n $K_p$ l\xean `2.5`, `5.0`, r\u1ED3i `8.0`. T\u1EA1i $K_p = 10.0$, l\xf2 b\u1EAFt \u0111\u1EA7u xu\u1EA5t hi\u1EC7n dao \u0111\u1ED9ng nhi\u1EC7t h\xecnh sin li\xean t\u1EE5c quanh m\u1EE9c 145\xb0C v\u1EDBi bi\xean \u0111\u1ED9 \xb13\xb0C, chu k\u1EF3 dao \u0111\u1ED9ng $T_u \\\\approx 120text{ gi\xe2y}$.\\n3.  \xc1p d\u1EE5ng c\xf4ng th\u1EE9c t\xednh nhanh Ziegler-Nichols cho b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PI:\\n    *   \\n\\n```math\\nK_p = 0.45 \\\\cdot K_u = 0.45 \\\\cdot 10.0 = 4.5\\n```\\n\\n\\n    *   \\n\\n```math\\nT_i = 0.83 \\\\cdot T_u = 0.83 \\\\cdot 120text{ s} \\\\approx 100text{ gi\xe2y}\\n```\\n\\n\\n4.  C\xe0i \u0111\u1EB7t c\xe1c th\xf4ng s\u1ED1 $K_p = 4.5$ v\xe0 $T_i = 100text{ s}$ v\xe0o kh\u1ED1i PID c\u1EE7a PLC. K\u1EBFt qu\u1EA3: l\xf2 nhi\u1EC7t t\u0103ng t\u1ED1c m\u01B0\u1EE3t m\xe0, \u0111\u1EA1t m\u1EE9c \u1ED5n \u0111\u1ECBnh 150\xb0C sau kho\u1EA3ng 8 ph\xfat kh\u1EDFi \u0111\u1ED9ng, sai s\u1ED1 dao \u0111\u1ED9ng th\u1EF1c t\u1EBF ch\u1EC9 c\xf2n \xb10.4\xb0C, ho\xe0n to\xe0n \u0111\xe1p \u1EE9ng y\xeau c\u1EA7u kh\u1EAFt khe c\u1EE7a quy tr\xecnh s\u1EA3n xu\u1EA5t."},{"id":"analog-4-20ma-va-cong-thuc-scaling-analog-plc","metadata":{"permalink":"/shareme/blog/analog-4-20ma-va-cong-thuc-scaling-analog-plc","source":"@site/blog/2026/2026-07-22-analog-4-20ma-va-cong-thuc-scaling.mdx","title":"T\u1EA1i sao d\xf9ng t\xedn hi\u1EC7u d\xf2ng 4-20mA v\xe0 c\xf4ng th\u1EE9c scaling tuy\u1EBFn t\xednh trong PLC","description":"Trong \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a, b\xean c\u1EA1nh c\xe1c t\xedn hi\u1EC7u s\u1ED1 ON/OFF (Digital Input/Output), ch\xfang ta th\u01B0\u1EDDng xuy\xean ph\u1EA3i l\xe0m vi\u1EC7c v\u1EDBi c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng v\u1EADt l\xfd bi\u1EBFn \u0111\u1ED5i li\xean t\u1EE5c nh\u01B0 nhi\u1EC7t \u0111\u1ED9, \xe1p su\u1EA5t, l\u01B0u l\u01B0\u1EE3ng, m\u1EF1c n\u01B0\u1EDBc... \u0110\u1EC3 PLC hi\u1EC3u \u0111\u01B0\u1EE3c c\xe1c gi\xe1 tr\u1ECB n\xe0y, ch\xfang ph\u1EA3i \u0111\u01B0\u1EE3c chuy\u1EC3n \u0111\u1ED5i th\xe0nh t\xedn hi\u1EC7u \u0111i\u1EC7n t\u01B0\u01A1ng t\u1EF1 (Analog).","date":"2026-07-22T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"C\u1EA3m Bi\u1EBFn","permalink":"/shareme/blog/tags/sensors"},{"inline":false,"label":"PLC","permalink":"/shareme/blog/tags/plc"}],"readingTime":5.19,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"analog-4-20ma-va-cong-thuc-scaling-analog-plc","title":"T\u1EA1i sao d\xf9ng t\xedn hi\u1EC7u d\xf2ng 4-20mA v\xe0 c\xf4ng th\u1EE9c scaling tuy\u1EBFn t\xednh trong PLC","authors":["gemini"],"tags":["tu-dong-hoa","sensors","plc"],"image":"https://images.unsplash.com/photo-1555664424-778a1e5e1b48?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D"},"unlisted":false,"prevItem":{"title":"Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng v\xe0 h\u01B0\u1EDBng d\u1EABn c\xe1c b\u01B0\u1EDBc tuning b\u1ED9 \u0111i\u1EC1u khi\u1EC3n PID th\u1EF1c t\u1EBF","permalink":"/shareme/blog/nguyen-ly-va-tuning-bo-dieu-khien-pid"},"nextItem":{"title":"T\xecm hi\u1EC3u giao th\u1EE9c Modbus TCP/IP v\xe0 ph\xe2n bi\u1EC7t v\u1EDBi Modbus RTU","permalink":"/shareme/blog/tim-hieu-modbus-tcp-ip-vs-modbus-rtu"}},"content":"Trong \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a, b\xean c\u1EA1nh c\xe1c t\xedn hi\u1EC7u s\u1ED1 ON/OFF (Digital Input/Output), ch\xfang ta th\u01B0\u1EDDng xuy\xean ph\u1EA3i l\xe0m vi\u1EC7c v\u1EDBi c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng v\u1EADt l\xfd bi\u1EBFn \u0111\u1ED5i li\xean t\u1EE5c nh\u01B0 nhi\u1EC7t \u0111\u1ED9, \xe1p su\u1EA5t, l\u01B0u l\u01B0\u1EE3ng, m\u1EF1c n\u01B0\u1EDBc... \u0110\u1EC3 PLC hi\u1EC3u \u0111\u01B0\u1EE3c c\xe1c gi\xe1 tr\u1ECB n\xe0y, ch\xfang ph\u1EA3i \u0111\u01B0\u1EE3c chuy\u1EC3n \u0111\u1ED5i th\xe0nh t\xedn hi\u1EC7u \u0111i\u1EC7n t\u01B0\u01A1ng t\u1EF1 (**Analog**).\\n\\nHai chu\u1EA9n t\xedn hi\u1EC7u analog ph\u1ED5 bi\u1EBFn nh\u1EA5t l\xe0 **0-10V** v\xe0 **4-20mA**. Tuy nhi\xean, t\u1EA1i c\xe1c m\xf4i tr\u01B0\u1EDDng nh\xe0 m\xe1y c\xf4ng nghi\u1EC7p l\u1EDBn, chu\u1EA9n d\xf2ng \u0111i\u1EC7n **4-20mA** g\u1EA7n nh\u01B0 chi\u1EBFm v\u1ECB th\u1EBF \u0111\u1ED9c t\xf4n. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD gi\u1EA3i th\xedch l\xfd do t\u1EA1i sao d\xf2ng 4-20mA l\u1EA1i \u01B0u vi\u1EC7t h\u01A1n, \u0111\u1ED3ng th\u1EDDi chia s\u1EBB c\xf4ng th\u1EE9c to\xe1n h\u1ECDc c\xf9ng c\xe1ch vi\u1EBFt code **scaling tuy\u1EBFn t\xednh** \u0111\u1EC3 \u0111\u1ED5i gi\xe1 tr\u1ECB raw \u0111\u1ECDc v\u1EC1 th\xe0nh s\u1ED1 \u0111o th\u1EF1c t\u1EBF trong PLC.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. T\u1EA1i sao l\u1EA1i ch\u1ECDn t\xedn hi\u1EC7u d\xf2ng 4-20mA thay v\xec \u0111i\u1EC7n \xe1p 0-10V?\\n\\nC\xf3 3 l\xfd do ch\xednh m\xe0 c\xe1c k\u1EF9 s\u01B0 thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng lu\xf4n \u01B0u ti\xean ch\u1ECDn chu\u1EA9n d\xf2ng \u0111i\u1EC7n 4-20mA:\\n\\n### 1.1. Kh\u1EA3 n\u0103ng ch\u1ED1ng nhi\u1EC5u v\u01B0\u1EE3t tr\u1ED9i v\xe0 truy\u1EC1n xa\\nT\xedn hi\u1EC7u \u0111i\u1EC7n \xe1p 0-10V r\u1EA5t d\u1EC5 b\u1ECB s\u1EE5t \xe1p tr\xean \u0111\u01B0\u1EDDng truy\u1EC1n do \u0111i\u1EC7n tr\u1EDF c\u1EE7a d\xe2y d\u1EABn (\u0111\u1EB7c bi\u1EC7t khi k\xe9o d\xe2y \u0111i xa tr\xean 50 m\xe9t). \u0110\u1ED3ng th\u1EDDi, \u0111i\u1EC7n \xe1p xoay chi\u1EC1u sinh ra t\u1EEB c\xe1c d\xe2y \u0111\u1ED9ng l\u1EF1c \u0111i c\u1EA1nh b\xean s\u1EBD d\u1EC5 d\xe0ng c\u1EA3m \u1EE9ng v\xe0o d\xe2y t\xedn hi\u1EC7u \u0111i\u1EC7n \xe1p g\xe2y sai l\u1EC7ch ch\u1EC9 s\u1ED1.\\nNg\u01B0\u1EE3c l\u1EA1i, ngu\u1ED3n d\xf2ng \u0111i\u1EC7n 4-20mA ho\u1EA1t \u0111\u1ED9ng d\u1EF1a tr\xean c\u01A1 ch\u1EBF v\xf2ng l\u1EB7p d\xf2ng \u0111i\u1EC7n (Current Loop). B\u1ED9 ph\xe1t t\xedn hi\u1EC7u (Transmitter) s\u1EBD t\u1EF1 \u0111\u1ED9ng \u0111i\u1EC1u ch\u1EC9nh \u0111i\u1EC7n \xe1p \u0111\u1EA7u ra \u0111\u1EC3 d\xf2ng \u0111i\u1EC7n trong v\xf2ng l\u1EB7p lu\xf4n gi\u1EEF \u0111\xfang m\u1EE9c t\u01B0\u01A1ng \u1EE9ng v\u1EDBi gi\xe1 tr\u1ECB \u0111o, b\u1EA5t k\u1EC3 \u0111i\u1EC7n tr\u1EDF \u0111\u01B0\u1EDDng d\xe2y thay \u0111\u1ED5i. Do \u0111\xf3, t\xedn hi\u1EC7u d\xf2ng \u0111i\u1EC7n kh\xf4ng b\u1ECB suy hao theo kho\u1EA3ng c\xe1ch v\xe0 c\u1EF1c k\u1EF3 kh\xf3 b\u1ECB nhi\u1EC5u.\\n\\n### 1.2. Ph\xe1t hi\u1EC7n l\u1ED7i \u0111\u1EE9t d\xe2y t\u1EE9c th\u1EDDi (Live Zero)\\n\u0110\xe2y l\xe0 \u01B0u \u0111i\u1EC3m c\u1EF1c k\u1EF3 \u0111\u1EAFt gi\xe1. \\n*   N\u1EBFu d\xf9ng t\xedn hi\u1EC7u **0-10V**: Khi c\u1EA3m bi\u1EBFn \u0111o \u0111\u01B0\u1EE3c gi\xe1 tr\u1ECB nh\u1ECF nh\u1EA5t (v\xed d\u1EE5 \xe1p su\u1EA5t b\u1EB1ng 0 bar) th\xec \u0111\u1EA7u ra l\xe0 `0V`. N\u1EBFu d\xe2y d\u1EABn b\u1ECB \u0111\u1EE9t, PLC nh\u1EADn v\u1EC1 \u0111i\u1EC7n \xe1p l\xe0 `0V`. PLC kh\xf4ng th\u1EC3 ph\xe2n bi\u1EC7t \u0111\u01B0\u1EE3c c\u1EA3m bi\u1EBFn \u0111ang \u0111o m\u1EE9c 0 hay d\xe2y truy\u1EC1n t\xedn hi\u1EC7u \u0111ang b\u1ECB \u0111\u1EE9t.\\n*   N\u1EBFu d\xf9ng t\xedn hi\u1EC7u **4-20mA**: Khi c\u1EA3m bi\u1EBFn \u0111o m\u1EE9c nh\u1ECF nh\u1EA5t, d\xf2ng \u0111i\u1EC7n g\u1EEDi v\u1EC1 l\xe0 `4mA`. N\u1EBFu d\xe2y t\xedn hi\u1EC7u b\u1ECB \u0111\u1EE9t, d\xf2ng \u0111i\u1EC7n l\u1EADp t\u1EE9c r\u1EDBt v\u1EC1 `0mA`. PLC ch\u1EC9 c\u1EA7n ki\u1EC3m tra n\u1EBFu d\xf2ng nh\u1EADn v\u1EC1 `< 3.6mA` th\xec l\u1EADp t\u1EE9c k\xedch ho\u1EA1t c\u1EA3nh b\xe1o \u0111\u1EE9t d\xe2y (Wire Break Fault) b\u1EA3o v\u1EC7 h\u1EC7 th\u1ED1ng an to\xe0n.\\n\\n---\\n\\n## 2. C\xf4ng th\u1EE9c to\xe1n h\u1ECDc Scaling tuy\u1EBFn t\xednh trong PLC\\n\\nKhi module Analog Input (ADC) c\u1EE7a PLC nh\u1EADn t\xedn hi\u1EC7u 4-20mA, n\xf3 s\u1EBD chuy\u1EC3n \u0111\u1ED5i d\xf2ng \u0111i\u1EC7n v\u1EADt l\xfd n\xe0y th\xe0nh m\u1ED9t s\u1ED1 nguy\xean (Raw Value) l\u01B0u trong b\u1ED9 nh\u1EDB. V\xed d\u1EE5:\\n*   PLC Siemens S7-1200 chuy\u1EC3n \u0111\u1ED5i 4-20mA th\xe0nh s\u1ED1 nguy\xean t\u1EEB **0 \u0111\u1EBFn 27648**.\\n*   PLC Mitsubishi FX5U chuy\u1EC3n \u0111\u1ED5i th\xe0nh s\u1ED1 nguy\xean t\u1EEB **0 \u0111\u1EBFn 16000** ho\u1EB7c **0 \u0111\u1EBFn 32000**.\\n\\nNhi\u1EC7m v\u1EE5 c\u1EE7a k\u1EF9 s\u01B0 l\xe0 ph\u1EA3i chuy\u1EC3n \u0111\u1ED5i s\u1ED1 nguy\xean Raw n\xe0y v\u1EC1 l\u1EA1i gi\xe1 tr\u1ECB v\u1EADt l\xfd th\u1EF1c t\u1EBF (v\xed d\u1EE5: nhi\u1EC7t \u0111\u1ED9 t\u1EEB 0 \u0111\u1EBFn 100\xb0C). Ph\xe9p bi\u1EBFn \u0111\u1ED5i n\xe0y \u0111\u01B0\u1EE3c g\u1ECDi l\xe0 **Scaling tuy\u1EBFn t\xednh (t\u1EF7 l\u1EC7 tuy\u1EBFn t\xednh)**.\\n\\n### C\xf4ng th\u1EE9c t\u1ED5ng qu\xe1t\\n\\nD\u1EF1a tr\xean ph\u01B0\u01A1ng tr\xecnh \u0111\u01B0\u1EDDng th\u1EB3ng \u0111i qua hai \u0111i\u1EC3m trong h\u1EC7 t\u1ECDa \u0111\u1ED9 Descardes, ta c\xf3 c\xf4ng th\u1EE9c t\xednh gi\xe1 tr\u1ECB th\u1EF1c t\u1EBF Scaled t\u1EEB gi\xe1 tr\u1ECB Raw \u0111\u1EA7u v\xe0o:\\n\\n\\n\\n```math\\nScaled = Out_{min} + \\\\frac{Raw - In_{min}}{In_{max} - In_{min}} \\\\cdot (Out_{max} - Out_{min})\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $Raw$: Gi\xe1 tr\u1ECB s\u1ED1 nguy\xean \u0111\u1ECDc v\u1EC1 hi\u1EC7n t\u1EA1i t\u1EEB k\xeanh Analog c\u1EE7a PLC.\\n*   $In_{min}$: Gi\xe1 tr\u1ECB s\u1ED1 nguy\xean \u1EE9ng v\u1EDBi \u0111i\u1EC3m gi\u1EDBi h\u1EA1n d\u01B0\u1EDBi (v\xed d\u1EE5 v\u1EDBi 4mA c\u1EE7a Siemens l\xe0 `0`).\\n*   $In_{max}$: Gi\xe1 tr\u1ECB s\u1ED1 nguy\xean \u1EE9ng v\u1EDBi \u0111i\u1EC3m gi\u1EDBi h\u1EA1n tr\xean (v\xed d\u1EE5 v\u1EDBi 20mA c\u1EE7a Siemens l\xe0 `27648`).\\n*   $Out_{min}$: Gi\xe1 tr\u1ECB \u0111o th\u1EF1c t\u1EBF t\u01B0\u01A1ng \u1EE9ng gi\u1EDBi h\u1EA1n d\u01B0\u1EDBi c\u1EE7a c\u1EA3m bi\u1EBFn (v\xed d\u1EE5 c\u1EA3m bi\u1EBFn \xe1p su\u1EA5t 0-10 Bar th\xec gi\u1EDBi h\u1EA1n d\u01B0\u1EDBi l\xe0 `0`).\\n*   $Out_{max}$: Gi\xe1 tr\u1ECB \u0111o th\u1EF1c t\u1EBF t\u01B0\u01A1ng \u1EE9ng gi\u1EDBi h\u1EA1n tr\xean c\u1EE7a c\u1EA3m bi\u1EBFn (v\xed d\u1EE5 c\u1EA3m bi\u1EBFn \xe1p su\u1EA5t 0-10 Bar th\xec gi\u1EDBi h\u1EA1n tr\xean l\xe0 `10`).\\n*   $Scaled$: Gi\xe1 tr\u1ECB th\u1EF1c t\u1EBF sau khi t\xednh to\xe1n (\u0111\u01A1n v\u1ECB v\u1EADt l\xfd nh\u01B0 \xb0C, Bar, m\xb3/h...).\\n\\n---\\n\\n## 3. V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\n\\nGi\u1EA3 s\u1EED n\xed c\xf3 m\u1ED9t c\u1EA3m bi\u1EBFn \xe1p su\u1EA5t n\u01B0\u1EDBc d\u1EA3i \u0111o **0 \u0111\u1EBFn 10 Bar**, xu\u1EA5t t\xedn hi\u1EC7u d\xf2ng **4-20mA** \u0111\u01B0a v\xe0o Module Analog Input c\u1EE7a PLC Siemens S7-1200. PLC \u0111ang \u0111\u1ECDc v\u1EC1 gi\xe1 tr\u1ECB nguy\xean Raw l\xe0 **13824**. H\xe3y t\xednh \xe1p su\u1EA5t n\u01B0\u1EDBc th\u1EF1c t\u1EBF trong \u0111\u01B0\u1EDDng \u1ED1ng hi\u1EC7n t\u1EA1i.\\n\\nC\xe1c th\xf4ng s\u1ED1 \u0111\xe3 bi\u1EBFt:\\n*   $Raw = 13824$\\n*   $In_{min} = 0$ (t\u01B0\u01A1ng \u1EE9ng 4mA c\u1EE7a k\xeanh Analog Input Siemens)\\n*   $In_{max} = 27648$ (t\u01B0\u01A1ng \u1EE9ng 20mA)\\n*   $Out_{min} = 0.0 \\\\text{ Bar}$\\n*   $Out_{max} = 10.0 \\\\text{ Bar}$\\n\\n\xc1p d\u1EE5ng c\xf4ng th\u1EE9c:\\n\\n\\n```math\\nScaled = 0.0 + \\\\frac{13824 - 0}{27648 - 0} \\\\cdot (10.0 - 0.0) = 0.5 \\\\cdot 10.0 = 5.0 \\\\text{ Bar}\\n```\\n\\n\\n\\nV\u1EADy \xe1p su\u1EA5t n\u01B0\u1EDBc hi\u1EC7n t\u1EA1i trong \u0111\u01B0\u1EDDng \u1ED1ng \u0111o \u0111\u01B0\u1EE3c l\xe0 **5.0 Bar**.\\n\\n### H\u01B0\u1EDBng d\u1EABn l\u1EADp tr\xecnh trong PLC\\n*   **V\u1EDBi PLC Siemens (TIA Portal):** N\xed s\u1EED d\u1EE5ng k\u1EBFt h\u1EE3p hai kh\u1ED1i l\u1EC7nh c\xf3 s\u1EB5n l\xe0 **NORM_X** (\u0111\u1EC3 chu\u1EA9n h\xf3a gi\xe1 tr\u1ECB Raw v\u1EC1 d\u1EA3i s\u1ED1 th\u1EF1c 0.0 - 1.0) v\xe0 kh\u1ED1i **SCALE_X** (\u0111\u1EC3 nh\xe2n t\u1EF7 l\u1EC7 t\u1EEB s\u1ED1 th\u1EF1c 0.0 - 1.0 sang d\u1EA3i \u0111o v\u1EADt l\xfd c\u1EE7a c\u1EA3m bi\u1EBFn).\\n*   **V\u1EDBi PLC Mitsubishi (GX Works):** N\u1EBFu kh\xf4ng c\xf3 h\xe0m Scale s\u1EB5n, n\xed t\u1EF1 vi\u1EBFt m\u1ED9t h\xe0m ch\u1EE9c n\u0103ng (Function Block) ho\u1EB7c vi\u1EBFt code tay tr\u1EF1c ti\u1EBFp theo c\xf4ng th\u1EE9c to\xe1n h\u1ECDc n\xeau tr\xean b\u1EB1ng c\xe1c l\u1EC7nh to\xe1n h\u1ECDc s\u1ED1 th\u1EF1c `SUB`, `DIV`, `MUL`, `ADD`. L\u01B0u \xfd lu\xf4n chuy\u1EC3n \u0111\u1ED5i bi\u1EBFn s\u1ED1 `Raw` sang ki\u1EC3u d\u1EEF li\u1EC7u s\u1ED1 th\u1EF1c (`REAL`) tr\u01B0\u1EDBc khi th\u1EF1c hi\u1EC7n ph\xe9p chia \u0111\u1EC3 kh\xf4ng b\u1ECB m\u1EA5t ph\u1EA7n th\u1EADp ph\xe2n."},{"id":"tim-hieu-modbus-tcp-ip-vs-modbus-rtu","metadata":{"permalink":"/shareme/blog/tim-hieu-modbus-tcp-ip-vs-modbus-rtu","source":"@site/blog/2026/2026-07-21-tim-hieu-modbus-tcp-ip.mdx","title":"T\xecm hi\u1EC3u giao th\u1EE9c Modbus TCP/IP v\xe0 ph\xe2n bi\u1EC7t v\u1EDBi Modbus RTU","description":"N\u1EBFu n\xed b\u01B0\u1EDBc ch\xe2n v\xe0o ng\xe0nh t\u1EF1 \u0111\u1ED9ng h\xf3a, ch\u1EAFc ch\u1EAFn n\xed s\u1EBD g\u1EB7p t\u1EEB kh\xf3a Modbus. \u0110\xe2y l\xe0 giao th\u1EE9c truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p ph\u1ED5 bi\u1EBFn nh\u1EA5t th\u1EBF gi\u1EDBi nh\u1EDD t\xednh m\u1EDF, mi\u1EC5n ph\xed v\xe0 c\u1EF1c k\u1EF3 \u0111\u01A1n gi\u1EA3n. Modbus c\xf3 hai bi\u1EBFn th\u1EC3 ng\u1EF1 tr\u1ECB \u1EDF hai t\u1EA7ng v\u1EADt l\xfd kh\xe1c nhau: Modbus RTU ch\u1EA1y tr\xean c\xe1p n\u1ED1i ti\u1EBFp (RS-485/RS-232) v\xe0 Modbus TCP/IP ch\u1EA1y tr\xean n\u1EC1n Ethernet ti\xeau chu\u1EA9n.","date":"2026-07-21T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"M\u1EA1ng Truy\u1EC1n Th\xf4ng","permalink":"/shareme/blog/tags/networking"},{"inline":false,"label":"Modbus","permalink":"/shareme/blog/tags/modbus"}],"readingTime":4.91,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"tim-hieu-modbus-tcp-ip-vs-modbus-rtu","title":"T\xecm hi\u1EC3u giao th\u1EE9c Modbus TCP/IP v\xe0 ph\xe2n bi\u1EC7t v\u1EDBi Modbus RTU","authors":["gemini"],"tags":["tu-dong-hoa","networking","modbus"],"image":"https://images.unsplash.com/photo-1558494949-ef010cbdcc31?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"prevItem":{"title":"T\u1EA1i sao d\xf9ng t\xedn hi\u1EC7u d\xf2ng 4-20mA v\xe0 c\xf4ng th\u1EE9c scaling tuy\u1EBFn t\xednh trong PLC","permalink":"/shareme/blog/analog-4-20ma-va-cong-thuc-scaling-analog-plc"},"nextItem":{"title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","permalink":"/shareme/blog/data-conversion-tool-guide"}},"content":"N\u1EBFu n\xed b\u01B0\u1EDBc ch\xe2n v\xe0o ng\xe0nh t\u1EF1 \u0111\u1ED9ng h\xf3a, ch\u1EAFc ch\u1EAFn n\xed s\u1EBD g\u1EB7p t\u1EEB kh\xf3a **Modbus**. \u0110\xe2y l\xe0 giao th\u1EE9c truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p ph\u1ED5 bi\u1EBFn nh\u1EA5t th\u1EBF gi\u1EDBi nh\u1EDD t\xednh m\u1EDF, mi\u1EC5n ph\xed v\xe0 c\u1EF1c k\u1EF3 \u0111\u01A1n gi\u1EA3n. Modbus c\xf3 hai bi\u1EBFn th\u1EC3 ng\u1EF1 tr\u1ECB \u1EDF hai t\u1EA7ng v\u1EADt l\xfd kh\xe1c nhau: **Modbus RTU** ch\u1EA1y tr\xean c\xe1p n\u1ED1i ti\u1EBFp (RS-485/RS-232) v\xe0 **Modbus TCP/IP** ch\u1EA1y tr\xean n\u1EC1n Ethernet ti\xeau chu\u1EA9n.\\n\\nNhi\u1EC1u k\u1EF9 s\u01B0 m\u1EDBi ra tr\u01B0\u1EDDng th\u01B0\u1EDDng nh\u1EA7m l\u1EABn gi\u1EEFa hai chu\u1EA9n n\xe0y ho\u1EB7c l\xfang t\xfang khi c\u1EA5u h\xecnh k\u1EBFt n\u1ED1i thi\u1EBFt b\u1ECB. Trong b\xe0i vi\u1EBFt n\xe0y, m\xecnh s\u1EBD ph\xe2n t\xedch chi ti\u1EBFt c\u1EA5u tr\xfac khung truy\u1EC1n c\u1EE7a Modbus TCP/IP, ch\u1EC9 ra \u0111i\u1EC3m kh\xe1c bi\u1EC7t c\u1ED1t l\xf5i v\xe0 h\u01B0\u1EDBng d\u1EABn c\xe1ch chuy\u1EC3n \u0111\u1ED5i gi\u1EEFa hai chu\u1EA9n n\xe0y trong th\u1EF1c t\u1EBF.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. C\u1EA5u tr\xfac khung truy\u1EC1n Modbus TCP/IP: MBAP Header l\xe0 g\xec?\\n\\n\u1EDE chu\u1EA9n Modbus RTU truy\u1EC1n th\u1ED1ng ch\u1EA1y tr\xean RS-485, khung truy\u1EC1n \u0111\u01B0\u1EE3c g\u1ECDi l\xe0 **ADU (Application Data Unit)** bao g\u1ED3m:\\n*   `[Address] (1 byte)`: \u0110\u1ECBa ch\u1EC9 Slave ID.\\n*   `[PDU (Protocol Data Unit)]`: M\xe3 h\xe0m (Function Code) + D\u1EEF li\u1EC7u.\\n*   `[CRC Checksum] (2 bytes)`: M\xe3 ki\u1EC3m tra l\u1ED7i.\\n\\nKhi chuy\u1EC3n sang m\xf4i tr\u01B0\u1EDDng Ethernet (Modbus TCP/IP), giao th\u1EE9c kh\xf4ng c\u1EA7n m\xe3 ki\u1EC3m tra l\u1ED7i CRC n\u1EEFa, v\xec b\u1EA3n th\xe2n t\u1EA7ng li\xean k\u1EBFt d\u1EEF li\u1EC7u v\xe0 t\u1EA7ng v\u1EADn chuy\u1EC3n c\u1EE7a b\u1ED9 giao th\u1EE9c TCP/IP \u0111\xe3 t\u1EF1 th\u1EF1c hi\u1EC7n c\u01A1 ch\u1EBF ph\xe1t hi\u1EC7n v\xe0 s\u1EEDa l\u1ED7i truy\u1EC1n nh\u1EADn c\u1EF1c k\u1EF3 tin c\u1EADy r\u1ED3i.\\n\\nThay v\xe0o \u0111\xf3, Modbus TCP/IP lo\u1EA1i b\u1ECF tr\u01B0\u1EDDng `Address` v\xe0 `CRC`, \u0111\u1ED3ng th\u1EDDi th\xeam v\xe0o m\u1ED9t \u0111o\u1EA1n d\u1EEF li\u1EC7u d\xe0i 7 bytes \u0111\u1EE9ng \u0111\u1EA7u khung truy\u1EC1n g\u1ECDi l\xe0 **MBAP Header (Modbus Application Protocol Header)**.\\n\\n### C\xf4ng th\u1EE9c ph\xe2n r\xe3 khung truy\u1EC1n Modbus TCP/IP\\n\\nKhung truy\u1EC1n Modbus TCP/IP ho\xe0n ch\u1EC9nh c\xf3 c\u1EA5u tr\xfac nh\u01B0 sau:\\n\\n\\n\\n```math\\n\\\\text{Modbus TCP/IP ADU} = [\\\\text{MBAP Header (7 bytes)}] + [\\\\text{PDU (M\xe3 h\xe0m + D\u1EEF li\u1EC7u)}]\\n```\\n\\n\\n\\n### Chi ti\u1EBFt c\xe1c tr\u01B0\u1EDDng trong MBAP Header:\\n1.  **Transaction Identifier (2 bytes):** ID c\u1EE7a giao d\u1ECBch. Master d\xf9ng \u0111\u1EC3 nh\u1EADn d\u1EA1ng g\xf3i tin ph\u1EA3n h\u1ED3i t\u01B0\u01A1ng \u1EE9ng t\u1EEB Slave. Gi\xe1 tr\u1ECB n\xe0y t\u0103ng d\u1EA7n sau m\u1ED7i l\u1EA7n g\u1EEDi.\\n2.  **Protocol Identifier (2 bytes):** ID giao th\u1EE9c. Lu\xf4n b\u1EB1ng `0x0000` (\u0111\u1EA1i di\u1EC7n cho Modbus).\\n3.  **Length (2 bytes):** \u0110\u1ED9 d\xe0i c\u1EE7a c\xe1c bytes ti\u1EBFp theo (bao g\u1ED3m Unit Identifier v\xe0 PDU).\\n4.  **Unit Identifier (1 byte):** ID thi\u1EBFt b\u1ECB \u0111\xedch. Th\u01B0\u1EDDng b\u1EB1ng `0xFF` ho\u1EB7c `0x01` n\u1EBFu k\u1EBFt n\u1ED1i tr\u1EF1c ti\u1EBFp Ethernet. Tr\u01B0\u1EDDng n\xe0y \u0111\u01B0\u1EE3c d\xf9ng khi Modbus TCP/IP \u0111i qua m\u1ED9t b\u1ED9 chuy\u1EC3n \u0111\u1ED5i gateway \u0111\u1EC3 giao ti\u1EBFp v\u1EDBi thi\u1EBFt b\u1ECB Modbus RTU (RS-485) n\u1ED1i ph\xeda sau.\\n\\n---\\n\\n## 2. Ph\xe2n bi\u1EC7t chi ti\u1EBFt Modbus RTU v\xe0 Modbus TCP/IP\\n\\n\u0110\u1EC3 c\xe1c n\xed d\u1EC5 h\xecnh dung, m\xecnh \u0111\xe3 t\u1ED5ng h\u1EE3p s\u1EF1 kh\xe1c bi\u1EC7t c\u01A1 b\u1EA3n nh\u1EA5t v\xe0o b\u1EA3ng d\u01B0\u1EDBi \u0111\xe2y:\\n\\n| Ti\xeau ch\xed so s\xe1nh | Modbus RTU | Modbus TCP/IP |\\n| :--- | :--- | :--- |\\n| **T\u1EA7ng v\u1EADt l\xfd (Physical)** | C\xe1p n\u1ED1i ti\u1EBFp RS-485 / RS-232 | C\xe1p m\u1EA1ng Ethernet (RJ45, Wifi, C\xe1p quang) |\\n| **Ki\u1EBFn tr\xfac m\u1EA1ng** | Master - Slave (Ch\u1EC9 c\xf3 1 Master duy nh\u1EA5t) | Client - Server (C\xf3 th\u1EC3 c\xf3 nhi\u1EC1u Client truy c\u1EADp \u0111\u1ED3ng th\u1EDDi) |\\n| **C\u1ED5ng k\u1EBFt n\u1ED1i m\u1EA1ng** | C\u1ED5ng COM xo\u1EAFn 2 d\xe2y (A, B) | C\u1ED5ng m\u1EA1ng RJ45 TCP Port m\u1EB7c \u0111\u1ECBnh: **502** |\\n| **Ki\u1EC3m tra l\u1ED7i** | D\xf9ng m\xe3 ki\u1EC3m tra **CRC-16** | T\u1EF1 \u0111\u1ED9ng x\u1EED l\xfd b\u1EDFi l\u1EDBp d\u01B0\u1EDBi c\u1EE7a **TCP/IP** |\\n| **Kho\u1EA3ng c\xe1ch truy\u1EC1n** | L\xean \u0111\u1EBFn **1200 m\xe9t** kh\xf4ng l\u1EB7p | T\u1ED1i \u0111a **100 m\xe9t** (v\u1EDBi c\xe1p m\u1EA1ng Cat5e/Cat6 th\xf4ng th\u01B0\u1EDDng), kh\xf4ng gi\u1EDBi h\u1EA1n n\u1EBFu d\xf9ng c\xe1p quang/Internet |\\n| **T\u1ED1c \u0111\u1ED9 truy\u1EC1n** | Ch\u1EADm (th\u01B0\u1EDDng t\u1EEB 9600 bps \u0111\u1EBFn 115200 bps) | R\u1EA5t nhanh (10 Mbps, 100 Mbps, 1 Gbps) |\\n\\n---\\n\\n## 3. C\xe1ch chuy\u1EC3n \u0111\u1ED5i gi\u1EEFa Modbus RTU v\xe0 Modbus TCP/IP trong th\u1EF1c t\u1EBF\\n\\nTrong c\xe1c d\u1EF1 \xe1n t\u1EF1 \u0111\u1ED9ng h\xf3a hi\u1EC7n \u0111\u1EA1i, vi\u1EC7c k\u1EBFt n\u1ED1i c\xe1c thi\u1EBFt b\u1ECB Modbus RTU c\u0169 (nh\u01B0 \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t \u0111\u1ED9, bi\u1EBFn t\u1EA7n) v\u1EC1 h\u1EC7 th\u1ED1ng gi\xe1m s\xe1t SCADA trung t\xe2m ch\u1EA1y chu\u1EA9n Modbus TCP/IP l\xe0 nhu c\u1EA7u r\u1EA5t l\u1EDBn. K\u1EF9 s\u01B0 th\u01B0\u1EDDng s\u1EED d\u1EE5ng 2 gi\u1EA3i ph\xe1p sau:\\n\\n### Gi\u1EA3i ph\xe1p 1: S\u1EED d\u1EE5ng b\u1ED9 chuy\u1EC3n \u0111\u1ED5i Gateway ph\u1EA7n c\u1EE9ng (Hardware Gateway)\\n*   N\xed mua c\xe1c thi\u1EBFt b\u1ECB chuy\u1EC3n \u0111\u1ED5i Gateway chuy\xean d\u1EE5ng nh\u01B0 **Moxa NPort 5150**, **ICP DAS tGW-715**, hay **ATC-3000**.\\n*   Thi\u1EBFt b\u1ECB n\xe0y c\xf3 1 c\u1ED5ng RJ45 v\xe0 1 c\u1ED5ng RS-485. N\xf3 ho\u1EA1t \u0111\u1ED9ng nh\u01B0 m\u1ED9t c\u1EA7u n\u1ED1i th\xf4ng tin. Khi nh\u1EADn \u0111\u01B0\u1EE3c g\xf3i tin Modbus TCP/IP t\u1EEB SCADA, Gateway s\u1EBD b\xf3c t\xe1ch MBAP Header, t\xednh to\xe1n v\xe0 th\xeam m\xe3 CRC-16 v\xe0o \u0111\u1EC3 t\u1EA1o th\xe0nh khung Modbus RTU chu\u1EA9n r\u1ED3i \u0111\u1EA9y ra c\u1ED5ng RS-485 xu\u1ED1ng c\xe1c Slave. Sau khi nh\u1EADn \u0111\u01B0\u1EE3c ph\u1EA3n h\u1ED3i t\u1EEB Slave, n\xf3 l\xe0m ng\u01B0\u1EE3c l\u1EA1i \u0111\u1EC3 g\u1EEDi tr\u1EA3 d\u1EEF li\u1EC7u v\u1EC1 SCADA.\\n\\n### Gi\u1EA3i ph\xe1p 2: S\u1EED d\u1EE5ng PLC l\xe0m thi\u1EBFt b\u1ECB chuy\u1EC3n \u0111\u1ED5i trung gian\\n*   H\u1EA7u h\u1EBFt c\xe1c d\xf2ng PLC trung b\xecnh hi\u1EC7n nay (nh\u01B0 Siemens S7-1200, Mitsubishi FX5U) \u0111\u1EC1u t\xedch h\u1EE3p s\u1EB5n c\u1EA3 c\u1ED5ng Ethernet v\xe0 c\u1ED5ng RS-485.\\n*   N\xed vi\u1EBFt ch\u01B0\u01A1ng tr\xecnh trong PLC l\u1EADp l\u1ECBch g\u1ECDi c\xe1c kh\u1ED1i l\u1EC7nh Modbus RTU Master \u0111\u1EC3 \u0111\u1ECDc d\u1EEF li\u1EC7u t\u1EEB thi\u1EBFt b\u1ECB RS-485 l\u01B0u v\xe0o b\u1ED9 nh\u1EDB \u0111\u1EC7m (DB/M). \u0110\u1ED3ng th\u1EDDi b\u1EADt t\xednh n\u0103ng Modbus TCP Server tr\xean PLC \u0111\u1EC3 cho ph\xe9p ph\u1EA7n m\u1EC1m SCADA k\u1EBFt n\u1ED1i v\xe0o v\xe0 \u0111\u1ECDc tr\u1EF1c ti\u1EBFp t\u1EEB c\xe1c v\xf9ng nh\u1EDB \u0111\u1EC7m \u0111\xf3. C\xe1ch n\xe0y t\u1ED1n th\xeam c\xf4ng vi\u1EBFt code nh\u01B0ng l\u1EA1i ti\u1EBFt ki\u1EC7m chi ph\xed ph\u1EA7n c\u1EE9ng r\u1EA5t nhi\u1EC1u.\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF\\n*   Khi c\u1EA5u h\xecnh k\u1EBFt n\u1ED1i Modbus TCP/IP tr\xean c\xe1c ph\u1EA7n m\u1EC1m SCADA (nh\u01B0 Kepware, Igniton), n\u1EBFu k\u1EBFt n\u1ED1i b\u1ECB l\u1ED7i ng\u1EAFt qu\xe3ng, h\xe3y t\u0103ng th\u1EDDi gian **Timeout** c\u1EE7a driver l\xean kho\u1EA3ng **1000ms \u0111\u1EBFn 2000ms** n\u1EBFu h\u1EC7 th\u1ED1ng \u0111i qua b\u1ED9 Gateway chuy\u1EC3n \u0111\u1ED5i RTU. B\u1EDFi v\xec t\u1ED1c \u0111\u1ED9 truy\u1EC1n tr\xean \u0111\u01B0\u1EDDng truy\u1EC1n RS-485 ch\u1EADm h\u01A1n m\u1EA1ng Ethernet h\xe0ng tr\u0103m l\u1EA7n, n\xean SCADA c\u1EA7n ch\u1EDD l\xe2u h\u01A1n \u0111\u1EC3 thi\u1EBFt b\u1ECB Slave ph\u1EA3n h\u1ED3i xong."},{"id":"data-conversion-tool-guide","metadata":{"permalink":"/shareme/blog/data-conversion-tool-guide","source":"@site/blog/2026/2026-07-20-data-converter.mdx","title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","description":"Trong l\u0129nh v\u1EF1c t\u1EF1 \u0111\u1ED9ng h\xf3a, l\u1EADp tr\xecnh PLC/SCADA/HMI v\xe0 thi\u1EBFt k\u1EBF thi\u1EBFt b\u1ECB IoT c\xf4ng nghi\u1EC7p, vi\u1EC7c x\u1EED l\xfd d\u1EEF li\u1EC7u th\xf4 (raw bytes) t\u1EEB c\xe1c c\u1EA3m bi\u1EBFn hay c\u01A1 c\u1EA5u ch\u1EA5p h\xe0nh qua \u0111\u01B0\u1EDDng truy\u1EC1n RS-485 / Modbus RTU l\xe0 c\xf4ng vi\u1EC7c th\u01B0\u1EDDng xuy\xean di\u1EC5n ra h\xe0ng ng\xe0y...","date":"2026-07-20T00:00:00.000Z","tags":[{"inline":false,"label":"Data Conversion","permalink":"/shareme/blog/tags/data-conversion"},{"inline":false,"label":"IEEE 754","permalink":"/shareme/blog/tags/ieee754"},{"inline":false,"label":"CRC16","permalink":"/shareme/blog/tags/crc16"},{"inline":false,"label":"Modbus","permalink":"/shareme/blog/tags/modbus"}],"readingTime":14.03,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"data-conversion-tool-guide","title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","authors":["gemini"],"tags":["data-conversion","ieee754","crc16","modbus"],"image":"https://pbs.twimg.com/media/HNSX94cawAAw37i.png"},"unlisted":false,"prevItem":{"title":"T\xecm hi\u1EC3u giao th\u1EE9c Modbus TCP/IP v\xe0 ph\xe2n bi\u1EC7t v\u1EDBi Modbus RTU","permalink":"/shareme/blog/tim-hieu-modbus-tcp-ip-vs-modbus-rtu"},"nextItem":{"title":"So s\xe1nh 4 ph\u01B0\u01A1ng ph\xe1p kh\u1EDFi \u0111\u1ED9ng \u0111\u1ED9ng c\u01A1 3 pha ph\u1ED5 bi\u1EBFn nh\u1EA5t trong c\xf4ng nghi\u1EC7p","permalink":"/shareme/blog/phuong-phap-khoi-dong-dong-co-3-pha"}},"content":"import MathRenderer from \\"@site/src/components/MathRenderer\\";\\n\\nTrong l\u0129nh v\u1EF1c t\u1EF1 \u0111\u1ED9ng h\xf3a, l\u1EADp tr\xecnh PLC/SCADA/HMI v\xe0 thi\u1EBFt k\u1EBF thi\u1EBFt b\u1ECB IoT c\xf4ng nghi\u1EC7p, vi\u1EC7c x\u1EED l\xfd d\u1EEF li\u1EC7u th\xf4 (raw bytes) t\u1EEB c\xe1c c\u1EA3m bi\u1EBFn hay c\u01A1 c\u1EA5u ch\u1EA5p h\xe0nh qua \u0111\u01B0\u1EDDng truy\u1EC1n **RS-485 / Modbus RTU** l\xe0 c\xf4ng vi\u1EC7c th\u01B0\u1EDDng xuy\xean di\u1EC5n ra h\xe0ng ng\xe0y...\\n\\n\u0110\u1EC3 gi\u1EA3i quy\u1EBFt tri\u1EC7t \u0111\u1EC3 c\xe1c v\u1EA5n \u0111\u1EC1 n\xe0y, m\xecnh \u0111\xe3 x\xe2y d\u1EF1ng b\u1ED9 c\xf4ng c\u1EE5 **[Data Conversion Tool](pathname:///shareme/tool/)**...\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Gi\u1EDBi thi\u1EC7u t\u1ED5ng quan v\u1EC1 Tool Data Conversion\\n\\nB\u1ED9 c\xf4ng c\u1EE5 **Data Conversion Tool** l\xe0 m\u1ED9t \u1EE9ng d\u1EE5ng web single-page \u0111a n\u0103ng gi\xfap N\xed nhanh ch\xf3ng ph\xe2n t\xedch, chuy\u1EC3n \u0111\u1ED5i v\xe0 \u0111\xf3ng g\xf3i d\u1EEF li\u1EC7u m\xe0 kh\xf4ng c\u1EA7n vi\u1EBFt code hay c\xe0i \u0111\u1EB7t c\xe1c ph\u1EA7n m\u1EC1m m\xf4 ph\u1ECFng ph\u1EE9c t\u1EA1p.\\n\\nGiao di\u1EC7n bao g\u1ED3m 6 tab ch\u1EE9c n\u0103ng chuy\xean bi\u1EC7t:\\n1. **H\u1EC7 c\u01A1 s\u1ED1 (Number Base Converter):** Chuy\u1EC3n \u0111\u1ED5i qua l\u1EA1i gi\u1EEFa Th\u1EADp ph\xe2n, Th\u1EADp l\u1EE5c ph\xe2n, Nh\u1ECB ph\xe2n v\xe0 B\xe1t ph\xe2n, \u0111\u1ED3ng th\u1EDDi t\xe1ch Byte/Word v\xe0 xem Bit Map.\\n2. **CRC16 (Modbus RTU Calculator):** T\xednh to\xe1n m\xe3 ki\u1EC3m tra l\u1ED7i 16-bit theo chu\u1EA9n Modbus RTU.\\n3. **Dec/Hex/Swap (Data Converter):** Chuy\u1EC3n \u0111\u1ED5i Dec $\\\\leftrightarrow$ Hex c\xf3/kh\xf4ng d\u1EA5u (8/16/32-bit) v\xe0 ho\xe1n \u0111\u1ED5i v\u1ECB tr\xed Byte/Word.\\n4. **Float $\\\\leftrightarrow$ Reg (IEEE 754 Converter):** Chuy\u1EC3n \u0111\u1ED5i s\u1ED1 th\u1EF1c 32-bit th\xe0nh hai thanh ghi Modbus 16-bit v\xe0 ng\u01B0\u1EE3c l\u1EA1i.\\n5. **Modbus Frame (RTU Builder):** T\u1EF1 \u0111\u1ED9ng t\u1EA1o khung truy\u1EC1n Modbus RTU chu\u1EA9n theo m\xe3 h\xe0m \u0111\u1ECDc/ghi.\\n6. **ASCII $\\\\leftrightarrow$ HEX Converter:** D\u1ECBch chu\u1ED7i k\xfd t\u1EF1 ASCII sang HEX bytes v\xe0 ng\u01B0\u1EE3c l\u1EA1i k\xe8m b\u1EA3ng tra c\u1EE9u m\xe3 \u0111i\u1EC1u khi\u1EC3n.\\n\\n---\\n\\n## 2. C\xf4ng d\u1EE5ng, C\xf4ng th\u1EE9c to\xe1n h\u1ECDc v\xe0 C\xe1ch \xe1p d\u1EE5ng c\u1EE7a t\u1EEBng Tab\\n\\n### 2.1. Tab 1: H\u1EC7 c\u01A1 s\u1ED1 (Number Base Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i t\u1EE9c th\u1EDDi m\u1ED9t gi\xe1 tr\u1ECB s\u1ED1 gi\u1EEFa c\xe1c h\u1EC7 c\u01A1 s\u1ED1 ph\u1ED5 bi\u1EBFn: Th\u1EADp ph\xe2n (Dec), Th\u1EADp l\u1EE5c ph\xe2n (Hex), Nh\u1ECB ph\xe2n (Bin) v\xe0 B\xe1t ph\xe2n (Oct). \u0110\u1ED3ng th\u1EDDi ph\xe2n t\xedch m\u1ED9t s\u1ED1 nguy\xean l\u1EDBn th\xe0nh c\xe1c ph\u1EA7n nh\u1ECF h\u01A1n: **Low Byte, High Byte, Low Word, High Word** v\xe0 bi\u1EC3u di\u1EC5n d\u01B0\u1EDBi d\u1EA1ng s\u01A1 \u0111\u1ED3 Bit Map 16-bit tr\u1EF1c quan.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\n\u0110\u1EC3 chuy\u1EC3n \u0111\u1ED5i m\u1ED9t s\u1ED1 \u1EDF h\u1EC7 c\u01A1 s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`b`} /> c\xf3 c\xe1c ch\u1EEF s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`d_n d_{n-1} \\\\dots d_0`} /> sang h\u1EC7 th\u1EADp ph\xe2n (Dec):\\n<MathRenderer formula={String.raw`N_{10} = \\\\sum_{i=0}^{n} d_i \\\\cdot b^i = d_n \\\\cdot b^n + d_{n-1} \\\\cdot b^{n-1} + \\\\dots + d_0 \\\\cdot b^0`} />\\n\\n*V\xed d\u1EE5:* V\u1EDBi s\u1ED1 HEX <MathRenderer displayMode={false} formula={String.raw`FF_{16}`} />:\\n<MathRenderer formula={String.raw`N_{10} = F \\\\cdot 16^1 + F \\\\cdot 16^0 = 15 \\\\cdot 16 + 15 \\\\cdot 1 = 255_{10}`} />\\n\\nC\xf4ng th\u1EE9c t\xe1ch c\xe1c th\xe0nh ph\u1EA7n Byte v\xe0 Word t\u1EEB m\u1ED9t s\u1ED1 nguy\xean kh\xf4ng d\u1EA5u <MathRenderer displayMode={false} formula={String.raw`N`} />:\\n*   **Low Byte (Byte 0):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{Low Byte}} = N \\\\pmod{2^8} = N \\\\ \\\\& \\\\ \\\\text{0xFF}`} />\\n*   **High Byte (Byte 1):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{High Byte}} = \\\\lfloor \\\\frac{N}{2^8} \\\\rfloor \\\\pmod{2^8} = (N \\\\gg 8) \\\\ \\\\& \\\\ \\\\text{0xFF}`} />\\n*   **Low Word (Word 0):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{Low Word}} = N \\\\pmod{2^{16}} = N \\\\ \\\\& \\\\ \\\\text{0xFFFF}`} />\\n*   **High Word (Word 1):** \\n    <MathRenderer formula={String.raw`N_{\\\\text{High Word}} = \\\\lfloor \\\\frac{N}{2^{16}} \\\\rfloor \\\\pmod{2^{16}} = (N \\\\gg 16) \\\\ \\\\& \\\\ \\\\text{0xFFFF}`} />\\n\\n*(Trong \u0111\xf3 <MathRenderer displayMode={false} formula={String.raw`\\\\&`} /> k\xfd hi\u1EC7u cho ph\xe9p to\xe1n bitwise AND, v\xe0 <MathRenderer displayMode={false} formula={String.raw`\\\\gg`} /> k\xfd hi\u1EC7u cho ph\xe9p to\xe1n d\u1ECBch ph\u1EA3i bitwise).*\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi c\u1EA5u h\xecnh b\u1EA3n \u0111\u1ED3 b\u1ED9 nh\u1EDB (Address Map) tr\xean HMI, ta th\u01B0\u1EDDng ph\u1EA3i ph\xe2n r\xe3 m\u1ED9t thanh ghi 16-bit th\xe0nh c\xe1c bit \u0111\u01A1n l\u1EBB (Bit Lamp/Bit Switch). V\xed d\u1EE5 thanh ghi tr\u1EA1ng th\xe1i m\xe1y c\xf3 gi\xe1 tr\u1ECB Dec l\xe0 `32768`, nh\u1EADp v\xe0o c\xf4ng c\u1EE5 s\u1EBD th\u1EA5y ngay bit th\u1EE9 `15` \u0111ang \u1EDF m\u1EE9c `1` (ON), c\xe1c bit kh\xe1c b\u1EB1ng `0` (OFF).\\n\\n---\\n\\n### 2.2. Tab 2: CRC16 Modbus Calculator\\n\\n#### C\xf4ng d\u1EE5ng\\nT\xednh to\xe1n m\xe3 ki\u1EC3m tra l\u1ED7i (Cyclic Redundancy Check) 16-bit cho m\u1ED9t chu\u1ED7i d\u1EEF li\u1EC7u \u0111\u1EA7u v\xe0o (h\u1EC7 HEX ho\u1EB7c chu\u1ED7i k\xfd t\u1EF1 ASCII). \u0110\u1EA7u ra tr\u1EA3 v\u1EC1 gi\xe1 tr\u1ECB CRC \u0111\u1EA7y \u0111\u1EE7, chia s\u1EB5n Byte th\u1EA5p (g\u1EEDi tr\u01B0\u1EDBc) v\xe0 Byte cao (g\u1EEDi sau) c\xf9ng khung truy\u1EC1n ho\xe0n ch\u1EC9nh k\xe8m m\xe3 ki\u1EC3m tra l\u1ED7i.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc (Thu\u1EADt to\xe1n CRC16 Modbus)\\nS\u1EED d\u1EE5ng \u0111a th\u1EE9c sinh (Polynomial): **<MathRenderer displayMode={false} formula={String.raw`0x8005`} />** \u0111\u1EA3o ng\u01B0\u1EE3c bit th\xe0nh **<MathRenderer displayMode={false} formula={String.raw`0xA001`} />**.\\nGi\xe1 tr\u1ECB kh\u1EDFi t\u1EA1o ban \u0111\u1EA7u (Initial Value) l\xe0 **<MathRenderer displayMode={false} formula={String.raw`0xFFFF`} />**.\\n\\nThu\u1EADt to\xe1n t\xednh to\xe1n t\u1EEBng byte nh\u01B0 sau:\\n1. G\xe1n gi\xe1 tr\u1ECB thanh ghi <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC} = \\\\text{0xFFFF}`} />.\\n2. V\u1EDBi m\u1ED7i byte d\u1EEF li\u1EC7u <MathRenderer displayMode={false} formula={String.raw`B_j`} /> trong chu\u1ED7i (<MathRenderer displayMode={false} formula={String.raw`j`} /> ch\u1EA1y t\u1EEB <MathRenderer displayMode={false} formula={String.raw`0`} /> \u0111\u1EBFn <MathRenderer displayMode={false} formula={String.raw`M-1`} />):\\n   <MathRenderer formula={String.raw`\\\\text{CRC} = \\\\text{CRC} \\\\oplus B_j`} />\\n3. Th\u1EF1c hi\u1EC7n l\u1EB7p 8 l\u1EA7n \u1EE9ng v\u1EDBi 8 bit (bi\u1EBFn ch\u1EA1y <MathRenderer displayMode={false} formula={String.raw`k`} /> t\u1EEB <MathRenderer displayMode={false} formula={String.raw`0`} /> \u0111\u1EBFn <MathRenderer displayMode={false} formula={String.raw`7`} />):\\n   <MathRenderer formula={String.raw`\\\\text{CRC}_{next} = \\\\begin{cases} (\\\\text{CRC} \\\\gg 1) \\\\oplus \\\\text{0xA001} & \\\\text{n\u1EBFu LSB}(\\\\text{CRC}) = 1 \\\\\\\\ \\\\text{CRC} \\\\gg 1 & \\\\text{n\u1EBFu LSB}(\\\\text{CRC}) = 0 \\\\end{cases}`} />\\n4. Sau khi duy\u1EC7t h\u1EBFt t\u1EA5t c\u1EA3 c\xe1c byte, gi\xe1 tr\u1ECB <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC}`} /> cu\u1ED1i c\xf9ng ch\xednh l\xe0 m\xe3 ki\u1EC3m tra l\u1ED7i. Theo chu\u1EA9n Modbus RTU, byte th\u1EA5p c\u1EE7a <MathRenderer displayMode={false} formula={String.raw`\\\\text{CRC}`} /> s\u1EBD \u0111\u01B0\u1EE3c ch\xe8n v\xe0o tr\u01B0\u1EDBc, byte cao ch\xe8n v\xe0o sau trong khung truy\u1EC1n.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi n\xed vi\u1EBFt ch\u01B0\u01A1ng tr\xecnh vi \u0111i\u1EC1u khi\u1EC3n (Arduino/STM32) ho\u1EB7c Script trong Python/C# \u0111\u1EC3 giao ti\u1EBFp v\u1EDBi thi\u1EBFt b\u1ECB Modbus, n\xed c\xf3 th\u1EC3 nh\u1EADp th\u1EE7 c\xf4ng khung d\u1EEF li\u1EC7u v\xed d\u1EE5 `01 03 00 00 00 0A` v\xe0o c\xf4ng c\u1EE5 \u0111\u1EC3 l\u1EA5y nhanh CRC l\xe0 `0xC5CD` (Lo Byte: `C5`, Hi Byte: `CD`). D\xf9ng k\u1EBFt qu\u1EA3 n\xe0y \u0111\u1EC3 ki\u1EC3m tra xem thu\u1EADt to\xe1n m\xe3 h\xf3a trong ch\u01B0\u01A1ng tr\xecnh c\u1EE7a n\xed \u0111\xe3 vi\u1EBFt \u0111\xfang ch\u01B0a.\\n\\n---\\n\\n### 2.3. Tab 3: Dec/Hex/Swap (Data Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nH\u1ED7 tr\u1EE3 chuy\u1EC3n \u0111\u1ED5i n\xe2ng cao gi\u1EEFa s\u1ED1 Th\u1EADp ph\xe2n v\xe0 Th\u1EADp l\u1EE5c ph\xe2n c\xf3 t\xf9y ch\u1ECDn k\xedch th\u01B0\u1EDBc d\u1EEF li\u1EC7u (8-bit, 16-bit, 32-bit) v\xe0 ch\u1EBF \u0111\u1ED9 c\xf3 d\u1EA5u (Signed) ho\u1EB7c kh\xf4ng d\u1EA5u (Unsigned). \u0110\u1ED3ng th\u1EDDi hi\u1EC3n th\u1ECB k\u1EBFt qu\u1EA3 **Byte Swap** (cho d\u1EEF li\u1EC7u 16-bit) v\xe0 **Word Swap** (cho d\u1EEF li\u1EC7u 32-bit).\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\n\u0110\u1ED1i v\u1EDBi s\u1ED1 nguy\xean c\xf3 d\u1EA5u (Signed) s\u1EED d\u1EE5ng bi\u1EC3u di\u1EC5n **B\xf9 2 (Two\'s Complement)**, m\u1ED9t s\u1ED1 nguy\xean kh\xf4ng d\u1EA5u <MathRenderer displayMode={false} formula={String.raw`X`} /> c\xf3 \u0111\u1ED9 r\u1ED9ng <MathRenderer displayMode={false} formula={String.raw`N`} />-bit s\u1EBD \u0111\u01B0\u1EE3c \xe1nh x\u1EA1 sang s\u1ED1 c\xf3 d\u1EA5u nh\u01B0 sau:\\n<MathRenderer formula={String.raw`X_{\\\\text{signed}} = \\\\begin{cases} X_{\\\\text{unsigned}} & \\\\text{n\u1EBFu } X_{\\\\text{unsigned}} < 2^{N-1} \\\\\\\\ X_{\\\\text{unsigned}} - 2^N & \\\\text{n\u1EBFu } X_{\\\\text{unsigned}} \\\\ge 2^{N-1} \\\\end{cases}`} />\\n\\n*V\xed d\u1EE5 16-bit (<MathRenderer displayMode={false} formula={String.raw`N=16`} />):*\\n*   N\u1EBFu \u0111\u1ECDc \u0111\u01B0\u1EE3c gi\xe1 tr\u1ECB HEX l\xe0 `FFFF` (Dec kh\xf4ng d\u1EA5u l\xe0 <MathRenderer displayMode={false} formula={String.raw`65535 \\\\ge 32768`} />):\\n    <MathRenderer formula={String.raw`X_{\\\\text{signed}} = 65535 - 65536 = -1`} />\\n*   **Ph\xe9p Byte Swap (16-bit):** \u0110\u1EA3o v\u1ECB tr\xed byte cao v\xe0 byte th\u1EA5p c\u1EE7a s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`V_{16} = B_1 B_0`} />:\\n    <MathRenderer formula={String.raw`\\\\text{ByteSwap}(V_{16}) = (B_0 \\\\ll 8) \\\\ | \\\\ B_1`} />\\n*   **Ph\xe9p Word Swap (32-bit):** \u0110\u1EA3o v\u1ECB tr\xed 2 word 16-bit c\u1EE7a s\u1ED1 <MathRenderer displayMode={false} formula={String.raw`V_{32} = W_1 W_0`} />:\\n    <MathRenderer formula={String.raw`\\\\text{WordSwap}(V_{32}) = ((W_0 \\\\ \\\\& \\\\ \\\\text{0xFFFF}) \\\\ll 16) \\\\ | \\\\ (W_1 \\\\ \\\\& \\\\ \\\\text{0xFFFF})`} />\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\n*   **X\u1EED l\xfd s\u1ED1 \xe2m:** PLC \u0111\u1ECDc c\u1EA3m bi\u1EBFn nhi\u1EC7t \u0111\u1ED9 tr\u1EA3 v\u1EC1 gi\xe1 tr\u1ECB raw d\u1EA1ng s\u1ED1 nguy\xean 16-bit. C\u1EA3m bi\u1EBFn b\xe1o l\u1ED7i tr\u1EA3 v\u1EC1 `-1`. N\u1EBFu HMI \u0111\u1ECDc \u1EDF c\u1EA5u h\xecnh Unsigned s\u1EBD hi\u1EC3n th\u1ECB `65535` g\xe2y hi\u1EC3u nh\u1EA7m. C\xf4ng c\u1EE5 gi\xfap ta \u0111\u1ED1i chi\u1EBFu nhanh \u0111\u1EC3 nh\u1EADn d\u1EA1ng l\u1ED7i ki\u1EC3u d\u1EEF li\u1EC7u.\\n*   **Kh\u1EAFc ph\u1EE5c Byte/Word Swap:** Khi g\u1EEDi d\u1EEF li\u1EC7u t\u1EEB PLC h\xe3ng Siemens (Big-Endian) sang PLC h\xe3ng Mitsubishi (Little-Endian), th\u1EE9 t\u1EF1 byte ho\u1EB7c word th\u01B0\u1EDDng b\u1ECB \u0111\u1EA3o l\u1ED9n. Ch\u1EC9 c\u1EA7n nh\u1EADp gi\xe1 tr\u1ECB l\u1ED7i v\xe0o, xem k\u1EBFt qu\u1EA3 Swap \u0111\u1EC3 bi\u1EBFt c\u1EA5u h\xecnh ho\xe1n \u0111\u1ED5i n\xe0o l\xe0 ch\xednh x\xe1c.\\n\\n---\\n\\n### 2.4. Tab 4: Float $\\\\leftrightarrow$ Register (IEEE 754 Converter)\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i m\u1ED9t s\u1ED1 th\u1EF1c 32-bit (Float 32) sang hai thanh ghi Modbus 16-bit (Holding Register) v\xe0 ng\u01B0\u1EE3c l\u1EA1i theo chu\u1EA9n **IEEE 754**. H\u1ED7 tr\u1EE3 l\u1EF1a ch\u1ECDn th\u1EE9 t\u1EF1 hi\u1EC3n th\u1ECB Word (High Word tr\u01B0\u1EDBc hay Low Word tr\u01B0\u1EDBc).\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc (Chu\u1EA9n s\u1ED1 th\u1EF1c IEEE 754)\\nS\u1ED1 th\u1EF1c \u0111\u01A1n \u0111\u1ED9 ch\xednh x\xe1c (Single-precision floating-point) 32-bit g\u1ED3m 3 ph\u1EA7n:\\n1.  **Bit d\u1EA5u (Sign bit - <MathRenderer displayMode={false} formula={String.raw`s`} />):** 1 bit (bit 31).\\n2.  **Ph\u1EA7n m\u0169 (Exponent - <MathRenderer displayMode={false} formula={String.raw`E`} />):** 8 bit (bit 30 \u0111\u1EBFn 23).\\n3.  **Ph\u1EA7n \u0111\u1ECBnh tr\u1ECB (Fraction / Mantissa - <MathRenderer displayMode={false} formula={String.raw`M`} />):** 23 bit (bit 22 \u0111\u1EBFn 0).\\n\\nGi\xe1 tr\u1ECB th\u1EF1c <MathRenderer displayMode={false} formula={String.raw`V`} /> \u0111\u01B0\u1EE3c t\xednh b\u1EB1ng c\xf4ng th\u1EE9c:\\n<MathRenderer formula={String.raw`V = (-1)^s \\\\times \\\\left(1 + \\\\sum_{i=1}^{23} b_{23-i} \\\\cdot 2^{-i}\\\\right) \\\\times 2^{E - 127}`} />\\nHay vi\u1EBFt g\u1ECDn:\\n<MathRenderer formula={String.raw`V = (-1)^s \\\\times (1 + M) \\\\times 2^{E - 127}`} />\\n\\n*V\xed d\u1EE5:* S\u1ED1 th\u1EF1c <MathRenderer displayMode={false} formula={String.raw`3.14`} /> c\xf3 bi\u1EC3u di\u1EC5n nh\u1ECB ph\xe2n 32-bit l\xe0:\\n<MathRenderer formula={String.raw`\\\\text{0x4048F5C3} \\\\rightarrow \\\\text{High Word} = \\\\text{0x4048} \\\\ (16456), \\\\ \\\\text{Low Word} = \\\\text{0xF5C3} \\\\ (62915)`} />\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi PLC \u0111\u1ECDc th\xf4ng s\u1ED1 L\u01B0u l\u01B0\u1EE3ng (Flow rate) ho\u1EB7c \u0110i\u1EC7n n\u0103ng ti\xeau th\u1EE5 (kWh) d\u1EA1ng s\u1ED1 th\u1EF1c t\u1EEB \u0111\u1ED3ng h\u1ED3 \u0111o th\xf4ng qua giao th\u1EE9c Modbus, k\u1EBFt qu\u1EA3 tr\u1EA3 v\u1EC1 l\xe0 hai thanh ghi 16-bit \u0111\u1ED9c l\u1EADp. \\nN\u1EBFu n\xed nh\u1EADn \u0111\u01B0\u1EE3c hai gi\xe1 tr\u1ECB `16456` v\xe0 `62915` t\u1EEB \u0111\u1ED3ng h\u1ED3, ch\u1EC9 c\u1EA7n nh\u1EADp v\xe0o Tab 4 \u1EDF ch\u1EBF \u0111\u1ED9 Register $\\\\rightarrow$ Float s\u1EBD gi\u1EA3i m\xe3 \u0111\u01B0\u1EE3c ngay gi\xe1 tr\u1ECB th\u1EF1c l\xe0 `3.14`. N\u1EBFu ra s\u1ED1 k\u1EF3 l\u1EA1, h\xe3y chuy\u1EC3n \u0111\u1ED5i Word Order t\u1EEB **High Word tr\u01B0\u1EDBc (Big-Endian)** sang **Low Word tr\u01B0\u1EDBc (Little-Endian Word)** \u0111\u1EC3 d\xf2 xem thi\u1EBFt b\u1ECB c\u1EE7a n\xed \u0111ang g\u1EEDi theo chu\u1EA9n n\xe0o.\\n\\n---\\n\\n### 2.5. Tab 5: Modbus Frame (Modbus RTU Frame Builder)\\n\\n#### C\xf4ng d\u1EE5ng\\nGi\xfap t\u1EF1 \u0111\u1ED9ng \u0111\xf3ng g\xf3i m\u1ED9t khung truy\u1EC1n Modbus RTU ho\xe0n ch\u1EC9nh d\u1EF1a tr\xean c\xe1c tham s\u1ED1 c\u1EA5u h\xecnh: **Slave ID, Function Code (FC01 - FC10), Start Address, Quantity** v\xe0 **D\u1EEF li\u1EC7u ghi (Write Data)**. \\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\nKhung truy\u1EC1n Modbus RTU Application Data Unit (ADU) c\xf3 c\u1EA5u tr\xfac:\\n<MathRenderer formula={String.raw`\\\\text{ADU} = [\\\\text{Slave ID}] + [\\\\text{Function Code}] + [\\\\text{Data Field}] + [\\\\text{CRC16 Checksum}`} />\\n\\n*   **Slave ID (1 byte):** \u0110\u1ECBa ch\u1EC9 thi\u1EBFt b\u1ECB \u0111\xedch (<MathRenderer displayMode={false} formula={String.raw`0x01 - 0xF7`} />).\\n*   **Function Code (1 byte):** M\xe3 h\xe0m x\u1EED l\xfd d\u1EEF li\u1EC7u (<MathRenderer displayMode={false} formula={String.raw`0x01`} />: \u0111\u1ECDc Coil, <MathRenderer displayMode={false} formula={String.raw`0x03`} />: \u0111\u1ECDc thanh ghi, <MathRenderer displayMode={false} formula={String.raw`0x10`} />: ghi nhi\u1EC1u thanh ghi...).\\n*   **Data Field (<MathRenderer displayMode={false} formula={String.raw`N`} /> bytes):** \u0110\u1ECBa ch\u1EC9 b\u1EAFt \u0111\u1EA7u, s\u1ED1 l\u01B0\u1EE3ng, ho\u1EB7c gi\xe1 tr\u1ECB ghi c\u1EE5 th\u1EC3.\\n*   **CRC16 Checksum (2 bytes):** T\xednh theo thu\u1EADt to\xe1n CRC16 Modbus tr\xean to\xe0n b\u1ED9 c\xe1c byte tr\u01B0\u1EDBc \u0111\xf3.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nKhi ki\u1EC3m tra l\u1ED7i truy\u1EC1n th\xf4ng b\u1EB1ng c\xe1c c\xf4ng c\u1EE5 Terminal chuy\xean d\u1EE5ng nh\u01B0 Hercules, RealTerm, hay Docklight, n\xed kh\xf4ng th\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp l\u1EC7nh th\xf4 n\u1EBFu kh\xf4ng t\xednh m\xe3 CRC. Thay v\xec m\u1EDF c\xe1c ph\u1EA7n m\u1EC1m t\xednh CRC r\u1EDDi r\u1EA1c, n\xed ch\u1EC9 c\u1EA7n \u0111i\u1EC1n c\xe1c tham s\u1ED1 tr\u1EF1c quan trong Tab 5, copy to\xe0n b\u1ED9 khung Hex thu \u0111\u01B0\u1EE3c v\xe0 d\xe1n v\xe0o ph\u1EA7n m\u1EC1m Terminal \u0111\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp xu\u1ED1ng bi\u1EBFn t\u1EA7n, c\u1EA3m bi\u1EBFn.\\n\\n---\\n\\n### 2.6. Tab 6: ASCII $\\\\leftrightarrow$ HEX Converter\\n\\n#### C\xf4ng d\u1EE5ng\\nChuy\u1EC3n \u0111\u1ED5i nhanh ch\xf3ng gi\u1EEFa m\u1ED9t chu\u1ED7i k\xfd t\u1EF1 v\u0103n b\u1EA3n (ASCII) v\xe0 m\u1ED9t chu\u1ED7i m\xe3 HEX t\u01B0\u01A1ng \u1EE9ng (c\xe1ch nhau b\u1EDFi kho\u1EA3ng tr\u1EAFng). Tab n\xe0y c\u0169ng t\xedch h\u1EE3p s\u1EB5n b\u1EA3ng tra c\u1EE9u nhanh c\xe1c k\xfd t\u1EF1 \u0111i\u1EC1u khi\u1EC3n \u0111\u1EB7c bi\u1EC7t th\u01B0\u1EDDng g\u1EB7p trong giao th\u1EE9c truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p.\\n\\n#### C\xf4ng th\u1EE9c to\xe1n h\u1ECDc\\nPh\xe9p chuy\u1EC3n \u0111\u1ED5i d\u1EF1a tr\xean b\u1EA3ng m\xe3 h\xf3a ti\xeau chu\u1EA9n ASCII, \xe1nh x\u1EA1 k\xfd t\u1EF1 <MathRenderer displayMode={false} formula={String.raw`c`} /> sang m\xe3 s\u1ED1 th\u1EADp l\u1EE5c ph\xe2n t\u01B0\u01A1ng \u1EE9ng:\\n<MathRenderer formula={String.raw`\\\\text{ASCII}(c) \\\\longleftrightarrow \\\\text{HEX Code}`} />\\n\\n*V\xed d\u1EE5:* K\xfd t\u1EF1 `\'A\'` c\xf3 m\xe3 Hex l\xe0 `41` (Dec: 65), k\xfd t\u1EF1 \u0111i\u1EC1u khi\u1EC3n b\u1EAFt \u0111\u1EA7u khung truy\u1EC1n `STX` (Start of Text) c\xf3 m\xe3 Hex l\xe0 `02`.\\n\\n#### \xc1p d\u1EE5ng th\u1EF1c t\u1EBF\\nNhi\u1EC1u thi\u1EBFt b\u1ECB c\xf4ng nghi\u1EC7p c\u0169 ho\u1EB7c \u0111\u1EA7u \u0111\u1ECDc m\xe3 v\u1EA1ch (Barcode Scanner), c\xe2n \u0111i\u1EC7n t\u1EED truy\u1EC1n th\xf4ng b\u1EB1ng giao th\u1EE9c ASCII th\xf4 qua c\u1ED5ng RS-232. Khung truy\u1EC1n th\u01B0\u1EDDng \u0111\u01B0\u1EE3c \u0111\u1ECBnh d\u1EA1ng ki\u1EC3u: `[STX] + D\u1EEF li\u1EC7u + [ETX]`. C\xf4ng c\u1EE5 n\xe0y gi\xfap n\xed d\u1ECBch c\xe1c chu\u1ED7i Hex \u0111\u1ECDc \u0111\u01B0\u1EE3c t\u1EEB c\u1ED5ng COM th\xe0nh chu\u1ED7i v\u0103n b\u1EA3n \u0111\u1ECDc \u0111\u01B0\u1EE3c v\xe0 ng\u01B0\u1EE3c l\u1EA1i.\\n\\n---\\n\\n## 3. T\u1ED5ng h\u1EE3p c\xe1ch kh\u1EAFc ph\u1EE5c c\xe1c l\u1ED7i th\u1EF1c t\u1EBF b\u1EB1ng Tool\\n\\n| T\xean l\u1ED7i truy\u1EC1n th\xf4ng | Bi\u1EC3u hi\u1EC7n th\u1EF1c t\u1EBF | C\xe1ch \xe1p d\u1EE5ng Tool \u0111\u1EC3 x\u1EED l\xfd |\\n| :--- | :--- | :--- |\\n| **L\u1ED7i 1: Sai th\u1EE9 t\u1EF1 Word (Word Swap / Endianness)** | \u0110\u1ECDc s\u1ED1 th\u1EF1c Float 32-bit t\u1EEB \u0111\u1ED3ng h\u1ED3 \u0111o, thay v\xec hi\u1EC3n th\u1ECB `220.5` V th\xec m\xe0n h\xecnh PLC hi\u1EC3n th\u1ECB m\u1ED9t s\u1ED1 c\u1EF1c l\u1EDBn ho\u1EB7c c\u1EF1c nh\u1ECF v\xf4 ngh\u0129a. | Nh\u1EADp hai thanh ghi HEX \u0111\u1ECDc \u0111\u01B0\u1EE3c v\xe0o **Tab 4 (Float $\\\\leftrightarrow$ Reg)**, th\u1EED \u0111\u1ED5i t\xf9y ch\u1ECDn th\u1EE9 t\u1EF1 Word gi\u1EEFa **High Word tr\u01B0\u1EDBc** v\xe0 **Low Word tr\u01B0\u1EDBc** cho \u0111\u1EBFn khi thu \u0111\u01B0\u1EE3c s\u1ED1 th\u1EF1c mong mu\u1ED1n. |\\n| **L\u1ED7i 2: Hi\u1EC3n th\u1ECB tr\xe0n s\u1ED1 \xe2m (Signed Mismatch)** | C\u1EA3m bi\u1EBFn l\u1EF1c k\xe9o hi\u1EC3n th\u1ECB t\u1EA3i tr\u1ECDng \xe2m `-50` kg nh\u01B0ng PLC l\u1EA1i hi\u1EC3n th\u1ECB `65486`. | Nh\u1EADp gi\xe1 tr\u1ECB `65486` v\xe0o ph\u1EA7n HEX c\u1EE7a **Tab 3 (Dec/Hex/Swap)**, ch\u1ECDn k\xedch th\u01B0\u1EDBc **16-bit** v\xe0 chuy\u1EC3n \u0111\u1ED5i qua l\u1EA1i gi\u1EEFa **Unsigned** v\xe0 **Signed** \u0111\u1EC3 \u0111\u1ED1i chi\u1EBFu c\xf4ng th\u1EE9c b\xf9 2. |\\n| **L\u1ED7i 3: Khung truy\u1EC1n b\u1ECB l\u1ED7i CRC (CRC Fail)** | G\u1EEDi l\u1EC7nh t\u1EEB PLC nh\u01B0ng bi\u1EBFn t\u1EA7n kh\xf4ng ph\u1EA3n h\u1ED3i, \u0111\xe8n RX/TX tr\xean c\u1ED5ng truy\u1EC1n th\xf4ng nh\xe1y \u0111\u1ECF c\u1EA3nh b\xe1o l\u1ED7i CRC. | Nh\u1EADp khung Hex c\u1EE7a l\u1EC7nh v\xe0o **Tab 2 (CRC16)** \u0111\u1EC3 t\xednh l\u1EA1i CRC, so s\xe1nh v\u1EDBi m\xe3 CRC \u0111ang g\u1EEDi trong PLC \u0111\u1EC3 xem c\xf3 b\u1ECB l\u1ED7i l\u1EADp tr\xecnh ho\u1EB7c \u0111\u1EA3o ng\u01B0\u1EE3c byte CRC hay kh\xf4ng. |\\n| **L\u1ED7i 4: G\u1EEDi sai \u0111\u1ECBa ch\u1EC9 thanh ghi Modbus** | G\u1EEDi l\u1EC7nh \u0111\u1ECDc thanh ghi nh\u01B0ng thi\u1EBFt b\u1ECB Slave tr\u1EA3 v\u1EC1 m\xe3 l\u1ED7i ngo\u1EA1i l\u1EC7 `02` (Illegal Data Address). | S\u1EED d\u1EE5ng **Tab 5 (Modbus Frame)** \u0111\u1EC3 x\xe2y d\u1EF1ng l\u1EA1i khung truy\u1EC1n chu\u1EA9n, l\u01B0u \xfd \u0111\u1ECBa ch\u1EC9 trong khung truy\u1EC1n Modbus th\u1EF1c t\u1EBF ph\u1EA3i tr\u1EEB \u0111i 1 \u0111\u01A1n v\u1ECB so v\u1EDBi \u0111\u1ECBa ch\u1EC9 tr\xean t\xe0i li\u1EC7u (v\xed d\u1EE5 \u0111\u1ECDc thanh ghi `40001` th\xec \u0111i\u1EC1n Start Address l\xe0 `0000`). |\\n\\n---\\n\\n## 4. \u0110\xe1nh gi\xe1 \u01B0u \u0111i\u1EC3m & Nh\u01B0\u1EE3c \u0111i\u1EC3m c\u1EE7a Tool\\n\\n### \u01AFu \u0111i\u1EC3m\\n*   **T\u1EA5t c\u1EA3 trong m\u1ED9t (All-in-One):** T\xedch h\u1EE3p t\u1EA5t c\u1EA3 c\xe1c ti\u1EC7n \xedch chuy\u1EC3n \u0111\u1ED5i c\u1EA7n thi\u1EBFt nh\u1EA5t cho d\xe2n l\u1EADp tr\xecnh \u0111i\u1EC1u khi\u1EC3n t\u1EF1 \u0111\u1ED9ng h\xf3a tr\xean m\u1ED9t trang duy nh\u1EA5t.\\n*   **Ph\u1EA3n h\u1ED3i th\u1EDDi gian th\u1EF1c (Real-time):** Nh\u1EADp gi\xe1 tr\u1ECB \u1EDF b\u1EA5t c\u1EE9 \xf4 n\xe0o, to\xe0n b\u1ED9 c\xe1c \xf4 c\xf2n l\u1EA1i t\u1EF1 \u0111\u1ED9ng t\xednh to\xe1n v\xe0 c\u1EADp nh\u1EADt ngay l\u1EADp t\u1EE9c.\\n*   **Ph\xe2n t\xedch khung tr\u1EF1c quan:** Gi\xfap b\xf3c t\xe1ch c\xe1c th\xe0nh ph\u1EA7n trong g\xf3i tin Modbus (ID, FC, Addr, CRC) m\u1ED9t c\xe1ch sinh \u0111\u1ED9ng, r\u1EA5t h\u1EEFu \xedch cho \u0111\xe0o t\u1EA1o v\xe0 nghi\xean c\u1EE9u.\\n*   **Giao di\u1EC7n hi\u1EC7n \u0111\u1EA1i:** T\u1ED1i \u01B0u hi\u1EC3n th\u1ECB tr\xean c\u1EA3 \u0111i\u1EC7n tho\u1EA1i v\xe0 m\xe1y t\xednh, h\u1ED7 tr\u1EE3 copy nhanh k\u1EBFt qu\u1EA3 qua m\u1ED9t n\xfat nh\u1EA5n b\u1EA5m ti\u1EC7n d\u1EE5ng.\\n\\n### Nh\u01B0\u1EE3c \u0111i\u1EC3m\\n*   **Ch\u01B0a h\u1ED7 tr\u1EE3 c\xe1c thu\u1EADt to\xe1n CRC kh\xe1c:** Hi\u1EC7n t\u1EA1i c\xf4ng c\u1EE5 m\u1EDBi ch\u1EC9 h\u1ED7 tr\u1EE3 t\xednh to\xe1n CRC16 Modbus (\u0111a th\u1EE9c $0xA001$). Ch\u01B0a t\xedch h\u1EE3p c\xe1c chu\u1EA9n CRC ph\u1ED5 bi\u1EBFn kh\xe1c nh\u01B0 CRC8, CRC32, hay CRC16-CCITT.\\n*   **Ch\u01B0a h\u1ED7 tr\u1EE3 k\u1EBFt n\u1ED1i ph\u1EA7n c\u1EE9ng:** Ch\u01B0a h\u1ED7 tr\u1EE3 t\xednh n\u0103ng Web Serial API \u0111\u1EC3 g\u1EEDi tr\u1EF1c ti\u1EBFp d\u1EEF li\u1EC7u t\u1EEB tr\xecnh duy\u1EC7t xu\u1ED1ng c\u1ED5ng COM v\u1EADt l\xfd c\u1EE7a m\xe1y t\xednh (ch\u1EC9 d\u1EEBng l\u1EA1i \u1EDF ph\xe2n t\xedch t\u0129nh).\\n\\n---\\n\\n## 5. K\u1EBFt lu\u1EADn\\n\\nB\u1ED9 c\xf4ng c\u1EE5 **Data Conversion Tool** l\xe0 tr\u1EE3 th\u1EE7 \u0111\u1EAFc l\u1EF1c gi\xfap r\xfat ng\u1EAFn th\u1EDDi gian chu\u1EA9n \u0111o\xe1n v\xe0 kh\u1EAFc ph\u1EE5c l\u1ED7i truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p. Vi\u1EC7c hi\u1EC3u r\xf5 c\xe1c c\xf4ng th\u1EE9c to\xe1n h\u1ECDc \u0111\u1EE9ng sau nh\u01B0 IEEE 754, Two\'s Complement b\xf9 2 hay c\u01A1 ch\u1EBF CRC16 gi\xfap ch\xfang ta l\xe0m ch\u1EE7 ho\xe0n to\xe0n d\u1EEF li\u1EC7u c\u1EE7a h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n. H\xe3y truy c\u1EADp trang **[Tool Chuy\u1EC3n \u0110\u1ED5i D\u1EEF Li\u1EC7u](pathname:///shareme/tool/)** \u0111\u1EC3 tr\u1EA3i nghi\u1EC7m v\xe0 t\u1ED1i \u01B0u h\xf3a c\xf4ng vi\u1EC7c c\u1EE7a n\xed ngay h\xf4m nay!"},{"id":"phuong-phap-khoi-dong-dong-co-3-pha","metadata":{"permalink":"/shareme/blog/phuong-phap-khoi-dong-dong-co-3-pha","source":"@site/blog/2026/2026-07-20-phuong-phap-khoi-dong-dong-co.mdx","title":"So s\xe1nh 4 ph\u01B0\u01A1ng ph\xe1p kh\u1EDFi \u0111\u1ED9ng \u0111\u1ED9ng c\u01A1 3 pha ph\u1ED5 bi\u1EBFn nh\u1EA5t trong c\xf4ng nghi\u1EC7p","description":"Trong c\xe1c nh\xe0 m\xe1y s\u1EA3n xu\u1EA5t, \u0111\u1ED9ng c\u01A1 kh\xf4ng \u0111\u1ED3ng b\u1ED9 3 pha chi\u1EBFm t\u1EDBi h\u01A1n 80% t\u1ED5ng s\u1ED1 c\xe1c thi\u1EBFt b\u1ECB ti\xeau th\u1EE5 \u0111i\u1EC7n l\u1EF1c. Khi \u0111\u1ED9ng c\u01A1 \u0111\u1EE9ng y\xean v\xe0 b\u1EAFt \u0111\u1EA7u \u0111\u01B0\u1EE3c c\u1EA5p \u0111i\u1EC7n, do rotor ch\u01B0a quay, h\u1EC7 s\u1ED1 tr\u01B0\u1EE3t b\u1EB1ng 1 d\u1EABn \u0111\u1EBFn d\xf2ng \u0111i\u1EC7n kh\u1EDFi \u0111\u1ED9ng v\u1ECDt l\xean r\u1EA5t cao, g\u1EA5p t\u1EEB 5 \u0111\u1EBFn 7 l\u1EA7n d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c.","date":"2026-07-20T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"\u0110i\u1EC1u Khi\u1EC3n \u0110\u1ED9ng C\u01A1","permalink":"/shareme/blog/tags/motor-control"}],"readingTime":5.81,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"phuong-phap-khoi-dong-dong-co-3-pha","title":"So s\xe1nh 4 ph\u01B0\u01A1ng ph\xe1p kh\u1EDFi \u0111\u1ED9ng \u0111\u1ED9ng c\u01A1 3 pha ph\u1ED5 bi\u1EBFn nh\u1EA5t trong c\xf4ng nghi\u1EC7p","authors":["gemini"],"tags":["tu-dong-hoa","motor-control"],"image":"https://images.unsplash.com/photo-1504917595217-d4dc5ebe6122?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"prevItem":{"title":"H\u01B0\u1EDBng D\u1EABn S\u1EED D\u1EE5ng Tool Data Converter","permalink":"/shareme/blog/data-conversion-tool-guide"},"nextItem":{"title":"T\xecm hi\u1EC3u chu\u1EA9n truy\u1EC1n th\xf4ng RS485 v\xe0 gi\u1EA3i ph\xe1p ch\u1ED1ng nhi\u1EC5u th\u1EF1c t\u1EBF","permalink":"/shareme/blog/truyen-thong-rs485-va-giai-phap-chong-nhieu"}},"content":"Trong c\xe1c nh\xe0 m\xe1y s\u1EA3n xu\u1EA5t, \u0111\u1ED9ng c\u01A1 kh\xf4ng \u0111\u1ED3ng b\u1ED9 3 pha chi\u1EBFm t\u1EDBi h\u01A1n 80% t\u1ED5ng s\u1ED1 c\xe1c thi\u1EBFt b\u1ECB ti\xeau th\u1EE5 \u0111i\u1EC7n l\u1EF1c. Khi \u0111\u1ED9ng c\u01A1 \u0111\u1EE9ng y\xean v\xe0 b\u1EAFt \u0111\u1EA7u \u0111\u01B0\u1EE3c c\u1EA5p \u0111i\u1EC7n, do rotor ch\u01B0a quay, h\u1EC7 s\u1ED1 tr\u01B0\u1EE3t b\u1EB1ng 1 d\u1EABn \u0111\u1EBFn d\xf2ng \u0111i\u1EC7n kh\u1EDFi \u0111\u1ED9ng v\u1ECDt l\xean r\u1EA5t cao, g\u1EA5p t\u1EEB **5 \u0111\u1EBFn 7 l\u1EA7n** d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c.\\n\\nD\xf2ng kh\u1EDFi \u0111\u1ED9ng l\u1EDBn n\xe0y g\xe2y s\u1EE5t \xe1p l\u01B0\u1EDBi \u0111i\u1EC7n c\u1EE5c b\u1ED9, l\xe0m \u1EA3nh h\u01B0\u1EDFng \u0111\u1EBFn c\xe1c thi\u1EBFt b\u1ECB \u0111i\u1EC7n t\u1EED nh\u1EA1y c\u1EA3m xung quanh (nh\u01B0 PLC, c\u1EA3m bi\u1EBFn) v\xe0 g\xe2y gi\u1EADt c\u01A1 kh\xed ph\xe1 h\u1ECFng h\u1ED9p s\u1ED1, kh\u1EDBp n\u1ED1i. V\xec v\u1EADy, vi\u1EC7c ch\u1ECDn l\u1EF1a ph\u01B0\u01A1ng ph\xe1p kh\u1EDFi \u0111\u1ED9ng ph\xf9 h\u1EE3p l\xe0 v\xf4 c\xf9ng quan tr\u1ECDng. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD so s\xe1nh chi ti\u1EBFt 4 gi\u1EA3i ph\xe1p kh\u1EDFi \u0111\u1ED9ng ph\u1ED5 bi\u1EBFn nh\u1EA5t hi\u1EC7n nay: Kh\u1EDFi \u0111\u1ED9ng tr\u1EF1c ti\u1EBFp (DOL), Kh\u1EDFi \u0111\u1ED9ng Sao-Tam gi\xe1c (Star-Delta), Kh\u1EDFi \u0111\u1ED9ng m\u1EC1m (Soft Starter) v\xe0 Bi\u1EBFn t\u1EA7n (VFD).\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Kh\u1EDFi \u0111\u1ED9ng tr\u1EF1c ti\u1EBFp (Direct-On-Line - DOL)\\n\\n\u0110\xe2y l\xe0 ph\u01B0\u01A1ng ph\xe1p \u0111\u01A1n gi\u1EA3n nh\u1EA5t, c\u1EA5p th\u1EB3ng \u0111i\u1EC7n \xe1p l\u01B0\u1EDBi \u0111\u1ECBnh m\u1EE9c (v\xed d\u1EE5 380V) v\xe0o cu\u1ED9n d\xe2y stator c\u1EE7a \u0111\u1ED9ng c\u01A1.\\n\\n### \u0110\u1EB7c \u0111i\u1EC3m k\u1EF9 thu\u1EADt\\n*   **D\xf2ng kh\u1EDFi \u0111\u1ED9ng:** \\n\\n```math\\nI_{k\u0111} = (5 \\\\sim 7) \\\\cdot I_{\u0111m}\\n```\\n\\n\\n*   **Moment kh\u1EDFi \u0111\u1ED9ng:** L\u1EDBn nh\u1EA5t trong c\xe1c ph\u01B0\u01A1ng ph\xe1p c\u01A1 b\u1EA3n, gi\xfap \u0111\u1ED9ng c\u01A1 t\u0103ng t\u1ED1c r\u1EA5t nhanh.\\n*   **Thi\u1EBFt b\u1ECB y\xeau c\u1EA7u:** Ch\u1EC9 c\u1EA7n 1 Aptomat (CB), 1 Contactor \u0111\xf3ng c\u1EAFt ngu\u1ED3n v\xe0 1 Relay nhi\u1EC7t b\u1EA3o v\u1EC7 qu\xe1 t\u1EA3i.\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF\\n*   Ch\u1EC9 \xe1p d\u1EE5ng cho c\xe1c \u0111\u1ED9ng c\u01A1 c\xf4ng su\u1EA5t nh\u1ECF (th\u01B0\u1EDDng d\u01B0\u1EDBi **5.5 kW** ho\u1EB7c 7.5 HP) \u0111\u1EC3 tr\xe1nh \u1EA3nh h\u01B0\u1EDFng \u0111\u1EBFn l\u01B0\u1EDBi \u0111i\u1EC7n c\u1EE7a nh\xe0 m\xe1y.\\n*   Tr\xe1nh d\xf9ng cho c\xe1c h\u1EC7 th\u1ED1ng c\xf3 c\xe1nh qu\u1EA1t qu\xe1n t\xednh l\u1EDBn ho\u1EB7c b\u01A1m n\u01B0\u1EDBc d\xe0i v\xec l\u1EF1c gi\u1EADt kh\u1EDFi \u0111\u1ED9ng m\u1EA1nh d\u1EC5 g\xe2y n\u1EE9t v\u1EE1 c\xe1nh qu\u1EA1t ho\u1EB7c hi\u1EC7n t\u01B0\u1EE3ng b\xfaa n\u01B0\u1EDBc (water hammer) l\xe0m v\u1EE1 \u0111\u01B0\u1EDDng \u1ED1ng.\\n\\n---\\n\\n## 2. Kh\u1EDFi \u0111\u1ED9ng Sao - Tam gi\xe1c (Star - Delta Starter)\\n\\nPh\u01B0\u01A1ng ph\xe1p n\xe0y l\xe0m gi\u1EA3m d\xf2ng \u0111i\u1EC7n kh\u1EDFi \u0111\u1ED9ng b\u1EB1ng c\xe1ch gi\u1EA3m \u0111i\u1EC7n \xe1p \u0111\u1EB7t v\xe0o cu\u1ED9n d\xe2y \u0111\u1ED9ng c\u01A1 trong giai \u0111o\u1EA1n \u0111\u1EA7u. \u0110\u1ED9ng c\u01A1 kh\u1EDFi \u0111\u1ED9ng \u1EDF s\u01A1 \u0111\u1ED3 h\xecnh **Sao (Y)**, sau m\u1ED9t kho\u1EA3ng th\u1EDDi gian c\xe0i \u0111\u1EB7t tr\xean r\u01A1-le th\u1EDDi gian (Timer), m\u1EA1ch t\u1EF1 \u0111\u1ED9ng chuy\u1EC3n sang s\u01A1 \u0111\u1ED3 \u0111\u1EA5u **Tam gi\xe1c (Delta - D)** \u0111\u1EC3 ch\u1EA1y \u0111\u1ECBnh m\u1EE9c.\\n\\n### C\xf4ng th\u1EE9c gi\u1EA3m d\xf2ng v\xe0 moment\\n\\nKhi \u0111\u1EA5u h\xecnh Sao, \u0111i\u1EC7n \xe1p \u0111\u1EB7t l\xean m\u1ED7i cu\u1ED9n d\xe2y gi\u1EA3m \u0111i c\u0103n 3 l\u1EA7n so v\u1EDBi \u0111\u1EA5u Tam gi\xe1c. Nh\u1EDD \u0111\xf3, d\xf2ng \u0111i\u1EC7n kh\u1EDFi \u0111\u1ED9ng v\xe0 moment kh\u1EDFi \u0111\u1ED9ng c\u1EE7a \u0111\u1ED9ng c\u01A1 gi\u1EA3m \u0111i **3 l\u1EA7n**:\\n\\n\\n\\n```math\\nI_{k\u0111_Sao} = \\\\frac{1}{3} I_{k\u0111_Tamgi\xe1c}\\n```\\n\\n\\n\\n\\n\\n```math\\nT_{k\u0111_Sao} = \\\\frac{1}{3} T_{k\u0111_Tamgi\xe1c}\\n```\\n\\n\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF\\n*   **\u0110i\u1EC1u ki\u1EC7n b\u1EAFt bu\u1ED9c:** \u0110\u1ED9ng c\u01A1 ph\u1EA3i c\xf3 nh\xe3n ghi th\xf4ng s\u1ED1 cu\u1ED9n d\xe2y l\xe0 **380D/660Y** ho\u1EB7c **380/660V** th\xec m\u1EDBi \u0111\u1EA5u Sao-Tam gi\xe1c tr\xean l\u01B0\u1EDBi 380V \u0111\u01B0\u1EE3c. N\u1EBFu nh\xe3n ghi 220D/380Y, tuy\u1EC7t \u0111\u1ED1i kh\xf4ng \u0111\u01B0\u1EE3c d\xf9ng ph\u01B0\u01A1ng ph\xe1p n\xe0y v\xec khi ch\u1EA1y Tam gi\xe1c \u0111\u1ED9ng c\u01A1 s\u1EBD ch\xe1y do qu\xe1 \xe1p cu\u1ED9n d\xe2y.\\n*   Do moment kh\u1EDFi \u0111\u1ED9ng b\u1ECB gi\u1EA3m \u0111i 3 l\u1EA7n, ph\u01B0\u01A1ng ph\xe1p n\xe0y ch\u1EC9 th\xedch h\u1EE3p cho c\xe1c t\u1EA3i kh\u1EDFi \u0111\u1ED9ng nh\u1EB9 (t\u1EA3i kh\xf4ng t\u1EA3i ho\u1EB7c t\u1EA3i qu\xe1n t\xednh nh\u1ECF) nh\u01B0 m\xe1y n\xe9n kh\xed, qu\u1EA1t gi\xf3, b\u01A1m n\u01B0\u1EDBc ly t\xe2m.\\n\\n---\\n\\n## 3. Kh\u1EDFi \u0111\u1ED9ng m\u1EC1m (Soft Starter)\\n\\nKh\u1EDFi \u0111\u1ED9ng m\u1EC1m s\u1EED d\u1EE5ng c\xe1c linh ki\u1EC7n \u0111i\u1EC7n t\u1EED b\xe1n d\u1EABn c\xf4ng su\u1EA5t g\u1ED3m 3 c\u1EB7p **Thyristor (SCR)** \u0111\u1EA5u song song ng\u01B0\u1EE3c cho 3 pha. B\u1EB1ng c\xe1ch \u0111i\u1EC1u khi\u1EC3n g\xf3c k\xedch m\u1EDF c\u1EE7a Thyristor, kh\u1EDFi \u0111\u1ED9ng m\u1EC1m t\u0103ng d\u1EA7n \u0111i\u1EC7n \xe1p t\u1EEB m\u1ED9t m\u1EE9c ban \u0111\u1EA7u (Start Voltage) l\xean \u0111\u1EBFn \u0111i\u1EC7n \xe1p \u0111\u1ECBnh m\u1EE9c m\u1ED9t c\xe1ch m\u01B0\u1EE3t m\xe0.\\n\\n### \u0110\u1EB7c \u0111i\u1EC3m k\u1EF9 thu\u1EADt\\n*   **D\xf2ng kh\u1EDFi \u0111\u1ED9ng:** C\xf3 th\u1EC3 gi\u1EDBi h\u1EA1n ch\u1EC9nh \u0111\u1ECBnh t\u1EEB **2.5 \u0111\u1EBFn 4.5 l\u1EA7n** d\xf2ng \u0111\u1ECBnh m\u1EE9c th\xf4ng qua c\xe0i \u0111\u1EB7t.\\n*   **Th\u1EDDi gian kh\u1EDFi \u0111\u1ED9ng:** C\u1EA5u h\xecnh th\u1EDDi gian t\u0103ng t\u1ED1c (Ramp time) linh ho\u1EA1t t\u1EEB v\xe0i gi\xe2y \u0111\u1EBFn h\xe0ng ch\u1EE5c gi\xe2y.\\n*   **Bypass Contactor:** H\u1EA7u h\u1EBFt kh\u1EDFi \u0111\u1ED9ng m\u1EC1m hi\u1EC7n \u0111\u1EA1i y\xeau c\u1EA7u ho\u1EB7c t\xedch h\u1EE3p s\u1EB5n contactor bypass \u0111\u1EC3 ng\u1EAFt Thyristor ra khi \u0111\u1ED9ng c\u01A1 \u0111\xe3 \u0111\u1EA1t t\u1ED1c \u0111\u1ED9 \u0111\u1ECBnh m\u1EE9c, gi\xfap t\u1EA3n nhi\u1EC7t v\xe0 ti\u1EBFt ki\u1EC7m \u0111i\u1EC7n n\u0103ng.\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF\\n*   Kh\u1EDFi \u0111\u1ED9ng m\u1EC1m c\u1EF1c k\u1EF3 th\xedch h\u1EE3p cho c\xe1c \u1EE9ng d\u1EE5ng b\u01A1m n\u01B0\u1EDBc c\xf4ng su\u1EA5t l\u1EDBn (t\u1EEB 15 kW tr\u1EDF l\xean) v\xec n\xf3 gi\xfap tri\u1EC7t ti\xeau ho\xe0n to\xe0n hi\u1EC7n t\u01B0\u1EE3ng b\xfaa n\u01B0\u1EDBc khi d\u1EEBng b\u01A1m (ch\u1EE9c n\u0103ng Soft Stop).\\n*   L\u01B0u \xfd kh\u1EDFi \u0111\u1ED9ng m\u1EC1m **kh\xf4ng th\u1EC3 thay \u0111\u1ED5i t\u1ED1c \u0111\u1ED9 quay** c\u1EE7a \u0111\u1ED9ng c\u01A1 trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh th\u01B0\u1EDDng tr\u1EF1c, n\xf3 ch\u1EC9 ho\u1EA1t \u0111\u1ED9ng trong giai \u0111o\u1EA1n kh\u1EDFi \u0111\u1ED9ng v\xe0 d\u1EEBng m\xe1y.\\n\\n---\\n\\n## 4. B\u1ED9 bi\u1EBFn t\u1EA7n (Variable Frequency Drive - VFD)\\n\\nBi\u1EBFn t\u1EA7n l\xe0 gi\u1EA3i ph\xe1p kh\u1EDFi \u0111\u1ED9ng v\xe0 \u0111i\u1EC1u khi\u1EC3n \u0111\u1ED9ng c\u01A1 cao c\u1EA5p nh\u1EA5t. N\xf3 ho\u1EA1t \u0111\u1ED9ng b\u1EB1ng c\xe1ch bi\u1EBFn \u0111\u1ED5i ngu\u1ED3n \u0111i\u1EC7n xoay chi\u1EC1u c\u1ED1 \u0111\u1ECBnh th\xe0nh ngu\u1ED3n \u0111i\u1EC7n c\xf3 \u0111i\u1EC7n \xe1p v\xe0 t\u1EA7n s\u1ED1 thay \u0111\u1ED5i \u0111\u01B0\u1EE3c.\\n\\n### C\xf4ng th\u1EE9c t\u1ED1c \u0111\u1ED9 \u0111\u1ED9ng c\u01A1\\n\\nBi\u1EBFn t\u1EA7n \u0111i\u1EC1u khi\u1EC3n t\u1ED1c \u0111\u1ED9 quay c\u1EE7a \u0111\u1ED9ng c\u01A1 d\u1EF1a tr\xean c\xf4ng th\u1EE9c t\u1EA7n s\u1ED1:\\n\\n\\n\\n```math\\nn = \\\\frac{60 \\\\cdot f}{p} \\\\cdot (1 - s)\\n```\\n\\n\\n\\n*(Trong \u0111\xf3 f l\xe0 t\u1EA7n s\u1ED1, p l\xe0 s\u1ED1 c\u1EB7p c\u1EF1c, s l\xe0 h\u1EC7 s\u1ED1 tr\u01B0\u1EE3t).*\\n\\n### \u01AFu \u0111i\u1EC3m v\u01B0\u1EE3t tr\u1ED9i\\n*   **D\xf2ng kh\u1EDFi \u0111\u1ED9ng:** C\u1EF1c k\u1EF3 th\u1EA5p, ch\u1EC9 t\u1EEB **1.0 \u0111\u1EBFn 1.5 l\u1EA7n** d\xf2ng \u0111\u1ECBnh m\u1EE9c. \u0110\xe2y l\xe0 ph\u01B0\u01A1ng ph\xe1p duy nh\u1EA5t kh\xf4ng g\xe2y s\u1EE5t \xe1p l\u01B0\u1EDBi \u0111i\u1EC7n khi kh\u1EDFi \u0111\u1ED9ng t\u1EA3i n\u1EB7ng.\\n*   **Kh\u1EA3 n\u0103ng \u0111i\u1EC1u khi\u1EC3n:** Cho ph\xe9p thay \u0111\u1ED5i t\u1ED1c \u0111\u1ED9 \u0111\u1ED9ng c\u01A1 li\xean t\u1EE5c, \u0111\u1EA3o chi\u1EC1u quay m\u01B0\u1EE3t m\xe0, \u0111i\u1EC1u khi\u1EC3n l\u1EF1c torque ch\xednh x\xe1c.\\n*   **Ti\u1EBFt ki\u1EC7m \u0111i\u1EC7n n\u0103ng:** Gi\xfap ti\u1EBFt ki\u1EC7m t\u1EEB 20-50% \u0111i\u1EC7n n\u0103ng ti\xeau th\u1EE5 \u0111\u1ED1i v\u1EDBi c\xe1c t\u1EA3i b\u01A1m, qu\u1EA1t ho\u1EA1t \u0111\u1ED9ng \u1EDF l\u01B0u l\u01B0\u1EE3ng bi\u1EBFn \u0111\u1ED5i.\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF\\n*   Bi\u1EBFn t\u1EA7n sinh ra nhi\u1EC1u s\xf3ng h\xe0i (Harmonics) g\xe2y nhi\u1EC5u c\xe1c thi\u1EBFt b\u1ECB truy\u1EC1n th\xf4ng RS-485 xung quanh. Khi thi c\xf4ng t\u1EE7 \u0111i\u1EC7n d\xf9ng bi\u1EBFn t\u1EA7n, b\u1EAFt bu\u1ED9c d\xf9ng c\xe1p \u0111\u1ED9ng l\u1EF1c ch\u1ED1ng nhi\u1EC5u chuy\xean d\u1EE5ng c\xf3 b\u1ECDc kim, n\u1ED1i ti\u1EBFp \u0111\u1ECBa v\u1ECF motor th\u1EADt k\u1EF9 v\xe0 l\u1EAFp b\u1ED9 l\u1ECDc s\xf3ng h\xe0i (choke) n\u1EBFu c\xe1p ngu\u1ED3n motor d\xe0i tr\xean 50 m\xe9t.\\n\\n---\\n\\n## 5. B\u1EA3ng t\u1ED5ng h\u1EE3p so s\xe1nh c\xe1c ph\u01B0\u01A1ng ph\xe1p\\n\\n| Ti\xeau ch\xed | Kh\u1EDFi \u0111\u1ED9ng tr\u1EF1c ti\u1EBFp (DOL) | Sao - Tam gi\xe1c | Kh\u1EDFi \u0111\u1ED9ng m\u1EC1m | Bi\u1EBFn t\u1EA7n (VFD) |\\n| :--- | :--- | :--- | :--- | :--- |\\n| **D\xf2ng kh\u1EDFi \u0111\u1ED9ng** | R\u1EA5t cao (5-7 Idm) | Trung b\xecnh (2-3.5 Idm) | Th\u1EA5p (2.5-4 Idm) | R\u1EA5t th\u1EA5p (1-1.5 Idm) |\\n| **Moment kh\u1EDFi \u0111\u1ED9ng** | R\u1EA5t l\u1EDBn | B\u1ECB gi\u1EA3m 3 l\u1EA7n | Ch\u1EC9nh \u0111\u1ECBnh \u0111\u01B0\u1EE3c | R\u1EA5t l\u1EDBn, t\u1ED1i \u01B0u torque |\\n| **\u1EA2nh h\u01B0\u1EDFng c\u01A1 kh\xed** | G\xe2y gi\u1EADt m\u1EA1nh | Gi\u1EADt nh\u1EB9 khi chuy\u1EC3n Y-D | M\u01B0\u1EE3t m\xe0 | C\u1EF1c k\u1EF3 m\u01B0\u1EE3t m\xe0 |\\n| **\u0110i\u1EC1u ch\u1EC9nh t\u1ED1c \u0111\u1ED9** | Kh\xf4ng | Kh\xf4ng | Kh\xf4ng | \u0110i\u1EC1u ch\u1EC9nh v\xf4 c\u1EA5p |\\n| **Gi\xe1 th\xe0nh \u0111\u1EA7u t\u01B0** | R\u1EA5t r\u1EBB | R\u1EBB | Trung b\xecnh | Cao |\\n| **\u1EE8ng d\u1EE5ng t\u1ED1i \u01B0u** | Motor c\xf4ng su\u1EA5t < 5.5 kW | Motor qu\u1EA1t ly t\xe2m, b\u01A1m nh\u1EB9 | B\u01A1m n\u01B0\u1EDBc l\u1EDBn, b\u0103ng t\u1EA3i | C\xe1c m\xe1y y\xeau c\u1EA7u thay \u0111\u1ED5i t\u1ED1c \u0111\u1ED9 |"},{"id":"truyen-thong-rs485-va-giai-phap-chong-nhieu","metadata":{"permalink":"/shareme/blog/truyen-thong-rs485-va-giai-phap-chong-nhieu","source":"@site/blog/2026/2026-07-19-truyen-thong-rs485-chong-nhieu.mdx","title":"T\xecm hi\u1EC3u chu\u1EA9n truy\u1EC1n th\xf4ng RS485 v\xe0 gi\u1EA3i ph\xe1p ch\u1ED1ng nhi\u1EC5u th\u1EF1c t\u1EBF","description":"Trong th\u1EBF gi\u1EDBi truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p, b\xean c\u1EA1nh Ethernet hi\u1EC7n \u0111\u1EA1i, chu\u1EA9n truy\u1EC1n th\xf4ng v\u1EADt l\xfd RS-485 v\u1EABn lu\xf4n gi\u1EEF v\u1ECB tr\xed \\"v\u01B0\u01A1ng gi\u1EA3\\" nh\u1EDD chi ph\xed r\u1EBB, d\u1EC5 tri\u1EC3n khai v\xe0 kh\u1EA3 n\u0103ng k\xe9o d\xe2y \u0111i xa l\xean \u0111\u1EBFn 1200 m\xe9t. H\u1EA7u h\u1EBFt c\xe1c thi\u1EBFt b\u1ECB nh\u01B0 bi\u1EBFn t\u1EA7n, \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t \u0111\u1ED9, c\u1EA3m bi\u1EBFn c\xf4ng nghi\u1EC7p hi\u1EC7n nay \u0111\u1EC1u t\xedch h\u1EE3p c\u1ED5ng RS-485 ch\u1EA1y giao th\u1EE9c Modbus RTU.","date":"2026-07-19T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"M\u1EA1ng Truy\u1EC1n Th\xf4ng","permalink":"/shareme/blog/tags/networking"}],"readingTime":5.81,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"truyen-thong-rs485-va-giai-phap-chong-nhieu","title":"T\xecm hi\u1EC3u chu\u1EA9n truy\u1EC1n th\xf4ng RS485 v\xe0 gi\u1EA3i ph\xe1p ch\u1ED1ng nhi\u1EC5u th\u1EF1c t\u1EBF","authors":["gemini"],"tags":["tu-dong-hoa","networking"],"image":"https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"prevItem":{"title":"So s\xe1nh 4 ph\u01B0\u01A1ng ph\xe1p kh\u1EDFi \u0111\u1ED9ng \u0111\u1ED9ng c\u01A1 3 pha ph\u1ED5 bi\u1EBFn nh\u1EA5t trong c\xf4ng nghi\u1EC7p","permalink":"/shareme/blog/phuong-phap-khoi-dong-dong-co-3-pha"},"nextItem":{"title":"Top 5 c\xf4ng th\u1EE9c t\xednh to\xe1n c\u1ED1t l\xf5i","permalink":"/shareme/blog/top-5-cong-thuc-dien-tu-dong-hoa"}},"content":"Trong th\u1EBF gi\u1EDBi truy\u1EC1n th\xf4ng c\xf4ng nghi\u1EC7p, b\xean c\u1EA1nh Ethernet hi\u1EC7n \u0111\u1EA1i, chu\u1EA9n truy\u1EC1n th\xf4ng v\u1EADt l\xfd **RS-485** v\u1EABn lu\xf4n gi\u1EEF v\u1ECB tr\xed \\"v\u01B0\u01A1ng gi\u1EA3\\" nh\u1EDD chi ph\xed r\u1EBB, d\u1EC5 tri\u1EC3n khai v\xe0 kh\u1EA3 n\u0103ng k\xe9o d\xe2y \u0111i xa l\xean \u0111\u1EBFn 1200 m\xe9t. H\u1EA7u h\u1EBFt c\xe1c thi\u1EBFt b\u1ECB nh\u01B0 bi\u1EBFn t\u1EA7n, \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t \u0111\u1ED9, c\u1EA3m bi\u1EBFn c\xf4ng nghi\u1EC7p hi\u1EC7n nay \u0111\u1EC1u t\xedch h\u1EE3p c\u1ED5ng RS-485 ch\u1EA1y giao th\u1EE9c Modbus RTU.\\n\\nTuy nhi\xean, RS-485 c\u0169ng l\xe0 n\u1ED7i \xe1m \u1EA3nh l\u1EDBn nh\u1EA5t c\u1EE7a c\xe1c k\u1EF9 s\u01B0 \u0111i c\xf4ng tr\u01B0\u1EDDng khi x\u1EA3y ra t\xecnh tr\u1EA1ng nhi\u1EC5u t\xedn hi\u1EC7u: l\xfac ch\u1EA1y \u0111\u01B0\u1EE3c l\xfac kh\xf4ng, thi\u1EBFt b\u1ECB th\u1EC9nh tho\u1EA3ng m\u1EA5t k\u1EBFt n\u1ED1i, ho\u1EB7c truy\u1EC1n d\u1EEF li\u1EC7u b\u1ECB sai l\u1EC7ch. B\xe0i vi\u1EBFt n\xe0y m\xecnh s\u1EBD m\u1ED5 x\u1EBB chi ti\u1EBFt nguy\xean l\xfd v\u1EADt l\xfd c\u1EE7a RS-485 v\xe0 c\xe1c gi\u1EA3i ph\xe1p ch\u1ED1ng nhi\u1EC5u th\u1EF1c t\u1EBF gi\xfap n\xed t\u1EF1 tin x\u1EED l\xfd l\u1ED7i t\u1EA1i c\xf4ng tr\xecnh.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Nguy\xean l\xfd ho\u1EA1t \u0111\u1ED9ng c\u1EE7a RS-485: T\u1EA1i sao l\u1EA1i l\xe0 truy\u1EC1n vi sai?\\n\\n\u0110i\u1EC3m m\u1EA5u ch\u1ED1t gi\xfap RS-485 truy\u1EC1n xa v\xe0 ch\u1ED1ng nhi\u1EC5u t\u1ED1t h\u01A1n RS-232 c\u0169 ch\xednh l\xe0 c\u01A1 ch\u1EBF **truy\u1EC1n d\u1EABn vi sai (Differential Signaling)**.\\n\\nThay v\xec d\xf9ng 1 d\xe2y t\xedn hi\u1EC7u v\xe0 1 d\xe2y \u0111\u1EA5t chung (Single-ended) nh\u01B0 RS-232, RS-485 s\u1EED d\u1EE5ng hai d\xe2y k\xfd hi\u1EC7u l\xe0 **A** (hay Rx/Tx-) v\xe0 **B** (hay Rx/Tx+). \\n\\n### C\xf4ng th\u1EE9c \u0111i\u1EC7n \xe1p \u0111\u1EA7u nh\u1EADn\\n\\nTr\u1EA1ng th\xe1i logic (0 ho\u1EB7c 1) \u0111\u01B0\u1EE3c quy\u1EBFt \u0111\u1ECBnh b\u1EDFi \u0111\u1ED9 l\u1EC7ch \u0111i\u1EC7n \xe1p gi\u1EEFa hai d\xe2y ch\u1EE9 kh\xf4ng ph\u1EE5 thu\u1ED9c v\xe0o \u0111i\u1EC7n \xe1p \u0111\u1ED1i \u0111\u1EA5t:\\n\\n\\n\\n```math\\nV_{diff} = V_B - V_A\\n```\\n\\n\\n\\nQuy \u01B0\u1EDBc tr\u1EA1ng th\xe1i logic \u0111\u1EA7u nh\u1EADn:\\n*   N\u1EBFu $V_{diff} \\\\ge +200{ mV}$: Tr\u1EA1ng th\xe1i logic l\xe0 **1** (Mark/Idle).\\n*   N\u1EBFu $V_{diff} \\\\le -200{ mV}$: Tr\u1EA1ng th\xe1i logic l\xe0 **0** (Space).\\n\\n### C\u01A1 ch\u1EBF t\u1EF1 tri\u1EC7t ti\xeau nhi\u1EC5u\\nKhi m\u1ED9t ngu\u1ED3n nhi\u1EC5u \u0111i\u1EC7n t\u1EEB (v\xed d\u1EE5 t\u1EEB c\xe1p \u0111\u1ED9ng l\u1EF1c bi\u1EBFn t\u1EA7n ch\u1EA1y song song) t\xe1c \u0111\u1ED9ng l\xean \u0111\u01B0\u1EDDng d\xe2y RS-485, do hai d\xe2y A v\xe0 B \u0111\u01B0\u1EE3c xo\u1EAFn ch\u1EB7t v\u1EDBi nhau, nhi\u1EC5u s\u1EBD t\xe1c \u0111\u1ED9ng l\xean c\u1EA3 hai d\xe2y m\u1ED9t l\u01B0\u1EE3ng \u0111i\u1EC7n \xe1p nhi\u1EC5u gi\u1ED1ng nhau $V_{noise}$:\\n\\n\\n\\n```math\\nV_{diff_nhi\u1EC1u} = (V_B + V_{noise}) - (V_A + V_{noise}) = V_B - V_A = V_{diff}\\n```\\n\\n\\n\\nNh\u1EDD ph\xe9p tr\u1EEB vi sai t\u1EA1i \u0111\u1EA7u nh\u1EADn, \u0111i\u1EC7n \xe1p nhi\u1EC5u $V_{noise}$ ho\xe0n to\xe0n b\u1ECB tri\u1EC7t ti\xeau! \u0110\xe2y ch\xednh l\xe0 l\xfd do v\xec sao \u0111\u01B0\u1EDDng truy\u1EC1n vi sai ho\u1EA1t \u0111\u1ED9ng c\u1EF1c k\u1EF3 \u1ED5n \u0111\u1ECBnh trong m\xf4i tr\u01B0\u1EDDng nhi\u1EC1u nhi\u1EC5u \u0111i\u1EC7n t\u1EEB c\u1EE7a nh\xe0 m\xe1y.\\n\\n---\\n\\n## 2. 4 nguy\xean t\u1EAFc v\xe0ng \u0111\u1EC3 ch\u1ED1ng nhi\u1EC5u RS-485 th\u1EF1c t\u1EBF \u1EDF c\xf4ng tr\u01B0\u1EDDng\\n\\nL\xfd thuy\u1EBFt l\xe0 v\u1EADy, nh\u01B0ng n\u1EBFu n\xed \u0111\u1EA5u n\u1ED1i sai k\u1EF9 thu\u1EADt th\xec \u0111\u01B0\u1EDDng truy\u1EC1n v\u1EABn s\u1EBD ch\u1EADp ch\u1EDDn. D\u01B0\u1EDBi \u0111\xe2y l\xe0 4 nguy\xean t\u1EAFc b\u1EA5t di b\u1EA5t d\u1ECBch m\xe0 b\u1EA5t k\u1EF3 k\u1EF9 s\u01B0 thi c\xf4ng n\xe0o c\u0169ng ph\u1EA3i thu\u1ED9c l\xf2ng:\\n\\n### 2.1. B\u1EAFt bu\u1ED9c \u0111i d\xe2y theo s\u01A1 \u0111\u1ED3 Daisy Chain (N\u1ED1i ti\u1EBFp)\\n*   **Sai l\u1EA7m ph\u1ED5 bi\u1EBFn:** R\u1EA5t nhi\u1EC1u b\u1EA1n \u0111\u1EA5u n\u1ED1i RS-485 theo s\u01A1 \u0111\u1ED3 h\xecnh sao (Star topology) ho\u1EB7c r\u1EBD nh\xe1nh t\xf9y ti\u1EC7n nh\u01B0 \u0111\u1EA5u \u0111i\u1EC7n sinh ho\u1EA1t. \u0110i\u1EC1u n\xe0y t\u1EA1o ra c\xe1c \u0111i\u1EC3m ph\u1EA3n x\u1EA1 t\xedn hi\u1EC7u (impedance mismatch), g\xe2y m\xe9o d\u1EA1ng s\xf3ng v\xe0 tri\u1EC7t ti\xeau t\xedn hi\u1EC7u.\\n*   **\u0110\u1EA5u \u0111\xfang:** Ph\u1EA3i k\xe9o m\u1ED9t \u0111\u01B0\u1EDDng c\xe1p tr\u1EE5c ch\xednh t\u1EEB Master l\u1EA7n l\u01B0\u1EE3t \u0111i qua c\xe1c Slave theo s\u01A1 \u0111\u1ED3 **Daisy Chain** (\u0111\u1EA7u thi\u1EBFt b\u1ECB n\xe0y n\u1ED1i ti\u1EBFp sang thi\u1EBFt b\u1ECB kia). \u0110\u01B0\u1EDDng nh\xe1nh r\u1EBD t\u1EEB tr\u1EE5c ch\xednh v\xe0o thi\u1EBFt b\u1ECB (stub length) ph\u1EA3i c\xe0ng ng\u1EAFn c\xe0ng t\u1ED1t (d\u01B0\u1EDBi 30 cm).\\n\\n### 2.2. L\u1EAFp \u0111i\u1EC7n tr\u1EDF \u0111\u1EA7u cu\u1ED1i 120 Ohm (Terminating Resistor)\\n*   T\xedn hi\u1EC7u \u0111i\u1EC7n truy\u1EC1n trong d\xe2y c\xe1p ho\u1EA1t \u0111\u1ED9ng gi\u1ED1ng nh\u01B0 s\xf3ng n\u01B0\u1EDBc. Khi truy\u1EC1n \u0111\u1EBFn cu\u1ED1i \u0111\u01B0\u1EDDng d\xe2y, n\u1EBFu g\u1EB7p s\u1EF1 thay \u0111\u1ED5i \u0111\u1ED9t ng\u1ED9t v\u1EC1 tr\u1EDF kh\xe1ng (cu\u1ED1i d\xe2y b\u1ECB h\u1EDF m\u1EA1ch), s\xf3ng t\xedn hi\u1EC7u s\u1EBD ph\u1EA3n x\u1EA1 ng\u01B0\u1EE3c l\u1EA1i v\xe0 \u0111\xe8 l\xean s\xf3ng t\xedn hi\u1EC7u \u0111ang truy\u1EC1n t\u1EDBi, g\xe2y l\u1ED7i d\u1EEF li\u1EC7u.\\n*   **Gi\u1EA3i ph\xe1p:** M\u1EAFc m\u1ED9t \u0111i\u1EC7n tr\u1EDF **120 Ohm** song song gi\u1EEFa hai d\xe2y A v\xe0 B \u1EDF **hai \u0111i\u1EC3m \u0111\u1EA7u v\xe0 cu\u1ED1i c\xf9ng** c\u1EE7a \u0111\u01B0\u1EDDng c\xe1p truy\u1EC1n d\u1EABn. \u0110i\u1EC7n tr\u1EDF n\xe0y gi\xfap h\u1EA5p th\u1EE5 s\xf3ng ph\u1EA3n x\u1EA1, \u1ED5n \u0111\u1ECBnh \u0111\u01B0\u1EDDng truy\u1EC1n.\\n\\n### 2.3. S\u1EED d\u1EE5ng c\xe1p xo\u1EAFn k\xe9p c\xf3 b\u1ECDc kim ch\u1ED1ng nhi\u1EC5u (Shielded Twisted Pair)\\n*   Lu\xf4n ch\u1ECDn lo\u1EA1i c\xe1p chuy\xean d\u1EE5ng cho RS-485 (v\xed d\u1EE5 c\xe1p Belden 9841 ho\u1EB7c c\xe1p Alantek). C\xe1p ph\u1EA3i c\xf3 c\xe1c l\xf5i xo\u1EAFn k\xe9p v\u1EDBi nhau v\xe0 c\xf3 l\u1EDBp l\xe1 nh\xf4m/l\u01B0\u1EDBi \u0111\u1ED3ng b\u1ECDc xung quanh (Shield).\\n*   **Nguy\xean t\u1EAFc n\u1ED1i \u0111\u1EA5t ch\u1ED1ng nhi\u1EC5u c\xe1p (Shield Grounding):** L\u1EDBp b\u1ECDc kim (Shield) c\u1EE7a c\xe1p ch\u1ED1ng nhi\u1EC5u **ch\u1EC9 \u0111\u01B0\u1EE3c n\u1ED1i \u0111\u1EA5t duy nh\u1EA5t t\u1EA1i 1 \u0111i\u1EC3m** (th\u01B0\u1EDDng l\xe0 t\u1EA1i t\u1EE7 \u0111i\u1EC7n trung t\xe2m ho\u1EB7c ph\xeda Master). Tuy\u1EC7t \u0111\u1ED1i kh\xf4ng n\u1ED1i \u0111\u1EA5t c\u1EA3 hai \u0111\u1EA7u c\u1EE7a l\u1EDBp b\u1ECDc kim v\xec s\u1EBD t\u1EA1o ra v\xf2ng l\u1EB7p ti\u1EBFp \u0111\u1ECBa (Ground Loop), sinh ra d\xf2ng \u0111i\u1EC7n ch\u1EA1y tr\xean v\u1ECF c\xe1p l\xe0m \u0111\u01B0\u1EDDng truy\u1EC1n nhi\u1EC5u n\u1EB7ng h\u01A1n.\\n\\n### 2.4. Tr\xe1nh \u0111i chung m\xe1ng c\xe1p \u0111\u1ED9ng l\u1EF1c\\n*   Tuy\u1EC7t \u0111\u1ED1i kh\xf4ng \u0111i chung d\xe2y c\xe1p t\xedn hi\u1EC7u RS-485 song song s\xe1t b\xean c\u1EA1nh c\xe1p \u0111\u1ED9ng l\u1EF1c c\u1EA5p ngu\u1ED3n cho \u0111\u1ED9ng c\u01A1, bi\u1EBFn t\u1EA7n.\\n*   N\u1EBFu b\u1EAFt bu\u1ED9c ph\u1EA3i \u0111i chung m\xe1ng c\xe1p, h\xe3y gi\u1EEF kho\u1EA3ng c\xe1ch t\u1ED1i thi\u1EC3u **20 cm** gi\u1EEFa c\xe1p t\xedn hi\u1EC7u v\xe0 c\xe1p \u0111\u1ED9ng l\u1EF1c, ho\u1EB7c s\u1EED d\u1EE5ng m\xe1ng c\xe1p c\xf3 v\xe1ch ng\u0103n b\u1EB1ng kim lo\u1EA1i \u0111\u01B0\u1EE3c n\u1ED1i \u0111\u1EA5t t\u1ED1t.\\n\\n---\\n\\n## 3. V\xed d\u1EE5 x\u1EED l\xfd l\u1ED7i th\u1EF1c t\u1EBF t\u1EA1i nh\xe0 m\xe1y\\n\\nM\u1ED9t l\u1EA7n m\xecnh \u0111i x\u1EED l\xfd s\u1EF1 c\u1ED1 cho h\u1EC7 th\u1ED1ng \u0111\u1ECDc d\u1EEF li\u1EC7u 10 \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t \u0111\u1ED9 c\u1EE7a h\xe3ng Autonics v\u1EC1 PLC Siemens qua Modbus RTU. M\u1EA1ng d\xe2y k\xe9o d\xe0i kho\u1EA3ng 300 m\xe9t. Bi\u1EC3u hi\u1EC7n l\u1ED7i: th\u1EC9nh tho\u1EA3ng PLC b\xe1o l\u1ED7i Timeout \u1EDF c\xe1c \u0111\u1ED3ng h\u1ED3 n\u1EB1m \u1EDF cu\u1ED1i \u0111\u01B0\u1EDDng d\xe2y, ho\u1EB7c d\u1EEF li\u1EC7u nhi\u1EC7t \u0111\u1ED9 \u0111\u1ECDc v\u1EC1 nh\u1EA3y s\u1ED1 lung tung.\\n\\n**C\xe1c b\u01B0\u1EDBc m\xecnh \u0111\xe3 ki\u1EC3m tra v\xe0 kh\u1EAFc ph\u1EE5c:**\\n1.  **Ki\u1EC3m tra s\u01A1 \u0111\u1ED3 \u0111\u1EA5u d\xe2y:** Ph\xe1t hi\u1EC7n th\u1EE3 \u0111i\u1EC7n \u0111\u1EA5u d\xe2y theo m\xf4 h\xecnh h\xecnh sao t\u1EA1i t\u1EE7 trung gian. M\xecnh \u0111\xe3 y\xeau c\u1EA7u \u0111\u1EA5u n\u1ED1i l\u1EA1i theo \u0111\xfang s\u01A1 \u0111\u1ED3 **Daisy Chain** n\u1ED1i ti\u1EBFp.\\n2.  **\u0110o tr\u1EDF kh\xe1ng cu\u1ED1i \u0111\u01B0\u1EDDng d\xe2y:** Khi ng\u1EAFt ngu\u1ED3n, \u0111o \u0111i\u1EC7n tr\u1EDF gi\u1EEFa d\xe2y A v\xe0 B \u1EDF cu\u1ED1i \u0111\u01B0\u1EDDng d\xe2y th\u1EA5y tr\u1EDF kh\xe1ng v\xf4 c\xf9ng (do ch\u01B0a l\u1EAFp \u0111i\u1EC7n tr\u1EDF \u0111\u1EA7u cu\u1ED1i). M\xecnh \u0111\xe3 l\u1EAFp th\xeam \u0111i\u1EC7n tr\u1EDF **120 Ohm, 1/4W** t\u1EA1i c\u1ED5ng PLC Master v\xe0 t\u1EA1i \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t \u0111\u1ED9 s\u1ED1 10.\\n3.  **X\u1EED l\xfd ti\u1EBFp \u0111\u1ECBa v\u1ECF c\xe1p:** L\u1EDBp Shield c\u1EE7a c\xe1p \u0111\u01B0\u1EE3c \u0111\u1EA5u v\xe0o v\u1ECF kim lo\u1EA1i c\u1EE7a c\u1EA3 10 \u0111\u1ED3ng h\u1ED3 nhi\u1EC7t. M\xecnh \u0111\xe3 ng\u1EAFt h\u1EBFt ti\u1EBFp \u0111\u1ECBa v\u1ECF c\xe1p \u1EDF c\xe1c \u0111\u1ED3ng h\u1ED3, ch\u1EC9 gi\u1EEF l\u1EA1i ti\u1EBFp \u0111\u1ECBa duy nh\u1EA5t t\u1EA1i \u0111\u1EA7u t\u1EE7 PLC Master.\\n\\nSau khi th\u1EF1c hi\u1EC7n 3 b\u01B0\u1EDBc tr\xean, h\u1EC7 th\u1ED1ng ho\u1EA1t \u0111\u1ED9ng c\u1EF1c k\u1EF3 \u1ED5n \u0111\u1ECBnh, chu k\u1EF3 \u0111\u1ECDc Modbus gi\u1EA3m t\u1EEB 500ms xu\u1ED1ng c\xf2n 50ms m\xe0 kh\xf4ng h\u1EC1 x\u1EA3y ra b\u1EA5t k\u1EF3 l\u1ED7i m\u1EA5t g\xf3i tin (packet loss) n\xe0o. Hy v\u1ECDng kinh nghi\u1EC7m n\xe0y gi\xfap \xedch cho c\xe1c n\xed khi l\xe0m th\u1EF1c t\u1EBF!"},{"id":"top-5-cong-thuc-dien-tu-dong-hoa","metadata":{"permalink":"/shareme/blog/top-5-cong-thuc-dien-tu-dong-hoa","source":"@site/blog/2026/2026-07-18-top-5-cong-thu-dien.mdx","title":"Top 5 c\xf4ng th\u1EE9c t\xednh to\xe1n c\u1ED1t l\xf5i","description":"M\u01B0\u1EDDi n\u0103m l\u0103n l\u1ED9n v\u1EDBi t\u1EE7 b\u1EA3ng \u0111i\u1EC7n, t\u1EEB c\xe1c nh\xe0 m\xe1y xi m\u0103ng, d\u1EC7t may cho t\u1EDBi c\xe1c tr\u1EA1m b\u01A1m, m\xecnh nh\u1EADn ra m\u1ED9t \u0111i\u1EC1u: d\xf9 c\xf4ng ngh\u1EC7 c\xf3 thay \u0111\u1ED5i, PLC c\xf3 th\xf4ng minh th\u1EBF n\xe0o, th\xec n\u1EC1n t\u1EA3ng c\u01A1 \u0111i\u1EC7n v\u1EABn l\xe0 c\xe1i g\u1ED1c. R\u1EA5t nhi\u1EC1u k\u1EF9 s\u01B0 tr\u1EBB thi\u1EBFt k\u1EBF code PLC r\u1EA5t gi\u1ECFi nh\u01B0ng khi t\xednh to\xe1n ch\u1ECDn c\xe1p, ch\u1ECDn kh\u1EDFi \u0111\u1ED9ng t\u1EEB (contactor) hay c\xe0i d\xf2ng cho relay nhi\u1EC7t th\xec l\u1EA1i ch\u1ECDn sai, d\u1EABn \u0111\u1EBFn t\u1EE7 \u0111i\u1EC7n b\u1ECB ch\xe1y s\xe9m ho\u1EB7c \u0111\u1ED9ng c\u01A1 c\u1EE7a kh\xe1ch h\xe0ng b\u1ECB om d\xe2y.","date":"2026-07-18T00:00:00.000Z","tags":[{"inline":false,"label":"T\u1EF1 \u0110\u1ED9ng H\xf3a","permalink":"/shareme/blog/tags/tu-dong-hoa"},{"inline":false,"label":"\u0110i\u1EC7n C\xf4ng Nghi\u1EC7p","permalink":"/shareme/blog/tags/dien-cong-nghiep"}],"readingTime":12.89,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"}],"frontMatter":{"slug":"top-5-cong-thuc-dien-tu-dong-hoa","title":"Top 5 c\xf4ng th\u1EE9c t\xednh to\xe1n c\u1ED1t l\xf5i","authors":["gemini"],"tags":["tu-dong-hoa","dien-cong-nghiep"],"image":"https://images.unsplash.com/photo-1635070041078-e363dbe005cb?auto=format&fit=crop&w=800&q=80"},"unlisted":false,"prevItem":{"title":"T\xecm hi\u1EC3u chu\u1EA9n truy\u1EC1n th\xf4ng RS485 v\xe0 gi\u1EA3i ph\xe1p ch\u1ED1ng nhi\u1EC5u th\u1EF1c t\u1EBF","permalink":"/shareme/blog/truyen-thong-rs485-va-giai-phap-chong-nhieu"},"nextItem":{"title":"H\u01B0\u1EDBng d\u1EABn vi\u1EBFt b\xe0i Docusaurus Blog","permalink":"/shareme/blog/huong-dan-viet-blog-docusaurus"}},"content":"M\u01B0\u1EDDi n\u0103m l\u0103n l\u1ED9n v\u1EDBi t\u1EE7 b\u1EA3ng \u0111i\u1EC7n, t\u1EEB c\xe1c nh\xe0 m\xe1y xi m\u0103ng, d\u1EC7t may cho t\u1EDBi c\xe1c tr\u1EA1m b\u01A1m, m\xecnh nh\u1EADn ra m\u1ED9t \u0111i\u1EC1u: d\xf9 c\xf4ng ngh\u1EC7 c\xf3 thay \u0111\u1ED5i, PLC c\xf3 th\xf4ng minh th\u1EBF n\xe0o, th\xec n\u1EC1n t\u1EA3ng c\u01A1 \u0111i\u1EC7n v\u1EABn l\xe0 c\xe1i g\u1ED1c. R\u1EA5t nhi\u1EC1u k\u1EF9 s\u01B0 tr\u1EBB thi\u1EBFt k\u1EBF code PLC r\u1EA5t gi\u1ECFi nh\u01B0ng khi t\xednh to\xe1n ch\u1ECDn c\xe1p, ch\u1ECDn kh\u1EDFi \u0111\u1ED9ng t\u1EEB (contactor) hay c\xe0i d\xf2ng cho relay nhi\u1EC7t th\xec l\u1EA1i ch\u1ECDn sai, d\u1EABn \u0111\u1EBFn t\u1EE7 \u0111i\u1EC7n b\u1ECB ch\xe1y s\xe9m ho\u1EB7c \u0111\u1ED9ng c\u01A1 c\u1EE7a kh\xe1ch h\xe0ng b\u1ECB om d\xe2y. \\n\\n\u0110\u1EC3 gi\xfap c\xe1c n\xed (\u0111\u1EB7c bi\u1EC7t l\xe0 sinh vi\xean n\u0103m cu\u1ED1i v\xe0 k\u1EF9 s\u01B0 m\u1EDBi ra tr\u01B0\u1EDDng) t\u1EF1 tin thi\u1EBFt k\u1EBF v\xe0 thi c\xf4ng t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p m\xe0 kh\xf4ng s\u1EE3 b\u1ECB \\"\u0111\u1EC1n ti\u1EC1n\\", m\xecnh xin chia s\u1EBB **top 5 c\xf4ng th\u1EE9c t\xednh to\xe1n c\u1ED1t l\xf5i** c\xf9ng v\u1EDBi nh\u1EEFng kinh nghi\u1EC7m th\u1EF1c chi\u1EBFn t\xedch l\u0169y su\u1ED1t 10 n\u0103m qua.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. C\xf4ng th\u1EE9c t\xednh d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c cho \u0111\u1ED9ng c\u01A1 3 pha\\n\\n\u0110\xe2y l\xe0 c\xf4ng th\u1EE9c n\u1EC1n t\u1EA3ng nh\u1EA5t. M\u1ECDi thi\u1EBFt k\u1EBF t\u1EEB vi\u1EC7c ch\u1ECDn ti\u1EBFt di\u1EC7n d\xe2y d\u1EABn, Aptomat, Contactor \u0111\u1EBFn c\xe0i \u0111\u1EB7t Relay nhi\u1EC7t \u0111\u1EC1u b\u1EAFt \u0111\u1EA7u t\u1EEB vi\u1EC7c x\xe1c \u0111\u1ECBnh ch\xednh x\xe1c d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c c\u1EE7a \u0111\u1ED9ng c\u01A1.\\n\\n### C\xf4ng th\u1EE9c t\u1ED5ng qu\xe1t\\n\\n\\n\\n```math\\nI = \\\\frac{P}{\\\\sqrt{3} \\\\cdot U \\\\cdot \\\\cos\\\\varphi \\\\cdot \\\\eta}\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $I$: **D\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c** c\u1EE7a \u0111\u1ED9ng c\u01A1 (\u0111\u01A1n v\u1ECB: Ampe - A).\\n*   $P$: **C\xf4ng su\u1EA5t \u0111\u1ECBnh m\u1EE9c** ghi tr\xean nh\xe3n \u0111\u1ED9ng c\u01A1 (\u0111\u01A1n v\u1ECB: Watt - W). L\u01B0u \xfd n\u1EBFu nh\xe3n ghi m\xe3 l\u1EF1c (HP ho\u1EB7c h.p), n\xed ph\u1EA3i \u0111\u1ED5i sang Watt: 1 HP \u2248 746 W = 0.746 kW.\\n*   $U$: **\u0110i\u1EC7n \xe1p d\xe2y** \u0111\u1ECBnh m\u1EE9c c\u1EA5p v\xe0o \u0111\u1ED9ng c\u01A1 (\u0111\u01A1n v\u1ECB: V\xf4n - V). \u1EDE Vi\u1EC7t Nam, m\u1EA1ng h\u1EA1 th\u1EBF c\xf4ng nghi\u1EC7p th\u01B0\u1EDDng l\xe0 m\u1EA1ng 3 pha 380V.\\n*   $\\\\cos\\\\varphi$: **H\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t** (Power Factor) c\u1EE7a \u0111\u1ED9ng c\u01A1, th\u01B0\u1EDDng dao \u0111\u1ED9ng trong kho\u1EA3ng t\u1EEB 0.8 \u0111\u1EBFn 0.89 t\xf9y c\xf4ng su\u1EA5t v\xe0 h\xe3ng s\u1EA3n xu\u1EA5t.\\n*   $\\\\eta$ (Eta): **Hi\u1EC7u su\u1EA5t** c\u1EE7a \u0111\u1ED9ng c\u01A1, bi\u1EC3u th\u1ECB ph\u1EA7n c\xf4ng su\u1EA5t \u0111i\u1EC7n chuy\u1EC3n \u0111\u1ED5i th\xe0nh c\xf4ng su\u1EA5t c\u01A1 h\u1ECDc tr\xean tr\u1EE5c c\u01A1 c\u1EA5u, th\u01B0\u1EDDng t\u1EEB 0.85 \u0111\u1EBFn 0.95.\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF t\u1EEB c\xf4ng tr\xecnh\\n*   **M\u1EB9o t\xednh nhanh t\u1EA1i hi\u1EC7n tr\u01B0\u1EDDng:** \u0110\u1ED1i v\u1EDBi l\u01B0\u1EDBi \u0111i\u1EC7n 3 pha 380V ti\xeau chu\u1EA9n, n\u1EBFu nh\xe3n \u0111\u1ED9ng c\u01A1 b\u1ECB m\u1EDD $\\\\cos\\\\varphi$ v\xe0 hi\u1EC7u su\u1EA5t, n\xed c\xf3 th\u1EC3 l\u1EA5y **c\xf4ng su\u1EA5t \u0111\u1ECBnh m\u1EE9c (kW) nh\xe2n v\u1EDBi 2** \u0111\u1EC3 ra d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c (A) x\u1EA5p x\u1EC9. V\xed d\u1EE5: \u0111\u1ED9ng c\u01A1 11 kW s\u1EBD c\xf3 d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c kho\u1EA3ng 22 A. M\u1EB9o n\xe0y ch\xednh x\xe1c t\u1EDBi 90% \u0111\u1ED1i v\u1EDBi c\xe1c \u0111\u1ED9ng c\u01A1 th\xf4ng d\u1EE5ng t\u1EEB 4 kW \u0111\u1EBFn 110 kW.\\n*   N\u1EBFu \u0111\u1ED9ng c\u01A1 ho\u1EA1t \u0111\u1ED9ng trong m\xf4i tr\u01B0\u1EDDng nhi\u1EC7t \u0111\u1ED9 cao (tr\xean 40\xb0C) ho\u1EB7c ch\u1EA1y qu\xe1 t\u1EA3i nh\u1EB9 li\xean t\u1EE5c, d\xf2ng \u0111i\u1EC7n th\u1EF1c t\u1EBF c\xf3 th\u1EC3 t\u0103ng l\xean. H\xe3y lu\xf4n tr\u1EEB hao kho\u1EA3ng 10% khi ch\u1ECDn thi\u1EBFt b\u1ECB \u0111\xf3ng c\u1EAFt b\u1EA3o v\u1EC7.\\n\\n### V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\nGi\u1EA3 s\u1EED n\xed c\u1EA7n t\xednh d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c cho m\u1ED9t \u0111\u1ED9ng c\u01A1 b\u01A1m n\u01B0\u1EDBc 3 pha c\xf3 th\xf4ng s\u1ED1 tr\xean nameplate nh\u01B0 sau:\\n*   C\xf4ng su\u1EA5t: P = 15 kW = 15000 W\\n*   \u0110i\u1EC7n \xe1p: U = 380 V\\n*   H\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t: $\\\\cos\\\\varphi = 0.85$\\n*   Hi\u1EC7u su\u1EA5t: $\\\\eta = 0.90$\\n\\n\xc1p d\u1EE5ng c\xf4ng th\u1EE9c:\\n\\n\\n```math\\nI = \\\\frac{15000}{\\\\sqrt{3} \\\\cdot 380 \\\\cdot 0.85 \\\\cdot 0.90} \\\\approx 29.8 \\\\text{ A}\\n```\\n\\n\\n\\nV\u1EADy d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c c\u1EE7a \u0111\u1ED9ng c\u01A1 n\xe0y l\xe0 **29.8 A**.\\n\\n---\\n\\n## 2. C\xf4ng th\u1EE9c t\xednh v\xe0 ch\u1ECDn ti\u1EBFt di\u1EC7n d\xe2y d\u1EABn \u0111i\u1EC7n (Cable Sizing)\\n\\nSau khi c\xf3 \u0111\u01B0\u1EE3c d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c, vi\u1EC7c ti\u1EBFp theo l\xe0 t\xednh to\xe1n ti\u1EBFt di\u1EC7n d\xe2y d\u1EABn. Ch\u1ECDn d\xe2y qu\xe1 nh\u1ECF s\u1EBD l\xe0m d\xe2y n\xf3ng l\xean, ch\u1EA3y l\u1EDBp v\u1ECF c\xe1ch \u0111i\u1EC7n g\xe2y ch\u1EADp ch\xe1y t\u1EE7. Ch\u1ECDn d\xe2y qu\xe1 l\u1EDBn s\u1EBD l\xe0m t\u0103ng gi\xe1 th\xe0nh t\u1EE7 \u0111i\u1EC7n v\xe0 r\u1EA5t kh\xf3 \u0111\u1EA5u n\u1ED1i v\xe0o c\u1EA7u \u0111\u1EA5u (Terminal).\\n\\n### C\xf4ng th\u1EE9c t\xednh ti\u1EBFt di\u1EC7n\\n\\n\\n\\n```math\\nS = \\\\frac{I_{tk}}{J}\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $S$: **Ti\u1EBFt di\u1EC7n danh \u0111\u1ECBnh** c\u1EE7a ru\u1ED9t d\u1EABn (\u0111\u01A1n v\u1ECB: milim\xe9t vu\xf4ng - mm\xb2).\\n*   $I_{tk}$: **D\xf2ng \u0111i\u1EC7n t\xednh to\xe1n** l\u1EDBn nh\u1EA5t ch\u1EA1y qua d\xe2y d\u1EABn (\u0111\u01A1n v\u1ECB: Ampe - A). V\u1EDBi \u0111\u1ED9ng c\u01A1, d\xf2ng \u0111i\u1EC7n t\xednh to\xe1n l\u1EA5y b\u1EB1ng d\xf2ng \u0111\u1ECBnh m\u1EE9c I nh\xe2n th\xeam h\u1EC7 s\u1ED1 an to\xe0n.\\n*   $J$: **M\u1EADt \u0111\u1ED9 d\xf2ng \u0111i\u1EC7n cho ph\xe9p** (\u0111\u01A1n v\u1ECB: A/mm\xb2). \u0110\u1EA1i l\u01B0\u1EE3ng n\xe0y ph\u1EE5 thu\u1ED9c v\xe0o v\u1EADt li\u1EC7u l\xe0m l\xf5i d\xe2y (\u0111\u1ED3ng ho\u1EB7c nh\xf4m), lo\u1EA1i c\xe1ch \u0111i\u1EC7n (PVC ho\u1EB7c XLPE), ph\u01B0\u01A1ng ph\xe1p \u0111i d\xe2y (\u0111i trong m\xe1ng c\xe1p, \u0111i ng\u1EA7m d\u01B0\u1EDBi \u0111\u1EA5t hay \u0111i tr\xean kh\xf4ng).\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF t\u1EEB c\xf4ng tr\xecnh\\n*   Trong thi\u1EBFt k\u1EBF t\u1EE7 \u0111i\u1EC7n c\xf4ng nghi\u1EC7p ti\xeau chu\u1EA9n, ch\xfang ta ch\u1EE7 y\u1EBFu d\xf9ng **d\xe2y c\xe1p \u0111\u1ED3ng (Cu) c\xe1ch \u0111i\u1EC7n PVC ho\u1EB7c XLPE**.\\n*   \u0110\u1ED1i v\u1EDBi d\xe2y \u0111i b\xean trong t\u1EE7 \u0111i\u1EC7n (\u0111i\u1EC1u ki\u1EC7n t\u1EA3n nhi\u1EC7t k\xe9m v\xec d\xe2y b\xf3 s\xe1t nhau trong m\xe1ng nh\u1EF1a), kinh nghi\u1EC7m x\u01B0\u01A1ng m\xe1u l\xe0 ch\u1ECDn m\u1EADt \u0111\u1ED9 $J = 4 \\\\sim 5 \\\\text{ A/mm}^2$ \u0111\u1EC3 \u0111\u1EA3m b\u1EA3o an to\xe0n v\u1EADn h\xe0nh li\xean t\u1EE5c 24/7.\\n*   N\u1EBFu d\xe2y d\u1EABn ch\u1EA1y ngo\xe0i tr\u1EDDi, \u0111i ri\xeang l\u1EBB tr\xean khay c\xe1p tho\xe1ng kh\xed, n\xed c\xf3 th\u1EC3 l\u1EA5y $J = 6 \\\\text{ A/mm}^2$.\\n*   **L\u01B0u \xfd s\u1EE5t \xe1p:** \u0110\u1ED1i v\u1EDBi nh\u1EEFng t\u1EA3i \u1EDF r\u1EA5t xa t\u1EE7 \u0111i\u1EC7n (kho\u1EA3ng c\xe1ch tr\xean 50 m\xe9t), b\u1EAFt bu\u1ED9c ph\u1EA3i t\xednh to\xe1n th\xeam \u0111\u1ED9 s\u1EE5t \xe1p \u0111\u01B0\u1EDDng d\xe2y. Quy \u0111\u1ECBnh ti\xeau chu\u1EA9n \u0111\u1ED9 s\u1EE5t \xe1p kh\xf4ng qu\xe1 3% \u0111\u1ED1i v\u1EDBi t\u1EA3i \u0111\u1ED9ng c\u01A1. N\u1EBFu s\u1EE5t \xe1p qu\xe1 l\u1EDBn, \u0111\u1ED9ng c\u01A1 s\u1EBD b\u1ECB y\u1EBFu v\xe0 sinh nhi\u1EC7t d\u1EEF d\u1ED9i khi kh\u1EDFi \u0111\u1ED9ng. L\xfac n\xe0y ph\u1EA3i t\u0103ng ti\u1EBFt di\u1EC7n d\xe2y l\xean 1 \u0111\u1EBFn 2 c\u1EA5p so v\u1EDBi t\xednh to\xe1n l\xfd thuy\u1EBFt.\\n\\n### V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\nCh\u1ECDn ti\u1EBFt di\u1EC7n c\xe1p \u0111\u1ED3ng c\u1EA5p ngu\u1ED3n cho \u0111\u1ED9ng c\u01A1 3 pha \u1EDF V\xed d\u1EE5 1 c\xf3 d\xf2ng \u0111\u1ECBnh m\u1EE9c I = 29.8 A. \u0110\u1ED9ng c\u01A1 c\xe1ch t\u1EE7 \u0111i\u1EC7n kho\u1EA3ng 15 m\xe9t, \u0111i d\xe2y trong m\xe1ng c\xe1p k\xedn.\\n\\nCh\u1ECDn d\xf2ng \u0111i\u1EC7n t\xednh to\xe1n an to\xe0n b\u1EB1ng 1.25 l\u1EA7n d\xf2ng \u0111\u1ECBnh m\u1EE9c:\\n\\n\\n```math\\nI_{tk} = 29.8 \\\\times 1.25 = 37.25 \\\\text{ A}\\n```\\n\\n\\n\\nCh\u1ECDn m\u1EADt \u0111\u1ED9 d\xf2ng \u0111i\u1EC7n an to\xe0n \u0111i trong m\xe1ng k\xedn cho d\xe2y \u0111\u1ED3ng l\xe0 J = 5 A/mm\xb2:\\n\\n\\n```math\\nS = \\\\frac{37.25}{5} = 7.45 \\\\text{ mm}^2\\n```\\n\\n\\n\\nTheo ti\xeau chu\u1EA9n s\u1EA3n xu\u1EA5t c\xe1p \u0111i\u1EC7n t\u1EA1i Vi\u1EC7t Nam (nh\u01B0 Cadivi, Lioa...), c\xe1c ti\u1EBFt di\u1EC7n d\xe2y \u0111\u1ED3ng chu\u1EA9n l\xe0: 1.5, 2.5, 4, 6, 10, 16 mm\xb2...\\nSo s\xe1nh v\u1EDBi k\u1EBFt qu\u1EA3 t\xednh to\xe1n 7.45 mm\xb2, ta ch\u1ECDn ti\u1EBFt di\u1EC7n c\xe1p \u0111\u1ED3ng ti\xeau chu\u1EA9n g\u1EA7n nh\u1EA5t v\xe0 l\u1EDBn h\u01A1n l\xe0 **10 mm\xb2** (s\u1EED d\u1EE5ng lo\u1EA1i c\xe1p 3 pha 4 l\xf5i Copper/PVC/PVC 4x10 mm\xb2 ho\u1EB7c c\xe1p \u0111\u01A1n CV 10 mm\xb2 \u0111i trong m\xe1ng).\\n\\n---\\n\\n## 3. C\xf4ng th\u1EE9c t\xednh ch\u1ECDn Aptomat (CB) v\xe0 Contactor (Kh\u1EDFi \u0111\u1ED9ng t\u1EEB)\\n\\nAptomat (CB) d\xf9ng \u0111\u1EC3 b\u1EA3o v\u1EC7 ng\u1EAFn m\u1EA1ch v\xe0 qu\xe1 t\u1EA3i l\u1EDBn cho to\xe0n b\u1ED9 nh\xe1nh \u0111\u1ED9ng c\u01A1. Contactor (kh\u1EDFi \u0111\u1ED9ng t\u1EEB) d\xf9ng \u0111\u1EC3 \u0111\xf3ng c\u1EAFt ngu\u1ED3n \u0111\u1ED9ng l\u1EF1c \u0111i\u1EC1u khi\u1EC3n \u0111\u1ED9ng c\u01A1 ho\u1EA1t \u0111\u1ED9ng d\u01B0\u1EDBi l\u1EC7nh c\u1EE7a PLC ho\u1EB7c n\xfat nh\u1EA5n.\\n\\n### C\xf4ng th\u1EE9c ch\u1ECDn thi\u1EBFt b\u1ECB\\n\\n\\n\\n```math\\nI_{CB} \\\\ge (1.25 \\\\sim 1.5) \\\\cdot I_{\u0111m}\\n```\\n\\n\\n\\n\\n\\n```math\\nI_{Contactor} \\\\ge (1.15 \\\\sim 1.25) \\\\cdot I_{\u0111m}\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $I_{CB}$: **D\xf2ng \u0111\u1ECBnh m\u1EE9c** c\u1EE7a Aptomat b\u1EA3o v\u1EC7 (\u0111\u01A1n v\u1ECB: Ampe - A).\\n*   $I_{Contactor}$: **D\xf2ng \u0111\u1ECBnh m\u1EE9c** c\u1EE7a ti\u1EBFp \u0111i\u1EC3m \u0111\u1ED9ng l\u1EF1c Contactor (\u0111\u01A1n v\u1ECB: Ampe - A).\\n*   $I_{\u0111m}$: **D\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c** c\u1EE7a \u0111\u1ED9ng c\u01A1 (\u0111\u01A1n v\u1ECB: Ampe - A).\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF t\u1EEB c\xf4ng tr\xecnh\\n*   **Ch\u1ECDn \u0111\u1EB7c tuy\u1EBFn d\xf2ng c\u1EAFt (Trip Curve) c\u1EE7a CB:** Khi kh\u1EDFi \u0111\u1ED9ng tr\u1EF1c ti\u1EBFp (DOL), d\xf2ng \u0111i\u1EC7n kh\u1EDFi \u0111\u1ED9ng c\u1EE7a \u0111\u1ED9ng c\u01A1 t\u0103ng v\u1ECDt g\u1EA5p 5 \u0111\u1EBFn 7 l\u1EA7n d\xf2ng \u0111\u1ECBnh m\u1EE9c. Do \u0111\xf3, tuy\u1EC7t \u0111\u1ED1i kh\xf4ng d\xf9ng lo\u1EA1i CB chuy\xean d\u1EE5ng cho d\xe2n d\u1EE5ng (Curve B). \u0110\u1ED1i v\u1EDBi t\u1EA3i \u0111\u1ED9ng c\u01A1 t\u1EF1 \u0111\u1ED9ng h\xf3a, b\u1EAFt bu\u1ED9c ch\u1ECDn CB c\xf3 \u0111\u1EB7c t\xednh d\xf2ng c\u1EAFt lo\u1EA1i **Curve C** ho\u1EB7c **Curve D** (ch\u1ECBu \u0111\u01B0\u1EE3c d\xf2ng kh\u1EDFi \u0111\u1ED9ng m\xe0 kh\xf4ng nh\u1EA3y CB).\\n*   **H\u1EC7 s\u1ED1 d\xf2ng c\u1EAFt ng\u1EAFn m\u1EA1ch (Icu):** T\u1EE7 \u0111i\u1EC7n \u0111\u1EB7t g\u1EA7n tr\u1EA1m bi\u1EBFn \xe1p ngu\u1ED3n c\u1EA7n ch\u1ECDn CB c\xf3 d\xf2ng c\u1EAFt ng\u1EAFn m\u1EA1ch l\u1EDBn (v\xed d\u1EE5 15kA, 25kA ho\u1EB7c 36kA). N\u1EBFu \u0111\u1EB7t xa tr\u1EA1m c\xf3 th\u1EC3 ch\u1ECDn d\xf2ng c\u1EAFt th\u1EA5p h\u01A1n (6kA, 10kA) \u0111\u1EC3 ti\u1EBFt ki\u1EC7m chi ph\xed.\\n*   **Ch\u1ECDn Contactor theo lo\u1EA1i t\u1EA3i (Category):** B\u1EAFt bu\u1ED9c ch\u1ECDn Contactor \u0111\xe1p \u1EE9ng ti\xeau chu\u1EA9n **AC-3** (d\xe0nh cho \u0111\u1ED9ng c\u01A1 kh\xf4ng \u0111\u1ED3ng b\u1ED9 r\xf4-to l\u1ED3ng s\xf3c, ng\u1EAFt d\xf2ng khi \u0111\u1ED9ng c\u01A1 \u0111ang ch\u1EA1y). N\u1EBFu h\u1EC7 th\u1ED1ng y\xeau c\u1EA7u \u0111\u1EA3o chi\u1EC1u quay li\xean t\u1EE5c ho\u1EB7c ch\u1EA1y nh\u1EA5p nh\u1EA3 (Jogging) li\xean t\u1EE5c nh\u01B0 c\u1EA9u tr\u1EE5c, n\xed ph\u1EA3i ch\u1ECDn Contactor ti\xeau chu\u1EA9n **AC-4** c\xf3 d\xf2ng \u0111\u1ECBnh m\u1EE9c l\u1EDBn h\u01A1n nhi\u1EC1u.\\n\\n### V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\nT\xednh ch\u1ECDn CB v\xe0 Contactor b\u1EA3o v\u1EC7 \u0111i\u1EC1u khi\u1EC3n cho \u0111\u1ED9ng c\u01A1 c\xf3 d\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c $I_{\u0111m} = 29.8 \\\\text{ A}$, ch\u1EBF \u0111\u1ED9 l\xe0m vi\u1EC7c th\xf4ng th\u01B0\u1EDDng **AC-3**.\\n\\n1.  **T\xednh ch\u1ECDn Aptomat (CB):**\\n    \\n\\n```math\\nI_{CB} \\\\ge 1.25 \\\\cdot 29.8 = 37.25 \\\\text{ A}\\n```\\n\\n\\n    C\xe1c d\xf2ng \u0111\u1ECBnh m\u1EE9c ti\xeau chu\u1EA9n c\u1EE7a CB tr\xean th\u1ECB tr\u01B0\u1EDDng th\u01B0\u1EDDng l\xe0: 6, 10, 16, 20, 25, 32, 40, 50, 63, 80 A...\\n    Ta ch\u1ECDn Aptomat MCCB ho\u1EB7c MCB 3 pha lo\u1EA1i **40 A**, d\xf2ng c\u1EAFt ng\u1EAFn m\u1EA1ch khuy\u1EBFn ngh\u1ECB t\u1ED1i thi\u1EC3u l\xe0 **10 kA**, \u0111\u1EB7c t\xednh d\xf2ng c\u1EAFt **Curve C**.\\n2.  **T\xednh ch\u1ECDn Contactor:**\\n    \\n\\n```math\\nI_{Contactor} \\\\ge 1.2 \\\\cdot 29.8 = 35.76 \\\\text{ A}\\n```\\n\\n\\n    C\xe1c d\xf2ng \u0111\u1ECBnh m\u1EE9c Contactor ti\xeau chu\u1EA9n c\u1EE7a c\xe1c h\xe3ng (Schneider, LS, Mitsubishi...) l\xe0: 9, 12, 18, 22, 32, 40, 50 A...\\n    Ta ch\u1ECDn Contactor ti\xeau chu\u1EA9n **40 A** (v\xed d\u1EE5 m\xe3 d\xf2ng LCc1D40 c\u1EE7a Schneider) ho\u1EB7c contactor **38 A** \u0111\u1EC3 ho\u1EA1t \u0111\u1ED9ng an to\xe0n v\xe0 b\u1EC1n b\u1EC9.\\n\\n---\\n\\n## 4. C\xf4ng th\u1EE9c ch\u1EC9nh \u0111\u1ECBnh d\xf2ng b\u1EA3o v\u1EC7 cho Relay nhi\u1EC7t (Overload Relay)\\n\\nRelay nhi\u1EC7t l\xe0 thi\u1EBFt b\u1ECB b\u1EA3o v\u1EC7 \u0111\u1ED9ng c\u01A1 ch\u1ED1ng l\u1EA1i hi\u1EC7n t\u01B0\u1EE3ng qu\xe1 t\u1EA3i l\xe2u d\xe0i (d\u1EABn \u0111\u1EBFn ch\xe1y cu\u1ED9n d\xe2y). Tuy nhi\xean, n\u1EBFu c\xe0i \u0111\u1EB7t d\xf2ng b\u1EA3o v\u1EC7 qu\xe1 cao th\xec \u0111\u1ED9ng c\u01A1 s\u1EBD ch\xe1y tr\u01B0\u1EDBc khi relay k\u1ECBp t\xe1c \u0111\u1ED9ng. Ng\u01B0\u1EE3c l\u1EA1i, n\u1EBFu c\xe0i qu\xe1 th\u1EA5p th\xec relay s\u1EBD nh\u1EA3y li\xean t\u1EE5c l\xe0m gi\xe1n \u0111o\u1EA1n d\xe2y chuy\u1EC1n s\u1EA3n xu\u1EA5t.\\n\\n### C\xf4ng th\u1EE9c c\xe0i \u0111\u1EB7t d\xf2ng ch\u1EC9nh \u0111\u1ECBnh\\n\\n\\n\\n```math\\nI_{c\xe0i} = (1.0 \\\\sim 1.05) \\\\cdot I_{\u0111m}\\n```\\n\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $I_{c\xe0i}$: **D\xf2ng \u0111i\u1EC7n ch\u1EC9nh \u0111\u1ECBnh** (n\xfam xoay c\u1EA5u h\xecnh tr\xean m\u1EB7t tr\u01B0\u1EDBc c\u1EE7a relay nhi\u1EC7t) (\u0111\u01A1n v\u1ECB: Ampe - A).\\n*   $I_{\u0111m}$: **D\xf2ng \u0111i\u1EC7n \u0111\u1ECBnh m\u1EE9c** th\u1EF1c t\u1EBF ghi tr\xean nh\xe3n \u0111\u1ED9ng c\u01A1 (\u0111\u01A1n v\u1ECB: Ampe - A).\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF t\u1EEB c\xf4ng tr\xecnh\\n*   **Sai l\u1EA7m ph\u1ED5 bi\u1EBFn:** R\u1EA5t nhi\u1EC1u th\u1EE3 \u0111i\u1EC7n v\u1EADn h\xe0nh c\xf3 th\xf3i quen khi th\u1EA5y relay nhi\u1EC7t nh\u1EA3y b\u1EA3o v\u1EC7 qu\xe1 t\u1EA3i li\u1EC1n v\u1EB7n n\xfam xoay l\xean k\u1ECBch kim (t\u0103ng d\xf2ng ch\u1EC9nh \u0111\u1ECBnh l\xean g\u1EA5p 1.2 ho\u1EB7c 1.3 l\u1EA7n d\xf2ng \u0111\u1ECBnh m\u1EE9c) \u0111\u1EC3 \\"ch\u1EEFa ch\xe1y\\" t\u1EA1m th\u1EDDi. \u0110\xe2y l\xe0 h\xe0nh \u0111\u1ED9ng h\u1EE7y ho\u1EA1i thi\u1EBFt b\u1ECB. \u0110\u1ED9ng c\u01A1 ch\u1EA1y qu\xe1 t\u1EA3i l\xe2u d\xe0i s\u1EBD t\xedch t\u1EE5 nhi\u1EC7t l\xe0m h\u1ECFng l\u1EDBp s\u01A1n c\xe1ch \u0111i\u1EC7n c\u1EE7a cu\u1ED9n d\xe2y, g\xe2y ch\u1EA1m ch\u1EADp v\xe0 ch\xe1y n\u1ED5 \u0111\u1ED9ng c\u01A1.\\n*   N\u1EBFu \u0111\u1ED9ng c\u01A1 k\xe9o t\u1EA3i n\u1EB7ng v\xe0 th\u1EDDi gian kh\u1EDFi \u0111\u1ED9ng k\xe9o d\xe0i (v\xed d\u1EE5 qu\u1EA1t ly t\xe2m c\xf4ng nghi\u1EC7p c\xe1nh l\u1EDBn, m\xe1y nghi\u1EC1n \u0111\xe1), relay nhi\u1EC7t c\xf3 th\u1EC3 nh\u1EA3y khi \u0111ang kh\u1EDFi \u0111\u1ED9ng. \u0110\u1EC3 kh\u1EAFc ph\u1EE5c, n\xed ph\u1EA3i ch\u1ECDn b\u1ED9 kh\u1EDFi \u0111\u1ED9ng m\u1EC1m/bi\u1EBFn t\u1EA7n ho\u1EB7c l\u1EAFp relay nhi\u1EC7t lo\u1EA1i **Class 20** ho\u1EB7c **Class 30** (ch\u1ECBu th\u1EDDi gian kh\u1EDFi \u0111\u1ED9ng l\xe2u h\u01A1n) thay v\xec c\u1ED1 t\xecnh v\u1EB7n t\u0103ng d\xf2ng ch\u1EC9nh \u0111\u1ECBnh c\u1EE7a relay nhi\u1EC7t Class 10 th\xf4ng th\u01B0\u1EDDng.\\n\\n### V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\nCh\u1EC9nh \u0111\u1ECBnh d\xf2ng b\u1EA3o v\u1EC7 cho \u0111\u1ED9ng c\u01A1 \u1EDF V\xed d\u1EE5 1 c\xf3 d\xf2ng \u0111\u1ECBnh m\u1EE9c l\xe0 $I_{\u0111m} = 29.8 \\\\text{ A}$.\\n\xc1p d\u1EE5ng c\xf4ng th\u1EE9c ch\u1EC9nh \u0111\u1ECBnh:\\n\\n\\n```math\\nI_{c\xe0i} = 1.0 \\\\cdot 29.8 = 29.8 \\\\text{ A}\\n```\\n\\n\\nTh\u1EF1c t\u1EBF ta s\u1EBD ch\u1ECDn m\u1ED9t Relay nhi\u1EC7t c\xf3 d\u1EA3i ch\u1EC9nh b\u1EA3o ph\u1EE7 gi\xe1 tr\u1ECB n\xe0y (th\u01B0\u1EDDng l\xe0 d\u1EA3i 23 ~ 32 A ho\u1EB7c 28 ~ 40 A t\xf9y h\xe3ng s\u1EA3n xu\u1EA5t). Khi l\u1EAFp r\xe1p v\xe0o t\u1EE7, ta d\xf9ng tu\u1ED1c-n\u01A1-v\xedt xoay n\xfam ch\u1EC9nh tr\xean m\u1EB7t relay nhi\u1EC7t ch\u1EC9 ch\xednh x\xe1c v\xe0o v\u1EA1ch s\u1ED1 **30 A**.\\n\\n---\\n\\n## 5. C\xf4ng th\u1EE9c t\xednh b\xf9 c\xf4ng su\u1EA5t ph\u1EA3n kh\xe1ng (B\xf9 h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t Cos phi)\\n\\nT\u1EA1i c\xe1c nh\xe0 m\xe1y, x\xed nghi\u1EC7p s\u1EED d\u1EE5ng l\u01B0\u1EE3ng l\u1EDBn \u0111\u1ED9ng c\u01A1 \u0111i\u1EC7n (t\u1EA3i c\u1EA3m), h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t t\u1ED5ng c\u1EE7a m\u1EA1ng \u0111i\u1EC7n s\u1EBD b\u1ECB k\xe9o xu\u1ED1ng r\u1EA5t th\u1EA5p. \u0110i\u1EC7n l\u1EF1c quy \u0111\u1ECBnh n\u1EBFu h\u1EC7 s\u1ED1 cos phi nh\u1ECF h\u01A1n 0.9, nh\xe0 m\xe1y s\u1EBD b\u1ECB ph\u1EA1t ti\u1EC1n \u0111i\u1EC7n n\u0103ng ph\u1EA3n kh\xe1ng r\u1EA5t n\u1EB7ng h\xe0ng th\xe1ng. Do \u0111\xf3, k\u1EF9 s\u01B0 t\u1EF1 \u0111\u1ED9ng h\xf3a c\u1EA7n bi\u1EBFt c\xe1ch t\xednh to\xe1n dung l\u01B0\u1EE3ng t\u1EE5 b\xf9 \u0111\u1EC3 thi\u1EBFt k\u1EBF t\u1EE7 b\xf9 t\u1EF1 \u0111\u1ED9ng.\\n\\n### C\xf4ng th\u1EE9c t\xednh dung l\u01B0\u1EE3ng t\u1EE5 b\xf9\\n\\n\\n```math\\nQ_b = P \\\\cdot (\\\\tan\\\\varphi_1 - \\\\tan\\\\varphi_2)\\n```\\n\\n\\n### K\xfd hi\u1EC7u & \xdd ngh\u0129a c\xe1c \u0111\u1EA1i l\u01B0\u1EE3ng\\n*   $Q_b$: **Dung l\u01B0\u1EE3ng c\xf4ng su\u1EA5t ph\u1EA3n kh\xe1ng** c\u1EA7n b\xf9 (\u0111\u01A1n v\u1ECB: kilovolt-ampe ph\u1EA3n kh\xe1ng - kVAR).\\n*   $P$: **C\xf4ng su\u1EA5t t\xe1c d\u1EE5ng** c\u1EE7a to\xe0n h\u1EC7 th\u1ED1ng t\u1EA3i c\u1EA7n b\xf9 (\u0111\u01A1n v\u1ECB: kilowatt - kW).\\n*   $\\\\tan\\\\varphi_1$: H\u1EC7 s\u1ED1 ph\u1EA3n kh\xe1ng tr\u01B0\u1EDBc khi b\xf9, x\xe1c \u0111\u1ECBnh t\u1EEB h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t ban \u0111\u1EA7u $\\\\cos\\\\varphi_1$.\\n*   $\\\\tan\\\\varphi_2$: H\u1EC7 s\u1ED1 ph\u1EA3n kh\xe1ng sau khi b\xf9, x\xe1c \u0111\u1ECBnh t\u1EEB h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t m\u1EE5c ti\xeau $\\\\cos\\\\varphi_2$.\\n\\nC\xf4ng th\u1EE9c chuy\u1EC3n \u0111\u1ED5i t\u1EEB h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t $\\\\cos\\\\varphi$ sang h\u1EC7 s\u1ED1 ph\u1EA3n kh\xe1ng $\\\\tan\\\\varphi$:\\n\\n\\n```math\\n\\\\tan\\\\varphi = \\\\frac{\\\\sqrt{1 - \\\\cos^2\\\\varphi}}{\\\\cos\\\\varphi}\\n```\\n\\n\\n### L\u1EDDi khuy\xean th\u1EF1c t\u1EBF t\u1EEB c\xf4ng tr\xecnh\\n*   **M\u1EE5c ti\xeau b\xf9:** Th\xf4ng th\u01B0\u1EDDng, ch\xfang ta t\xednh to\xe1n b\xf9 h\u1EC7 s\u1ED1 cos phi t\u1EEB gi\xe1 tr\u1ECB ban \u0111\u1EA7u l\xean m\u1EE9c **0.95**. Kh\xf4ng n\xean thi\u1EBFt k\u1EBF b\xf9 k\u1ECBch kim l\xean 0.99 ho\u1EB7c 1.0 v\xec r\u1EA5t d\u1EC5 x\u1EA3y ra hi\u1EC7n t\u01B0\u1EE3ng **b\xf9 d\u01B0 (overcompensation)** khi t\u1EA3i gi\u1EA3m. B\xf9 d\u01B0 s\u1EBD sinh ra hi\u1EC7n t\u01B0\u1EE3ng t\u0103ng \xe1p l\u01B0\u1EDBi \u0111i\u1EC7n, g\xe2y h\u1ECFng h\xf3c c\xe1c thi\u1EBFt b\u1ECB nh\u1EA1y c\u1EA3m trong h\u1EC7 th\u1ED1ng \u0111i\u1EC1u khi\u1EC3n PLC/HMI v\xe0 l\xe0m n\xf3ng m\xe1y bi\u1EBFn \xe1p.\\n*   **Chia c\u1EA5p t\u1EE5 h\u1EE3p l\xfd:** Thay v\xec d\xf9ng m\u1ED9t t\u1EE5 b\xf9 l\u1EDBn duy nh\u1EA5t, h\xe3y chia nh\u1ECF dung l\u01B0\u1EE3ng c\u1EA7n b\xf9 th\xe0nh nhi\u1EC1u b\u01B0\u1EDBc t\u1EE5 nh\u1ECF (v\xed d\u1EE5 10 kVAR, 15 kVAR, 20 kVAR) k\u1EBFt h\u1EE3p v\u1EDBi b\u1ED9 \u0111i\u1EC1u khi\u1EC3n t\u1EE5 b\xf9 t\u1EF1 \u0111\u1ED9ng (APFC). \u0110i\u1EC1u n\xe0y gi\xfap h\u1EC7 th\u1ED1ng b\xf9 b\xe1m s\xe1t c\xf4ng su\u1EA5t th\u1EF1c t\u1EBF c\u1EE7a nh\xe0 x\u01B0\u1EDFng, h\u1EA1n ch\u1EBF t\u1ED1i \u0111a s\u1ED1 l\u1EA7n \u0111\xf3ng c\u1EAFt c\u1EE7a contactor v\xe0 b\u1EA3o v\u1EC7 tu\u1ED5i th\u1ECD t\u1EE5.\\n\\n### V\xed d\u1EE5 t\xednh to\xe1n c\u1EE5 th\u1EC3\\nM\u1ED9t nh\xe0 x\u01B0\u1EDFng c\u01A1 kh\xed c\xf3 t\u1ED5ng c\xf4ng su\u1EA5t ti\xeau th\u1EE5 t\xe1c d\u1EE5ng l\xe0 P = 120 kW. H\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t trung b\xecnh \u0111o \u0111\u01B0\u1EE3c l\xe0 $\\\\cos\\\\varphi_1 = 0.72$. T\xednh dung l\u01B0\u1EE3ng t\u1EE5 b\xf9 c\u1EA7n thi\u1EBFt \u0111\u1EC3 n\xe2ng h\u1EC7 s\u1ED1 c\xf4ng su\u1EA5t l\xean \u0111\u1EA1t chu\u1EA9n y\xeau c\u1EA7u l\xe0 $\\\\cos\\\\varphi_2 = 0.95$.\\n\\n1.  **T\xednh h\u1EC7 s\u1ED1 ph\u1EA3n kh\xe1ng tr\u01B0\u1EDBc khi b\xf9 ($\\\\tan\\\\varphi_1$):**\\n    \\n\\n```math\\n\\\\tan\\\\varphi_1 = \\\\frac{\\\\sqrt{1 - 0.72^2}}{0.72} \\\\approx 0.964\\n```\\n\\n\\n2.  **T\xednh h\u1EC7 s\u1ED1 ph\u1EA3n kh\xe1ng sau khi b\xf9 ($\\\\tan\\\\varphi_2$):**\\n    \\n\\n```math\\n\\\\tan\\\\varphi_2 = \\\\frac{\\\\sqrt{1 - 0.95^2}}{0.95} \\\\approx 0.329\\n```\\n\\n\\n3.  **T\xednh dung l\u01B0\u1EE3ng t\u1EE5 b\xf9 c\u1EA7n l\u1EAFp \u0111\u1EB7t (Q_b):**\\n    \\n\\n```math\\nQ_b = 120 \\\\cdot (0.964 - 0.329) = 120 \\\\cdot 0.635 = 76.2 \\\\text{ kVAR}\\n```\\n\\n\\nV\u1EDBi k\u1EBFt qu\u1EA3 t\xednh to\xe1n l\xe0 $Q_b = 76.2 \\\\text{ kVAR}$, trong th\u1EF1c t\u1EBF thi c\xf4ng t\u1EE7 t\u1EE5 b\xf9 \u0111i\u1EC7n, ta ch\u1ECDn l\u1EAFp \u0111\u1EB7t t\u1ED5ng dung l\u01B0\u1EE3ng t\u1EE5 b\xf9 kho\u1EA3ng **80 kVAR**. Ta c\xf3 th\u1EC3 thi\u1EBFt k\u1EBF t\u1EE7 b\xf9 t\u1EF1 \u0111\u1ED9ng chia l\xe0m 4 c\u1EA5p t\u1EE5 b\xf9: 2 t\u1EE5 20 kVAR v\xe0 4 t\u1EE5 10 kVAR k\u1EBFt h\u1EE3p \u0111i\u1EC1u khi\u1EC3n tu\u1EA7n t\u1EF1 \u0111\u1EC3 t\u1ED1i \u01B0u h\xf3a qu\xe1 tr\xecnh b\xf9 c\xf4ng su\u1EA5t."},{"id":"huong-dan-viet-blog-docusaurus","metadata":{"permalink":"/shareme/blog/huong-dan-viet-blog-docusaurus","source":"@site/blog/2030/2010-07-20-huong-dan-viet-blog-docusaurus.mdx","title":"H\u01B0\u1EDBng d\u1EABn vi\u1EBFt b\xe0i Docusaurus Blog","description":"Ch\xe0o c\xe1c n\xed! Trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh trang chia s\u1EBB ki\u1EBFn th\u1EE9c n\xe0y, vi\u1EC7c vi\u1EBFt c\xe1c b\xe0i chia s\u1EBB (blog) kh\xf4ng ch\u1EC9 \u0111\u01A1n thu\u1EA7n l\xe0 g\xf5 v\u0103n b\u1EA3n, m\xe0 ch\xfang ta c\xf2n t\u1EADn d\u1EE5ng s\u1EE9c m\u1EA1nh c\u1EE7a MDX (Markdown + JSX) \u0111\u1EC3 b\xe0i vi\u1EBFt sinh \u0111\u1ED9ng h\u01A1n v\u1EDBi c\xe1c kh\u1ED1i code, c\xf4ng th\u1EE9c to\xe1n h\u1ECDc, c\u1EA3nh b\xe1o (admonitions) v\xe0 c\xe1c c\xf4ng c\u1EE5 b\u1ED5 tr\u1EE3.","date":"2010-07-20T00:00:00.000Z","tags":[{"inline":false,"label":"Blog","permalink":"/shareme/blog/tags/blog"},{"inline":false,"label":"Share","permalink":"/shareme/blog/tags/share"},{"inline":false,"label":"Tips","permalink":"/shareme/blog/tags/tips"}],"readingTime":6.05,"hasTruncateMarker":true,"authors":[{"name":"Gemini","isPro":true,"title":"AI","url":"https://gemini.google.com","page":{"permalink":"/shareme/blog/authors/gemini"},"socials":{"newsletter":"https://gemini.google.com/"},"imageURL":"/shareme/img/gemini_logo.svg","key":"gemini"},{"name":"An Nguy\u1EC5n","title":"T\u1EADp s\u1EF1","url":"https://2naq.github.io/shareme","isPro":true,"page":{"permalink":"/shareme/blog/authors/an-nguyen"},"socials":{"zalo":"https://zalo.me/2naq","github":"https://github.com/2Naq","newsletter":"https://2naq.github.io/shareme"},"imageURL":"https://github.com/2Naq.png","key":"anTng"},{"name":"Yangshun Tay","title":"Ex-Meta Staff Engineer, Co-founder GreatFrontEnd","url":"https://linkedin.com/in/yangshun","page":{"permalink":"/shareme/blog/authors/yangshun"},"socials":{"x":"https://x.com/yangshunz","linkedin":"https://www.linkedin.com/in/yangshun/","github":"https://github.com/yangshun","newsletter":"https://www.greatfrontend.com"},"imageURL":"https://github.com/yangshun.png","key":"yangshun"},{"name":"S\xe9bastien Lorber","title":"Docusaurus maintainer, This Week In React editor","url":"https://thisweekinreact.com","page":{"permalink":"/shareme/blog/authors/slorber"},"description":"A freelance React and React-Native developer near Paris and Docusaurus maintainer. Also runs ThisWeekInReact.com, a newsletter to stay updated with the React ecosystem.","socials":{"bluesky":"https://bsky.app/profile/sebastienlorber.com","x":"https://x.com/sebastienlorber","linkedin":"https://www.linkedin.com/in/sebastienlorber/","github":"https://github.com/slorber","instagram":"https://www.instagram.com/thisweekinreact","newsletter":"https://thisweekinreact.com"},"imageURL":"https://github.com/slorber.png","key":"slorber"},{"name":"Cl\xe9ment Vannicatte","title":"Software Engineer @ Algolia","url":"https://github.com/shortcuts","socials":{"x":"https://x.com/sh0rtcts","github":"https://github.com/shortcuts"},"imageURL":"https://github.com/shortcuts.png","key":"shortcuts","page":null}],"frontMatter":{"slug":"huong-dan-viet-blog-docusaurus","title":"H\u01B0\u1EDBng d\u1EABn vi\u1EBFt b\xe0i Docusaurus Blog","authors":["gemini","anTng","yangshun","slorber","shortcuts"],"tags":["blog","share","tips"],"image":"https://docusaurus.io/assets/images/social-card-77e4a0d9b978e519751c324db47003e5.png"},"unlisted":false,"prevItem":{"title":"Top 5 c\xf4ng th\u1EE9c t\xednh to\xe1n c\u1ED1t l\xf5i","permalink":"/shareme/blog/top-5-cong-thuc-dien-tu-dong-hoa"}},"content":"Ch\xe0o c\xe1c n\xed! Trong qu\xe1 tr\xecnh v\u1EADn h\xe0nh trang chia s\u1EBB ki\u1EBFn th\u1EE9c n\xe0y, vi\u1EC7c vi\u1EBFt c\xe1c b\xe0i chia s\u1EBB (blog) kh\xf4ng ch\u1EC9 \u0111\u01A1n thu\u1EA7n l\xe0 g\xf5 v\u0103n b\u1EA3n, m\xe0 ch\xfang ta c\xf2n t\u1EADn d\u1EE5ng s\u1EE9c m\u1EA1nh c\u1EE7a **MDX (Markdown + JSX)** \u0111\u1EC3 b\xe0i vi\u1EBFt sinh \u0111\u1ED9ng h\u01A1n v\u1EDBi c\xe1c kh\u1ED1i code, c\xf4ng th\u1EE9c to\xe1n h\u1ECDc, c\u1EA3nh b\xe1o (admonitions) v\xe0 c\xe1c c\xf4ng c\u1EE5 b\u1ED5 tr\u1EE3.\\n\\n\u0110\u1EC3 gi\xfap c\xe1c n\xed m\u1EDBi l\xe0m quen ho\u1EB7c mu\u1ED1n tra c\u1EE9u nhanh c\xe1ch \u0111\u1ECBnh d\u1EA1ng b\xe0i vi\u1EBFt chu\u1EA9n ch\u1EC9nh m\xe0 **kh\xf4ng l\xe0m l\u1ED7i h\u1EC7 th\u1ED1ng build**, m\xecnh \u0111\xe3 t\u1ED5ng h\u1EE3p to\xe0n b\u1ED9 h\u01B0\u1EDBng d\u1EABn v\u1EADn h\xe0nh v\xe0 vi\u1EBFt blog d\u01B0\u1EDBi \u0111\xe2y.\\n\\n{/* truncate */}\\n\\n---\\n\\n## 1. Quy tr\xecnh t\u1EA1o b\xe0i vi\u1EBFt m\u1EDBi\\n\\n### B\u01B0\u1EDBc 1: Quy t\u1EAFc \u0111\u1EB7t t\xean file\\nM\u1ECDi b\xe0i vi\u1EBFt trong blog \u0111\u1EC1u \u0111\u01B0\u1EE3c l\u01B0u trong th\u01B0 m\u1EE5c `apps/docs/blog/2026/` (ho\u1EB7c th\u01B0 m\u1EE5c n\u0103m t\u01B0\u01A1ng \u1EE9ng).\\nT\xean file ph\u1EA3i tu\xe2n theo c\u1EA5u tr\xfac ng\xe0y th\xe1ng chu\u1EA9n \u0111\u1EC3 Docusaurus t\u1EF1 \u0111\u1ED9ng s\u1EAFp x\u1EBFp:\\n`YYYY-MM-DD-ten-bai-viet-viet-lien-khong-dau.mdx`\\n\\n*V\xed d\u1EE5:* `2026-07-20-huong-dan-viet-blog-docusaurus.mdx`\\n\\n---\\n\\n## 2. C\u1EA5u h\xecnh Frontmatter (Ph\u1EA7n \u0111\u1EA7u file)\\n\\nM\u1ED7i file b\xe0i vi\u1EBFt b\u1EAFt \u0111\u1EA7u b\u1EB1ng m\u1ED9t kh\u1ED1i Frontmatter n\u1EB1m gi\u1EEFa c\u1EB7p d\u1EA5u ba g\u1EA1ch ngang `---`. D\u01B0\u1EDBi \u0111\xe2y l\xe0 c\xe1c th\xf4ng s\u1ED1 c\u1ED1t l\xf5i:\\n\\n```yaml\\n---\\nslug: huong-dan-viet-blog-docusaurus\\ntitle: H\u01B0\u1EDBng d\u1EABn vi\u1EBFt b\xe0i Docusaurus Blog \\nauthors: [anTng]\\ntags: [tu-dong-hoa]\\nimage: https://pbs.twimg.com/media/HNSX94cawAAw37i.png\\n---\\n```\\n\\n*   **`slug`**: \u0110\u01B0\u1EDDng d\u1EABn URL r\xfat g\u1ECDn c\u1EE7a b\xe0i vi\u1EBFt (v\xed d\u1EE5: `https://.../blog/huong-dan-viet-blog-docusaurus`).\\n*   **`title`**: Ti\xeau \u0111\u1EC1 hi\u1EC3n th\u1ECB c\u1EE7a b\xe0i vi\u1EBFt.\\n*   **`authors`**: Danh s\xe1ch t\xe1c gi\u1EA3 vi\u1EBFt b\xe0i. C\xe1c key t\xe1c gi\u1EA3 \u0111\u01B0\u1EE3c \u0111\u1ECBnh ngh\u0129a trong file `blog/authors.yml` (v\xed d\u1EE5: `anTng`, `yangshun`, `slorber`).\\n*   **`tags`**: C\xe1c t\u1EEB kh\xf3a ph\xe2n lo\u1EA1i b\xe0i vi\u1EBFt. C\xe1c tags \u0111\u01B0\u1EE3c \u0111\u0103ng k\xfd trong file `blog/tags.yml` (v\xed d\u1EE5: `tu-dong-hoa`, `networking`, `plc`).\\n*   **`image`**: Link \u1EA3nh b\xeca \u0111\u1EA1i di\u1EC7n khi b\xe0i vi\u1EBFt \u0111\u01B0\u1EE3c chia s\u1EBB tr\xean m\u1EA1ng x\xe3 h\u1ED9i.\\n\\n### C\xe1ch c\u1EA5u h\xecnh th\xeam T\xe1c gi\u1EA3 & Th\u1EBB m\u1EDBi\\n*   **Th\xeam t\xe1c gi\u1EA3:** M\u1EDF file [blog/authors.yml](file:///e:/10.WorkSpace-Code/Nodejs/Docusaurus_PLC/shareme/apps/docs/blog/authors.yml) v\xe0 th\xeam c\u1EA5u h\xecnh theo m\u1EABu:\\n    ```yaml\\n    tenTacGiaKey:\\n      name: T\xean Hi\u1EC3n Th\u1ECB\\n      title: Ch\u1EE9c danh / M\xf4 t\u1EA3 ng\u1EAFn\\n      url: https://...\\n      image_url: https://github.com/username.png\\n      socials:\\n        github: username\\n    ```\\n*   **Th\xeam th\u1EBB:** M\u1EDF file [blog/tags.yml](file:///e:/10.WorkSpace-Code/Nodejs/Docusaurus_PLC/shareme/apps/docs/blog/tags.yml) v\xe0 khai b\xe1o:\\n    ```yaml\\n    tag-key:\\n      label: T\xean Th\u1EBB Hi\u1EC3n Th\u1ECB\\n      permalink: /tag-permalink\\n    ```\\n\\n---\\n\\n## 3. C\xe1c quy t\u1EAFc \u0111\u1ECBnh d\u1EA1ng n\u1ED9i dung c\u1ED1t l\xf5i\\n\\n### 3.1. \u0110i\u1EC3m ng\u1EAFt t\xf3m t\u1EAFt b\xe0i vi\u1EBFt (`truncate`)\\nH\xe3y ch\xe8n c\xfa ph\xe1p `{/* truncate */}` v\xe0o ngay sau 1-2 \u0111o\u1EA1n v\u0103n gi\u1EDBi thi\u1EC7u \u0111\u1EA7u ti\xean c\u1EE7a b\xe0i vi\u1EBFt. \\n*   **T\xe1c d\u1EE5ng:** To\xe0n b\u1ED9 n\u1ED9i dung ph\xeda tr\u01B0\u1EDBc `{/* truncate */}` s\u1EBD hi\u1EC3n th\u1ECB l\xe0m ph\u1EA7n m\xf4 t\u1EA3 ng\u1EAFn (excerpt) tr\xean trang ch\u1EE7 danh s\xe1ch Blog. N\u1ED9i dung ph\xeda sau s\u1EBD ch\u1EC9 hi\u1EC3n th\u1ECB khi ng\u01B0\u1EDDi \u0111\u1ECDc b\u1EA5m v\xe0o n\xfat \\"\u0110\u1ECDc th\xeam\\" (Read More).\\n\\n---\\n\\n### 3.2. Kh\u1ED1i th\xf4ng tin n\u1ED5i b\u1EADt (Admonitions)\\nDocusaurus h\u1ED7 tr\u1EE3 5 ki\u1EC3u h\u1ED9p c\u1EA3nh b\xe1o/ch\xfa th\xedch tr\u1EF1c quan b\u1EB1ng c\xe1ch s\u1EED d\u1EE5ng 3 d\u1EA5u hai ch\u1EA5m `:::`.\\n\\n:::note\\nS\u1EED d\u1EE5ng h\u1ED9p n\xe0y cho c\xe1c th\xf4ng tin b\u1ED5 sung, ghi ch\xfa b\xean l\u1EC1 ho\u1EB7c ng\u1EEF c\u1EA3nh chung.\\n:::\\n\\n:::tip\\nD\xe0nh cho c\xe1c m\u1EB9o th\u1EF1c h\xe0nh, kinh nghi\u1EC7m x\u01B0\u01A1ng m\xe1u ho\u1EB7c ph\xedm t\u1EAFt h\u1EEFu \xedch.\\n:::\\n\\n:::info\\nCung c\u1EA5p th\xf4ng tin quan tr\u1ECDng ho\u1EB7c t\xe0i li\u1EC7u tham kh\u1EA3o ch\xednh th\u1ED1ng c\u1EA7n ng\u01B0\u1EDDi \u0111\u1ECDc ch\xfa \xfd.\\n:::\\n\\n:::warning\\nD\xe0nh cho c\xe1c c\u1EA3nh b\xe1o nguy hi\u1EC3m, h\xe0nh \u0111\u1ED9ng d\u1EC5 g\xe2y l\u1ED7i h\u1EC7 th\u1ED1ng ho\u1EB7c thi\u1EBFt b\u1ECB.\\n:::\\n\\n:::danger\\nNh\u1EEFng h\xe0nh \u0111\u1ED9ng c\xf3 th\u1EC3 g\xe2y ch\xe1y h\u1ECFng t\u1EE7 \u0111i\u1EC7n, m\u1EA5t d\u1EEF li\u1EC7u, ho\u1EB7c \\"\u0111\u1EC1n ti\u1EC1n\\" cho d\u1EF1 \xe1n!\\n:::\\n\\n#### C\xfa ph\xe1p vi\u1EBFt trong MDX:\\n```markdown\\n:::warning\\nN\u1ED9i dung c\u1EA3nh b\xe1o c\u1EE7a c\xe1c n\xed vi\u1EBFt \u1EDF \u0111\xe2y.\\n:::\\n```\\n\\n---\\n\\n### 3.3. Vi\u1EBFt Kh\u1ED1i Code (Code Blocks)\\n\u0110\u1EC3 vi\u1EBFt m\xe3 ngu\u1ED3n ho\u1EB7c c\xe1c t\u1EADp l\u1EC7nh c\u1EA5u h\xecnh, h\xe3y s\u1EED d\u1EE5ng d\u1EA5u bao code: \\\\`\\\\`\\\\`. Docusaurus h\u1ED7 tr\u1EE3 t\xf4 s\xe1ng c\xfa ph\xe1p r\u1EA5t m\u1EA1nh m\u1EBD k\xe8m theo c\xe1c t\xednh n\u0103ng cao c\u1EA5p nh\u01B0:\\n\\n#### V\xed d\u1EE5 1: \u0110\u1EB7t ti\xeau \u0111\u1EC1 cho file code b\u1EB1ng `title`\\n```javascript title=\\"src/components/MathRenderer.jsx\\"\\nimport React from \'react\';\\n// Code c\u1EE7a n\xed\\n```\\n\\n#### V\xed d\u1EE5 2: T\xf4 s\xe1ng (Highlight) d\xf2ng c\u1EE5 th\u1EC3 b\u1EB1ng `{d\xf2ng}`\\n```python {2,4-5} title=\\"calculator.py\\"\\ndef add(a, b):\\n    return a + b  # D\xf2ng n\xe0y \u0111\u01B0\u1EE3c t\xf4 s\xe1ng\\n\\ndef subtract(a, b):\\n    return a - b  # Hai d\xf2ng n\xe0y c\u0169ng \u0111\u01B0\u1EE3c t\xf4 s\xe1ng\\n    # \u0111\u1EC3 ng\u01B0\u1EDDi \u0111\u1ECDc ch\xfa \xfd\\n```\\n\\n#### C\xfa ph\xe1p vi\u1EBFt trong MDX:\\n````markdown\\n```python {2,4-5} title=\\"calculator.py\\"\\ndef add(a, b):\\n    return a + b\\n```\\n````\\n---\\n\\n### 3.4. Vi\u1EBFt C\xf4ng th\u1EE9c To\xe1n h\u1ECDc (LaTeX) - QUY T\u1EAEC S\u1ED0NG C\xd2N\\n\\n:::warning\\n**L\u01B0u \xfd c\u1EF1c k\u1EF3 quan tr\u1ECDng \u0111\u1ED1i v\u1EDBi MDX v3:** \\nDo MDX t\u1EF1 \u0111\u1ED9ng hi\u1EC3u c\xe1c d\u1EA5u ngo\u1EB7c nh\u1ECDn `{}` l\xe0 m\xe3 code JavaScript, n\u1EBFu b\u1EA1n vi\u1EBFt c\xf4ng th\u1EE9c to\xe1n h\u1ECDc ch\u1EE9a ngo\u1EB7c nh\u1ECDn (nh\u01B0 `\\\\frac{A}{B}`, `\\\\sqrt{3}`, ho\u1EB7c ch\u1EC9 s\u1ED1 d\u01B0\u1EDBi `_{tk}`) b\xean trong c\u1EB7p d\u1EA5u \u0111\xf4-la k\xe9p `$$` th\xf4ng th\u01B0\u1EDDng, **tr\xecnh bi\xean d\u1ECBch s\u1EBD b\u1ECB s\u1EADp v\xe0 b\xe1o l\u1ED7i Acorn parse error**.\\n\\n:::\\n\\n#### Gi\u1EA3i ph\xe1p kh\u1EAFc ph\u1EE5c tri\u1EC7t \u0111\u1EC3:\\n\\n1.  **V\u1EDBi c\xf4ng th\u1EE9c kh\u1ED1i l\u1EDBn (Block Math):** **B\u1EAET BU\u1ED8C** s\u1EED d\u1EE5ng kh\u1ED1i code block c\xf3 ng\xf4n ng\u1EEF l\xe0 `math`. Tr\xecnh ph\xe2n t\xedch c\xfa ph\xe1p s\u1EBD coi \u0111\xe2y l\xe0 code t\u0129nh v\xe0 kh\xf4ng qu\xe9t l\u1ED7i JS.\\n    \\n    *C\xe1ch vi\u1EBFt:*\\n    ````markdown\\n    ```math\\n    I = \\\\frac{P}{\\\\sqrt{3} \\\\cdot U \\\\cdot \\\\cos\\\\varphi \\\\cdot \\\\eta}\\n    ```\\n    ````\\n\\n    *K\u1EBFt qu\u1EA3 hi\u1EC3n th\u1ECB tr\xean trang:*\\n    ```math\\n    I = \\\\frac{P}{\\\\sqrt{3} \\\\cdot U \\\\cdot \\\\cos\\\\varphi \\\\cdot \\\\eta}\\n    ```\\n\\n2.  **V\u1EDBi c\xf4ng th\u1EE9c n\u1ED9i d\xf2ng (Inline Math):** S\u1EED d\u1EE5ng m\u1ED9t d\u1EA5u \u0111\xf4-la \u0111\u01A1n `$ ... $` nh\u01B0ng **kh\xf4ng \u0111\u01B0\u1EE3c \u0111\u1EC3 kho\u1EA3ng tr\u1EAFng s\xe1t d\u1EA5u \u0111\xf4-la**, v\xe0 tr\xe1nh d\xf9ng k\xfd t\u1EF1 `{}` ph\u1EE9c t\u1EA1p trong c\xe2u v\u0103n. N\u1EBFu c\xf4ng th\u1EE9c inline c\xf3 d\u1EA5u `{}` g\xe2y l\u1ED7i, h\xe3y \u0111\u1ED5i sang d\xf9ng th\u1EBB JSX `<MathRendererInline>` c\xf3 s\u1EB5n c\u1EE7a d\u1EF1 \xe1n:\\n    \\n    *V\xed d\u1EE5:* S\u1EED d\u1EE5ng `<MathRendererInline displayMode={false} formula=\\"I_{\u0111m}\\" />` \u0111\u1EC3 hi\u1EC3n th\u1ECB an to\xe0n.\\n    ```math\\n        I_{\u0111m} \\n    ```\\n\\n---\\n\\n### 3.5. Ch\xe8n H\xecnh \u1EA3nh & Li\xean k\u1EBFt (Links)\\n\\n#### Ch\xe8n h\xecnh \u1EA3nh\\nB\u1EA1n n\xean t\u1EA1o m\u1ED9t th\u01B0 m\u1EE5c \u1EA3nh c\u1EE5c b\u1ED9 n\u1EB1m c\xf9ng c\u1EA5p v\u1EDBi file b\xe0i vi\u1EBFt \u0111\u1EC3 d\u1EC5 qu\u1EA3n l\xfd.\\n*   C\xfa ph\xe1p: `![M\xf4 t\u1EA3 \u1EA3nh](./img/ten-anh.png)`\\n\\n#### T\u1EA1o li\xean k\u1EBFt n\u1ED9i b\u1ED9 (Link qua l\u1EA1i gi\u1EEFa c\xe1c b\xe0i vi\u1EBFt)\\nH\xe3y d\xf9ng \u0111\u01B0\u1EDDng d\u1EABn t\u01B0\u01A1ng \u0111\u1ED1i tr\u1ECF tr\u1EF1c ti\u1EBFp \u0111\u1EBFn file `.mdx` ngu\u1ED3n. Docusaurus s\u1EBD t\u1EF1 \u0111\u1ED9ng chuy\u1EC3n \u0111\u1ED5i n\xf3 th\xe0nh URL ho\xe0n ch\u1EC9nh v\xe0 ki\u1EC3m tra xem link c\xf3 b\u1ECB h\u1ECFng (broken link) khi build hay kh\xf4ng.\\n*   C\xfa ph\xe1p: `[Xem th\xeam c\xf4ng th\u1EE9c d\xf2ng \u0111i\u1EC7n](./2026-07-18-top-5-cong-thu-dien.mdx)`\\n\\n#### T\u1EA1o li\xean k\u1EBFt \u0111\u1EBFn trang c\xf4ng c\u1EE5 (Tool c\u1EE7a d\u1EF1 \xe1n)\\nN\u1EBFu mu\u1ED1n d\u1EABn link t\u1EEB blog sang trang Tool ti\u1EC7n \xedch n\u1EB1m trong monorepo, h\xe3y s\u1EED d\u1EE5ng ti\u1EC1n t\u1ED1 `pathname:///` \u0111\u1EC3 tr\xe1nh Docusaurus hi\u1EC3u l\u1EA7m l\xe0 link \u1EA3o c\u1EE7a Single Page App.\\n*   C\xfa ph\xe1p: `[B\u1ED9 c\xf4ng c\u1EE5 Data Converter](pathname:///shareme/tool/)`\\n\\n---\\n\\n## 4. Ki\u1EC3m tra tr\u01B0\u1EDBc khi xu\u1EA5t b\u1EA3n\\n\\nTr\u01B0\u1EDBc khi \u0111\u1EA9y b\xe0i vi\u1EBFt l\xean GitHub/Staging, c\xe1c n\xed h\xe3y ch\u1EA1y c\xe1c l\u1EC7nh sau t\u1EA1i th\u01B0 m\u1EE5c g\u1ED1c \u0111\u1EC3 \u0111\u1EA3m b\u1EA3o b\xe0i vi\u1EBFt ho\u1EA1t \u0111\u1ED9ng m\u01B0\u1EE3t m\xe0:\\n\\n1.  Ch\u1EA1y server local \u0111\u1EC3 xem tr\u01B0\u1EDBc tr\u1EF1c quan b\xe0i vi\u1EBFt:\\n    ```bash\\n    npm run dev\\n    ```\\n2.  Ch\u1EA1y th\u1EED l\u1EC7nh ki\u1EC3m tra build t\u0129nh \u0111\u1EC3 r\xe0 so\xe1t to\xe0n b\u1ED9 l\u1ED7i c\xfa ph\xe1p ho\u1EB7c li\xean k\u1EBFt h\u1ECFng:\\n    ```bash\\n    npm run build\\n    ```"}]}}')}}]);